OUTPUT_FORMAT(elf64-x86-64)
ENTRY(_start)

SECTIONS {
    . = 1M;
    _kernel_start = .;

    .text : ALIGN(4K) {
        *(.multiboot)
        *(.text)
    }

    .rodata : ALIGN(4K) {
        *(.rodata)
    }

    .data : ALIGN(4K) {
        *(.data)
    }

    .bss : ALIGN(4K) {
        *(COMMON)
        *(.bss)
        /* Heap follows immediately in BSS — zero-initialised, not stored in ELF */
        _heap_start = .;
        . += 64M;
        _heap_end = .;
    }
    _kernel_end = _heap_end;
}

