13	/* ── Port I/O ─────────────────────────────────────────────────────────────── */
14	static inline void outb(uint16_t port, uint8_t val) {
15	    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
16	}
17	static inline uint8_t inb(uint16_t port) {
18	    uint8_t val;
19	    __asm__ volatile ("inb %1, %0" : "=a"(val) : "Nd"(port));
20	    return val;
21	}
22	
23	/* ── Hardware cursor ──────────────────────────────────────────────────────── */
24	void vga_cursor_enable(uint8_t cursor_start, uint8_t cursor_end) {
25	    /* Cursor Start Register (0x0A): bits[4:0] = start scanline, bit5 = enable */
26	    outb(VGA_CRTC_INDEX, 0x0A);
27	    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xC0) | (cursor_start & 0x1F));
28	    /* Cursor End Register (0x0B): bits[4:0] = end scanline */
29	    outb(VGA_CRTC_INDEX, 0x0B);
30	    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xE0) | (cursor_end & 0x1F));
31	}
32	
33	void vga_cursor_disable(void) {
34	    outb(VGA_CRTC_INDEX, 0x0A);
35	    outb(VGA_CRTC_DATA,  0x20);   /* bit 5 set = cursor off */
36	}
37	
38	void vga_cursor_move(size_t col, size_t row) {
39	    uint16_t pos = (uint16_t)(row * VGA_WIDTH + col);
40	    outb(VGA_CRTC_INDEX, 0x0F);
41	    outb(VGA_CRTC_DATA,  (uint8_t)(pos & 0xFF));
42	    outb(VGA_CRTC_INDEX, 0x0E);
43	    outb(VGA_CRTC_DATA,  (uint8_t)((pos >> 8) & 0xFF));
44	}
45	
46	/* ── Font upload ──────────────────────────────────────────────────────────── */
47	/*
48	 * Loads font8x16 into VGA character ROM (plane 2).
49	 *
50	 * Procedure (EGA/VGA font programming):
51	 *  1. Set Sequencer to allow CPU access to plane 2.
52	 *  2. Set Graphics Controller to map plane 2 at 0xA0000.
53	 *  3. Write 256 × 32-byte slots (16 bytes glyph + 16 bytes padding) to 0xA0000.
54	 *  4. Restore Sequencer and GC to normal text-mode values.
55	 */
56	static void vga_load_font(void) {
57	    /* ── Step 1: unlock plane 2 writes ── */
58	    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);   /* sync reset */
59	    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x04);   /* write plane 2 only */
60	    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x07);   /* sequential, chain-4 off */
61	    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);   /* end reset */
62	
63	    /* ── Step 2: GC maps plane 2 to 0xA0000, 64 KiB window ── */
64	    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x02);   /* read plane 2 */
65	    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x00);   /* write mode 0, read mode 0 */
66	    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x04);   /* 0xA0000, 64K, graphics */
67	
68	    /* ── Step 3: write font glyphs — all 16 rows of 8×16 font ── */
69	    volatile uint8_t *plane2 = (volatile uint8_t *)0xA0000;
70	    for (int ch = 0; ch < 256; ch++) {
71	        for (int row = 0; row < 16; row++)
72	            plane2[ch * 32 + row] = font8x16[ch][row];
73	        for (int row = 16; row < 32; row++)
74	            plane2[ch * 32 + row] = 0x00;
75	    }
76	
77	    /* ── Step 4: restore text-mode sequencer and GC settings ── */
78	    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);   /* sync reset */
79	    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x03);   /* planes 0+1 (text) */
80	    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x03);   /* sequential, odd/even */
81	    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);   /* end reset */
82	
83	    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x00);   /* read plane 0 */
84	    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x10);   /* odd/even mode */
85	    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x0E);   /* 0xB8000, 32K, text */
86	}
87	
88	/* Restore standard 80×25 text mode: 16-pixel cell height, 400 scan lines */
89	static void vga_set_80x25(void) {
90	    /* Unlock CRTC registers 0-7 */
91	    outb(VGA_CRTC_INDEX, 0x11);
92	    uint8_t r11 = inb(VGA_CRTC_DATA) & ~0x80u;
93	    outb(VGA_CRTC_DATA, r11);
94	
95	    /* Maximum Scan Line (reg 9): cell height - 1 = 15, double-scan off */
96	    outb(VGA_CRTC_INDEX, 0x09);
97	    uint8_t r09 = (inb(VGA_CRTC_DATA) & 0x60u) | 0x0Fu;
98	    outb(VGA_CRTC_DATA, r09);
99	}
100	
101	/* ── One-time init ────────────────────────────────────────────────────────── */
102	void vga_init(void) {
103	    vga_load_font();
104	    vga_set_80x25();
