#include <vga.h>
#include <font.h>
#include <serial.h>
#include <string.h>
#include <stdint.h>
#include <stddef.h>

/* ── State ────────────────────────────────────────────────────────────────── */
size_t  vga_col   = 0;
size_t  vga_row   = 0;
uint8_t vga_color = 0x0F;   /* white on black */

/* ── Port I/O ─────────────────────────────────────────────────────────────── */
static inline void outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}
static inline uint8_t inb(uint16_t port) {
    uint8_t val;
    __asm__ volatile ("inb %1, %0" : "=a"(val) : "Nd"(port));
    return val;
}

/* ── Hardware cursor ──────────────────────────────────────────────────────── */
void vga_cursor_enable(uint8_t cursor_start, uint8_t cursor_end) {
    /* Cursor Start Register (0x0A): bits[4:0] = start scanline, bit5 = enable */
    outb(VGA_CRTC_INDEX, 0x0A);
    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xC0) | (cursor_start & 0x1F));
    /* Cursor End Register (0x0B): bits[4:0] = end scanline */
    outb(VGA_CRTC_INDEX, 0x0B);
    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xE0) | (cursor_end & 0x1F));
}

void vga_cursor_disable(void) {
    outb(VGA_CRTC_INDEX, 0x0A);
    outb(VGA_CRTC_DATA,  0x20);   /* bit 5 set = cursor off */
}

void vga_cursor_move(size_t col, size_t row) {
    uint16_t pos = (uint16_t)(row * VGA_WIDTH + col);
    outb(VGA_CRTC_INDEX, 0x0F);
    outb(VGA_CRTC_DATA,  (uint8_t)(pos & 0xFF));
    outb(VGA_CRTC_INDEX, 0x0E);
    outb(VGA_CRTC_DATA,  (uint8_t)((pos >> 8) & 0xFF));
}

/* ── Font upload ──────────────────────────────────────────────────────────── */
/*
 * Loads font8x16 into VGA character ROM (plane 2).
 *
 * Procedure (EGA/VGA font programming):
 *  1. Set Sequencer to allow CPU access to plane 2.
 *  2. Set Graphics Controller to map plane 2 at 0xA0000.
 *  3. Write 256 × 32-byte slots (16 bytes glyph + 16 bytes padding) to 0xA0000.
 *  4. Restore Sequencer and GC to normal text-mode values.
 */
static void vga_load_font(void) {
    /* ── Step 1: unlock plane 2 writes ── */
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);   /* sync reset */
    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x04);   /* write plane 2 only */
    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x07);   /* sequential, chain-4 off */
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);   /* end reset */

    /* ── Step 2: GC maps plane 2 to 0xA0000, 64 KiB window ── */
    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x02);   /* read plane 2 */
    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x00);   /* write mode 0, read mode 0 */
    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x04);   /* 0xA0000, 64K, graphics */

    /* ── Step 3: write font glyphs — all 16 rows of 8×16 font ── */
    volatile uint8_t *plane2 = (volatile uint8_t *)0xA0000;
    for (int ch = 0; ch < 256; ch++) {
        for (int row = 0; row < 16; row++)
            plane2[ch * 32 + row] = font8x16[ch][row];
        for (int row = 16; row < 32; row++)
            plane2[ch * 32 + row] = 0x00;
    }

    /* ── Step 4: restore text-mode sequencer and GC settings ── */
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);   /* sync reset */
    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x03);   /* planes 0+1 (text) */
    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x03);   /* sequential, odd/even */
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);   /* end reset */

    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x00);   /* read plane 0 */
    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x10);   /* odd/even mode */
    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x0E);   /* 0xB8000, 32K, text */
}

/* Restore standard 80×25 text mode: 16-pixel cell height, 400 scan lines */
static void vga_set_80x25(void) {
    /* Unlock CRTC registers 0-7 */
    outb(VGA_CRTC_INDEX, 0x11);
    uint8_t r11 = inb(VGA_CRTC_DATA) & ~0x80u;
    outb(VGA_CRTC_DATA, r11);

    /* Maximum Scan Line (reg 9): cell height - 1 = 15, double-scan off */
    outb(VGA_CRTC_INDEX, 0x09);
    uint8_t r09 = (inb(VGA_CRTC_DATA) & 0x60u) | 0x0Fu;
    outb(VGA_CRTC_DATA, r09);
}

/* ── One-time init ────────────────────────────────────────────────────────── */
void vga_init(void) {
    vga_load_font();
    vga_set_80x25();
    /* Cursor: scanlines 14-15 of the 16-line cell */
    vga_cursor_enable(14, 15);
    vga_cursor_move(0, 0);
}

/* ── Screen operations ────────────────────────────────────────────────────── */
void vga_clear(void) {
    for (size_t i = 0; i < VGA_WIDTH * VGA_HEIGHT; i++)
        VGA_ADDR[i] = vga_entry(' ', vga_color);
    vga_col = 0;
    vga_row = 0;
    vga_cursor_move(0, 0);
}

/* Scroll the screen up one line and blank the last row */
static void vga_scroll(void) {
    memmove((void *)VGA_ADDR,
            (const void *)(VGA_ADDR + VGA_WIDTH),
            (VGA_HEIGHT - 1) * VGA_WIDTH * sizeof(uint16_t));
    uint16_t blank = vga_entry(' ', vga_color);
    for (size_t col = 0; col < VGA_WIDTH; col++)
        VGA_ADDR[(VGA_HEIGHT - 1) * VGA_WIDTH + col] = blank;
    vga_row = VGA_HEIGHT - 1;
}

/* Put a single character at the current cursor position */
static void vga_putchar(char c) {
    if (c == '\n') {
        vga_col = 0;
        if (++vga_row >= VGA_HEIGHT) vga_scroll();
        return;
    }
    if (c == '\r') {
        vga_col = 0;
        return;
    }
    if (c == '\t') {
        vga_col = (vga_col + 8) & ~7u;
        if (vga_col >= VGA_WIDTH) {
            vga_col = 0;
            if (++vga_row >= VGA_HEIGHT) vga_scroll();
        }
        return;
    }
    if (c == '\b') {
        if (vga_col > 0) vga_col--;
        VGA_ADDR[vga_row * VGA_WIDTH + vga_col] = vga_entry(' ', vga_color);
        return;
    }
    VGA_ADDR[vga_row * VGA_WIDTH + vga_col] = vga_entry(c, vga_color);
    if (++vga_col >= VGA_WIDTH) {
        vga_col = 0;
        if (++vga_row >= VGA_HEIGHT) vga_scroll();
    }
}

/* ── Cursor positioning ───────────────────────────────────────────────────── */
void vga_goto(size_t col, size_t row) {
    if (col >= VGA_WIDTH)  col = VGA_WIDTH  - 1;
    if (row >= VGA_HEIGHT) row = VGA_HEIGHT - 1;
    vga_col = col;
    vga_row = row;
    vga_cursor_move(col, row);
}

/* ── Print functions ──────────────────────────────────────────────────────── */
void kprint_char(char c) {
    vga_putchar(c);
    vga_cursor_move(vga_col, vga_row);
}

void kprint(const char *str) {
    serial_print(str);
    for (size_t i = 0; str[i]; i++)
        vga_putchar(str[i]);
    vga_cursor_move(vga_col, vga_row);
}

void kprint_color(const char *str, uint8_t color) {
    uint8_t saved = vga_color;
    vga_color = color;
    kprint(str);
    vga_color = saved;
}

void kprint_uint64(uint64_t n) {
    if (n == 0) { kprint("0"); return; }
    char buf[21]; int i = 20; buf[i] = '\0';
    while (n) { buf[--i] = '0' + (int)(n % 10); n /= 10; }
    kprint(buf + i);
}

void kprint_hex(uint64_t n) {
    static const char hex[] = "0123456789ABCDEF";
    char buf[19]; buf[0]='0'; buf[1]='x'; int i = 18; buf[i] = '\0';
    if (n == 0) { kprint("0x0"); return; }
    while (n) { buf[--i] = hex[n & 0xF]; n >>= 4; }
    kprint(buf + i - 2);   /* include 0x prefix */
}

