#include <detect.h>
#include <stdint.h>
#include <stddef.h>

/* ── CPUID helper ─────────────────────────────────────────────────────────── */
static inline void cpuid(uint32_t leaf, uint32_t *eax, uint32_t *ebx,
                          uint32_t *ecx, uint32_t *edx) {
    __asm__ volatile (
        "cpuid"
        : "=a"(*eax), "=b"(*ebx), "=c"(*ecx), "=d"(*edx)
        : "a"(leaf)
        : /* no clobbers beyond outputs */
    );
}

/* Copy 4 bytes of a register into a char buffer as little-endian chars */
static void reg_to_str(char *dst, uint32_t reg) {
    dst[0] = (char)( reg        & 0xFF);
    dst[1] = (char)((reg >>  8) & 0xFF);
    dst[2] = (char)((reg >> 16) & 0xFF);
    dst[3] = (char)((reg >> 24) & 0xFF);
}

/* ── CPU detection ────────────────────────────────────────────────────────── */
void detect_cpu(cpu_info_t *out) {
    uint32_t eax, ebx, ecx, edx;

    /* Vendor string from leaf 0 */
    cpuid(0, &eax, &ebx, &ecx, &edx);
    reg_to_str(out->vendor + 0, ebx);
    reg_to_str(out->vendor + 4, edx);
    reg_to_str(out->vendor + 8, ecx);
    out->vendor[12] = '\0';

    /* Family / model / stepping from leaf 1 */
    cpuid(1, &eax, &ebx, &ecx, &edx);
    out->stepping = eax & 0xF;
    uint8_t base_model  = (eax >>  4) & 0xF;
    uint8_t base_family = (eax >>  8) & 0xF;
    uint8_t ext_model   = (eax >> 16) & 0xF;

