#ifndef PMM_H
#define PMM_H

#include <stdint.h>
#include <stddef.h>

/*
 * Physical Memory Manager — bitmap allocator, 4 KiB frames.
 *
 * Call pmm_init() once, passing the Multiboot 1 info pointer.
 * The mmap (flags bit 6) is used when available; mem_upper fallback
 * is used otherwise.  The kernel image + heap are reserved automatically
 * using the linker-provided _kernel_start/_kernel_end symbols.
 */

#define PMM_FRAME_SIZE  4096u           /* bytes per physical frame      */
#define PMM_MAX_FRAMES  (512u * 1024u)  /* up to 2 GiB addressable       */

/* Multiboot 1 info struct — only the fields pmm_init() needs */
typedef struct {
    uint32_t flags;
    uint32_t mem_lower;     /* KiB below 1 MiB                          */
    uint32_t mem_upper;     /* KiB above 1 MiB                          */
    uint32_t boot_device;
    uint32_t cmdline;
    uint32_t mods_count;
    uint32_t mods_addr;
    uint32_t syms[4];
    uint32_t mmap_length;
    uint32_t mmap_addr;
} __attribute__((packed)) pmm_mb_info_t;

/* Multiboot 1 memory-map entry */
typedef struct {
    uint32_t size;          /* size of this entry (not counting size field) */
    uint64_t base_addr;
    uint64_t length;
    uint32_t type;          /* 1 = usable RAM                               */
} __attribute__((packed)) pmm_mmap_entry_t;

void     pmm_init(const pmm_mb_info_t *mbi);

/* Allocate one free physical frame; returns physical address or 0 on OOM */
uint64_t pmm_alloc_frame(void);

/* Return a frame to the free pool */
void     pmm_free_frame(uint64_t phys_addr);

/* Diagnostics */
size_t   pmm_free_frames(void);
size_t   pmm_total_frames(void);

#endif /* PMM_H */

