#ifndef GOP_H
#define GOP_H

#include <stdint.h>
#include <stddef.h>
#include <stdbool.h>

/*
 * GOP (Graphics Output Protocol) framebuffer driver.
 *
 * The framebuffer address and geometry come from the Multiboot 2 tag type 8
 * (MULTIBOOT_TAG_TYPE_FRAMEBUFFER).  gop_init() must be called before any
 * drawing function.  If the tag is absent (MB1 boot or GRUB text mode), the
 * module marks itself unavailable and all drawing calls silently no-op so the
 * kernel can fall back to VGA text mode.
 *
 * Colour format: 32 bpp, layout determined by the mask fields in the MB2 tag.
 * Common firmware layouts are BGRX (blue low byte) and RGBX (red low byte).
 * gop_pack_color() handles both by consulting the stored mask offsets.
 */

/* ── Framebuffer descriptor ────────────────────────────────────────────────── */
typedef struct {
    uint64_t addr;          /* linear framebuffer physical address            */
    uint32_t width;         /* horizontal resolution in pixels                */
    uint32_t height;        /* vertical resolution in pixels                  */
    uint32_t pitch;         /* bytes per scanline (may be > width * bpp/8)    */
    uint8_t  bpp;           /* bits per pixel (we request 32)                 */
    /* Colour channel bit positions (from MB2 tag) */
    uint8_t  red_pos;
    uint8_t  red_size;
    uint8_t  green_pos;
    uint8_t  green_size;
    uint8_t  blue_pos;
    uint8_t  blue_size;
} gop_info_t;

/* ── MB2 framebuffer tag (type 8) ──────────────────────────────────────────── */
/* Used internally by gop_init_from_mb2_tag(); exposed here for kernel.c use. */
typedef struct {
    uint32_t type;          /* = 8                                            */
    uint32_t size;
    uint64_t framebuffer_addr;
    uint32_t framebuffer_pitch;
    uint32_t framebuffer_width;
    uint32_t framebuffer_height;
    uint8_t  framebuffer_bpp;
    uint8_t  framebuffer_type;  /* 1 = indexed, 2 = RGB direct colour         */
    uint16_t reserved;
    /* For type==2 (direct colour): */
    uint8_t  red_field_position;
    uint8_t  red_mask_size;
    uint8_t  green_field_position;
    uint8_t  green_mask_size;
    uint8_t  blue_field_position;
    uint8_t  blue_mask_size;
} __attribute__((packed)) gop_mb2_tag_t;

/* ── Global state ──────────────────────────────────────────────────────────── */
extern gop_info_t gop_fb;       /* populated by gop_init_from_mb2_tag()       */
extern bool       gop_available; /* false → VGA text mode fallback is active   */

/* ── Initialisation ────────────────────────────────────────────────────────── */

/*
 * Initialise the GOP driver from a Multiboot 2 framebuffer tag.
 * Returns true on success, false if the tag is NULL or not a direct-colour fb.
 * On false, gop_available remains false and VGA text mode should be used.
 */
bool gop_init_from_mb2_tag(const gop_mb2_tag_t *tag);

/* ── Drawing primitives ────────────────────────────────────────────────────── */

/* Pack (r, g, b) into a 32-bit pixel word using the framebuffer's channel layout. */
static inline uint32_t gop_pack_color(uint8_t r, uint8_t g, uint8_t b);

/* Write one pixel at (x, y). No bounds check — caller must ensure validity. */
void gop_put_pixel(uint32_t x, uint32_t y, uint32_t color);

/* Fill a rectangle with a solid colour. */
void gop_fill_rect(uint32_t x, uint32_t y, uint32_t w, uint32_t h, uint32_t color);

/* Clear the entire framebuffer to a single colour (default: black = 0). */
void gop_clear(uint32_t color);

/* Blit an 8×N bitmap glyph at pixel position (px, py).
 * Each byte in bitmap[] is one row; bit 7 is the leftmost pixel.
 * fg/bg are packed 32-bit colours from gop_pack_color(). */
void gop_draw_glyph(uint32_t px, uint32_t py,
                    const uint8_t *bitmap, uint32_t rows,
                    uint32_t fg, uint32_t bg);

/* ── Inline implementation of gop_pack_color ───────────────────────────────── */
#include <gop.h>   /* prevent double-include guard re-entry — no-op here */

static inline uint32_t gop_pack_color(uint8_t r, uint8_t g, uint8_t b) {
    extern gop_info_t gop_fb;
    return ((uint32_t)r << gop_fb.red_pos)
         | ((uint32_t)g << gop_fb.green_pos)
         | ((uint32_t)b << gop_fb.blue_pos);
}

#endif /* GOP_H */

