#include <gop.h>
#include <stdint.h>
#include <stdbool.h>
#include <string.h>

/* ── Global framebuffer state ─────────────────────────────────────────────── */
gop_info_t gop_fb      = {0};
bool       gop_available = false;

/* ── Initialisation ────────────────────────────────────────────────────────── */

bool gop_init_from_mb2_tag(const gop_mb2_tag_t *tag) {
    if (!tag)
        return false;

    /* We only support direct-colour (type 2) framebuffers */
    if (tag->framebuffer_type != 2)
        return false;

    /* We need at least 15 bpp to do anything useful; we asked for 32 */
    if (tag->framebuffer_bpp < 15)
        return false;

    gop_fb.addr       = tag->framebuffer_addr;
    gop_fb.width      = tag->framebuffer_width;
    gop_fb.height     = tag->framebuffer_height;
    gop_fb.pitch      = tag->framebuffer_pitch;
    gop_fb.bpp        = tag->framebuffer_bpp;
    gop_fb.red_pos    = tag->red_field_position;
    gop_fb.red_size   = tag->red_mask_size;
    gop_fb.green_pos  = tag->green_field_position;
    gop_fb.green_size = tag->green_mask_size;
    gop_fb.blue_pos   = tag->blue_field_position;
    gop_fb.blue_size  = tag->blue_mask_size;

    gop_available = true;
    return true;
}

/* ── Internal helpers ──────────────────────────────────────────────────────── */

/*
 * Return a pointer to the first byte of scanline y.
 * pitch is the number of bytes per scanline (not necessarily width * bpp/8).
 */
static inline volatile uint32_t *row_ptr(uint32_t y) {
    return (volatile uint32_t *)(uintptr_t)(gop_fb.addr + (uint64_t)y * gop_fb.pitch);
}

/* ── Drawing primitives ────────────────────────────────────────────────────── */

void gop_put_pixel(uint32_t x, uint32_t y, uint32_t color) {
    volatile uint32_t *row = row_ptr(y);
    row[x] = color;
}

void gop_fill_rect(uint32_t x, uint32_t y, uint32_t w, uint32_t h, uint32_t color) {
    for (uint32_t row = y; row < y + h; row++) {
        volatile uint32_t *line = row_ptr(row);
        for (uint32_t col = x; col < x + w; col++)
            line[col] = color;
    }
}

void gop_clear(uint32_t color) {
    if (color == 0) {
        /* Fast path: memset works for all-zero (black) fills */
        memset((void *)(uintptr_t)gop_fb.addr, 0,
               (size_t)gop_fb.height * gop_fb.pitch);
    } else {
        gop_fill_rect(0, 0, gop_fb.width, gop_fb.height, color);
    }
}

void gop_draw_glyph(uint32_t px, uint32_t py,
                    const uint8_t *bitmap, uint32_t rows,
                    uint32_t fg, uint32_t bg) {
    for (uint32_t r = 0; r < rows; r++) {
        uint8_t bits = bitmap[r];
        volatile uint32_t *line = row_ptr(py + r);
        for (uint32_t c = 0; c < 8; c++)
            line[px + c] = (bits & (0x80u >> c)) ? fg : bg;
    }
}

