    uint32_t flags;
    uint32_t mem_lower;     /* KiB below 1 MiB  */
    uint32_t mem_upper;     /* KiB above 1 MiB  */
    uint32_t boot_device;
    uint32_t cmdline;
    uint32_t mods_count;
    uint32_t mods_addr;
    uint32_t syms[4];
    uint32_t mmap_length;
    uint32_t mmap_addr;
