typedef struct {
    uint32_t size;          /* size of this entry (not counting this field) */
    uint64_t base_addr;
    uint64_t length;
    uint32_t type;          /* 1 = usable RAM                               */
} __attribute__((packed)) pmm_mb1_mmap_entry_t;

