/* MB2 info starts with an 8-byte fixed header followed by a stream of tags. */
typedef struct {
    uint32_t total_size;
    uint32_t reserved;
} __attribute__((packed)) pmm_mb2_info_hdr_t;

/* Generic MB2 tag header — every tag begins with these two fields. */
typedef struct {
    uint32_t type;
    uint32_t size;
} __attribute__((packed)) pmm_mb2_tag_hdr_t;

/* MB2 tag type 6: memory map */
typedef struct {
    uint32_t type;          /* = 6                          */
    uint32_t size;
    uint32_t entry_size;    /* bytes per entry (usually 24) */
    uint32_t entry_version; /* = 0                          */
    /* Entries follow immediately */
} __attribute__((packed)) pmm_mb2_mmap_tag_t;

/* One entry in the MB2 memory map */
typedef struct {
    uint64_t base_addr;
    uint64_t length;
    uint32_t type;          /* 1 = usable RAM               */
    uint32_t reserved;
} __attribute__((packed)) pmm_mb2_mmap_entry_t;

/* MB2 tag type 4: basic memory info (mem_lower / mem_upper fallback) */
typedef struct {
    uint32_t type;          /* = 4 */
    uint32_t size;
    uint32_t mem_lower;
    uint32_t mem_upper;
} __attribute__((packed)) pmm_mb2_meminfo_tag_t;

/* ── API ────────────────────────────────────────────────────────────────────── */

/* Primary: Multiboot 2 boot — pass physical address of MB2 info struct */
void pmm_init_mb2(uint32_t mb2_info_phys);

/* Legacy fallback: Multiboot 1 boot — pass physical address of MB1 info struct */
void pmm_init_mb1(uint32_t mb1_info_phys);

/* Allocate one free physical frame; returns physical address or 0 on OOM */
uint64_t pmm_alloc_frame(void);

/* Return a frame to the free pool */
void pmm_free_frame(uint64_t phys_addr);

/* Diagnostics */
size_t pmm_free_frames(void);
size_t pmm_total_frames(void);

#endif /* PMM_H */

