extern char _kernel_start[];
extern char _kernel_end[];   /* _heap_end in linker.ld — first free byte */

/* ── Bitmap ───────────────────────────────────────────────────────────────── */
static uint8_t bitmap[PMM_MAX_FRAMES / 8];
static size_t  total_frames = 0;
static size_t  free_count   = 0;

/* ── Bitmap helpers ───────────────────────────────────────────────────────── */
static inline void bit_set(size_t frame) {
    bitmap[frame >> 3] |= (uint8_t)(1u << (frame & 7));
}
static inline void bit_clear(size_t frame) {
    bitmap[frame >> 3] &= (uint8_t)~(1u << (frame & 7));
}
static inline int bit_test(size_t frame) {
    return (bitmap[frame >> 3] >> (frame & 7)) & 1;
}

/* ── Internal range ops ───────────────────────────────────────────────────── */
static size_t addr_to_frame(uint64_t addr) {
    return (size_t)(addr / PMM_FRAME_SIZE);
}

static void pmm_reserve_range(uint64_t base, uint64_t len) {
    uint64_t end   = base + len;
    size_t   first = addr_to_frame(base);
    size_t   last  = addr_to_frame(end + PMM_FRAME_SIZE - 1);
    for (size_t f = first; f < last && f < PMM_MAX_FRAMES; f++) {
        if (!bit_test(f)) { bit_set(f); if (free_count) free_count--; }
    }
}

static void pmm_free_range(uint64_t base, uint64_t len) {
    size_t first = addr_to_frame(base);
    size_t last  = addr_to_frame(base + len);
    for (size_t f = first; f < last && f < PMM_MAX_FRAMES; f++) {
        if (bit_test(f)) { bit_clear(f); free_count++; total_frames++; }
    }
}

/* ── Shared finalisation (after any init path marks free ranges) ──────────── */
static void pmm_common_finalize(void) {
    /* Re-reserve kernel image + heap so we never hand them out */
    uint64_t kstart = (uint64_t)(uintptr_t)_kernel_start;
    uint64_t kend   = (uint64_t)(uintptr_t)_kernel_end;
    pmm_reserve_range(kstart, kend - kstart);

    /* Always reserve the first MiB (BIOS, IVT, VGA VRAM, info structs, …) */
    pmm_reserve_range(0, 0x100000u);
}

/* ── Multiboot 2 init ─────────────────────────────────────────────────────── */

void pmm_init_mb2(uint32_t mb2_info_phys) {
    memset(bitmap, 0xFF, sizeof(bitmap));
    free_count = total_frames = 0;

    const pmm_mb2_info_hdr_t *hdr =
        (const pmm_mb2_info_hdr_t *)(uintptr_t)mb2_info_phys;

    uintptr_t ptr = (uintptr_t)mb2_info_phys + sizeof(pmm_mb2_info_hdr_t);
    uintptr_t end = (uintptr_t)mb2_info_phys + hdr->total_size;

    const pmm_mb2_mmap_tag_t    *mmap_tag  = (void *)0;
    const pmm_mb2_meminfo_tag_t *basic_tag = (void *)0;

    /* Walk the tag stream looking for tag type 6 (mmap) or type 4 (basic mem) */
    while (ptr < end) {
        const pmm_mb2_tag_hdr_t *tag = (const pmm_mb2_tag_hdr_t *)ptr;
        if (tag->type == 0) break;   /* end tag */

        if (tag->type == 6) mmap_tag  = (const pmm_mb2_mmap_tag_t *)tag;
        if (tag->type == 4) basic_tag = (const pmm_mb2_meminfo_tag_t *)tag;

        /* Tags are padded to 8-byte alignment */
        ptr += (tag->size + 7u) & ~7u;
    }

    if (mmap_tag) {
        /* Preferred: full memory map */
        uintptr_t eptr = (uintptr_t)mmap_tag + sizeof(pmm_mb2_mmap_tag_t);
        uintptr_t eend = (uintptr_t)mmap_tag + mmap_tag->size;
        uint32_t  esz  = mmap_tag->entry_size;

        while (eptr + esz <= eend) {
            const pmm_mb2_mmap_entry_t *e = (const pmm_mb2_mmap_entry_t *)eptr;
            if (e->type == 1 && e->length >= PMM_FRAME_SIZE)
                pmm_free_range(e->base_addr, e->length);
            eptr += esz;
        }
    } else if (basic_tag) {
        /* Fallback: mem_upper gives KiB above 1 MiB */
        pmm_free_range(0x100000u, (uint64_t)basic_tag->mem_upper * 1024u);
    }

    pmm_common_finalize();
}

/* ── Multiboot 1 init (legacy fallback) ───────────────────────────────────── */

void pmm_init_mb1(uint32_t mb1_info_phys) {
    memset(bitmap, 0xFF, sizeof(bitmap));
