#include <pmm.h>
#include <stdint.h>
#include <string.h>

/* Linker symbols marking the physical extent of the kernel image + heap */
extern char _kernel_start[];
extern char _kernel_end[];   /* _heap_end in linker.ld — first free byte */

/* ── Bitmap ───────────────────────────────────────────────────────────────── */
/*
 * One bit per 4 KiB frame.  0 = free, 1 = used.
 * PMM_MAX_FRAMES / 8 = 65 536 bytes ≈ 64 KiB — kept in .bss.
 */
static uint8_t  bitmap[PMM_MAX_FRAMES / 8];
static size_t   total_frames = 0;
static size_t   free_count   = 0;

/* ── Bitmap helpers ───────────────────────────────────────────────────────── */

static inline void bit_set(size_t frame) {
    bitmap[frame >> 3] |= (uint8_t)(1u << (frame & 7));
}

static inline void bit_clear(size_t frame) {
    bitmap[frame >> 3] &= (uint8_t)~(1u << (frame & 7));
}

static inline int bit_test(size_t frame) {
    return (bitmap[frame >> 3] >> (frame & 7)) & 1;
}

/* ── Internal helpers ─────────────────────────────────────────────────────── */

static size_t addr_to_frame(uint64_t addr) {
    return (size_t)(addr / PMM_FRAME_SIZE);
}

/* Mark a physical range [base, base+len) as used (1) */
static void pmm_reserve_range(uint64_t base, uint64_t len) {
    uint64_t end   = base + len;
    size_t   first = addr_to_frame(base);
    size_t   last  = addr_to_frame(end + PMM_FRAME_SIZE - 1); /* ceil */

    for (size_t f = first; f < last && f < PMM_MAX_FRAMES; f++) {
        if (!bit_test(f)) {
            bit_set(f);
            if (free_count) free_count--;
        }
    }
}

/* Mark a physical range [base, base+len) as free (0) */
static void pmm_free_range(uint64_t base, uint64_t len) {
    size_t first = addr_to_frame(base);
    size_t last  = addr_to_frame(base + len); /* floor — don't exceed region */

    for (size_t f = first; f < last && f < PMM_MAX_FRAMES; f++) {
        if (bit_test(f)) {
            bit_clear(f);
            free_count++;
            total_frames++;
        }
    }
}

/* ── Public API ───────────────────────────────────────────────────────────── */

void pmm_init(const pmm_mb_info_t *mbi) {
    /* Start with everything reserved */
    memset(bitmap, 0xFF, sizeof(bitmap));
    free_count   = 0;
    total_frames = 0;

    if ((mbi->flags & (1u << 6)) && mbi->mmap_length > 0) {
        /* Preferred path: walk the Multiboot memory map */
        uintptr_t        ptr = (uintptr_t)mbi->mmap_addr;
        uintptr_t        end = ptr + mbi->mmap_length;

        while (ptr < end) {
            const pmm_mmap_entry_t *e = (const pmm_mmap_entry_t *)ptr;

            if (e->type == 1 && e->length >= PMM_FRAME_SIZE)
                pmm_free_range(e->base_addr, e->length);

            ptr += e->size + sizeof(e->size);
        }
    } else if (mbi->flags & 0x1) {
        /* Fallback: mem_upper gives KiB above 1 MiB */
        uint64_t upper_bytes = (uint64_t)mbi->mem_upper * 1024u;
        pmm_free_range(0x100000u, upper_bytes);
    }

    /* Re-reserve the kernel image + linker heap so we never hand them out */
    uint64_t kstart = (uint64_t)(uintptr_t)_kernel_start;
    uint64_t kend   = (uint64_t)(uintptr_t)_kernel_end;
    pmm_reserve_range(kstart, kend - kstart);

    /* Always reserve the first MiB (BIOS, IVT, VRAM, multiboot info, etc.) */
    pmm_reserve_range(0, 0x100000u);
}

uint64_t pmm_alloc_frame(void) {
    for (size_t w = 0; w < sizeof(bitmap); w++) {
        if (bitmap[w] == 0xFF) continue;   /* whole word used — fast skip */

        for (int b = 0; b < 8; b++) {
            size_t f = w * 8 + (size_t)b;
            if (f >= PMM_MAX_FRAMES) return 0;
            if (!bit_test(f)) {
                bit_set(f);
                free_count--;
                return (uint64_t)f * PMM_FRAME_SIZE;
            }
        }
    }
    return 0; /* OOM */
}

void pmm_free_frame(uint64_t phys_addr) {
    size_t f = addr_to_frame(phys_addr);
    if (f >= PMM_MAX_FRAMES) return;
    if (bit_test(f)) {
        bit_clear(f);
        free_count++;
    }
}

size_t pmm_free_frames(void)  { return free_count; }
size_t pmm_total_frames(void) { return total_frames; }

