#include <fs.h>
#include <rawfs.h>
#include <seed.h>
#include <serial.h>
#include <minit.h>

/* Multiboot 1 info struct (only fields we use) */
typedef struct {
    uint32_t flags;
    uint32_t mem_lower;   /* KiB below 1 MiB */
    uint32_t mem_upper;   /* KiB above 1 MiB */
} __attribute__((packed)) mb_info_t;

/*
 * shell_main is defined in userland/shell.c and linked into shell.elf at
 * 0x400000. The symbol is declared here so the kernel can reference it
 * directly when both are linked into a single flat binary (combined build).
 * In a future split-ELF build this becomes a fixed load address.
 */
extern void shell_main(void);

/* Detected RAM — written once at boot, read by malloc */
uint64_t nephilim_ram_kb = 0;

/* Cached CPU brand string — filled at boot, read by SYS_CPU_MODEL */
char boot_cpu_brand[64] = {0};

void kernel_main(uint32_t mb_magic, uint32_t mb_info_phys) {
    serial_init();
    vga_init();
    vga_clear();
    kprint("NephilimOS -- Hello, World!\n\n");

    /* ── Core subsystems ── */
    gdt_init();
    kprint("[GDT]     Ring 0 / Ring 1 descriptors + TSS loaded\n");

    idt_init();
    kprint("[IDT]     256 gates installed\n");

    /* Remap PIC and arm PIT before enabling interrupts */
    timer_init();
    kprint("[TIMER]   PIT at 100 Hz, IRQ0 armed\n");

    /* Safe to enable interrupts now — PIC is remapped to vectors 32–47 */
    __asm__ volatile ("sti");

    syscall_init();
    kprint("[SYSCALL] int 0x80 registered (Ring 0/1)\n");

    keyboard_init();
    kprint("[KBD]     PS/2 keyboard initialized\n");

    process_init();
    kprint("[PROC]    Process manager ready\n\n");

    /* ── CPU info ── */
    cpu_info_t cpu;
    detect_cpu(&cpu);
    kprint("CPU Vendor : "); kprint(cpu.vendor); kprint("\n");
    kprint("CPU Model  : ");
    if (cpu.brand[0] != '\0') {
        const char *b = cpu.brand;
        while (*b == ' ') b++;
        kprint(b);
        /* Cache trimmed brand string for SYS_CPU_MODEL syscall */
        size_t bi = 0;
        while (*b && bi < sizeof(boot_cpu_brand) - 1)
            boot_cpu_brand[bi++] = *b++;
        boot_cpu_brand[bi] = '\0';
    } else {
        kprint("(unavailable)");
        /* Fall back to vendor string */
        size_t vi = 0;
        while (cpu.vendor[vi] && vi < sizeof(boot_cpu_brand) - 1) {
            boot_cpu_brand[vi] = cpu.vendor[vi]; vi++;
        }
        boot_cpu_brand[vi] = '\0';
    }
    kprint("\n");
    kprint("Family     : "); kprint_uint64(cpu.family);
    kprint("  Model    : "); kprint_uint64(cpu.model);
    kprint("  Stepping : "); kprint_uint64(cpu.stepping);
    kprint("\n");

    /* ── RAM info + PMM init ── */
    if (mb_magic == 0x2BADB002) {
        mb_info_t *mbi = (mb_info_t *)(uintptr_t)mb_info_phys;
        if (mbi->flags & 0x1) {
            nephilim_ram_kb = (uint64_t)mbi->mem_lower + (uint64_t)mbi->mem_upper;
            kprint("RAM        : "); kprint_uint64(nephilim_ram_kb / 1024);
            kprint(" MB  (");       kprint_uint64(nephilim_ram_kb);
            kprint(" KB)\n");
        }

        pmm_init((const pmm_mb_info_t *)(uintptr_t)mb_info_phys);
        kprint("[PMM]     Free frames: "); kprint_uint64(pmm_free_frames());
        kprint(" (");                      kprint_uint64(pmm_free_frames() * 4 / 1024);
        kprint(" MB)\n");

        vmm_init();
        kprint("[VMM]     4-level paging active, CR3 recorded\n");
    }

    /* ── Filesystem init ── */
    vfs_init();
    nephilim_disk.data = nephilim_disk_image;
    nephilim_disk.size = RAWFS_IMAGE_SIZE;
    int mnt = vfs_mount("/", &rawfs_driver, &nephilim_disk, RAWFS_IMAGE_SIZE);
    if (mnt == FS_OK) {
        kprint("[VFS]     ext2 root filesystem mounted at /\n");
        /* Seed standard top-level directories (idempotent — ext2 ignores EEXIST) */
        vfs_mkdir("/tmp",  0755);
        vfs_mkdir("/home", 0755);
        vfs_mkdir("/bin",  0755);
        vfs_mkdir("/etc",  0755);
        kprint("[VFS]     seeded /tmp /home /bin /etc\n");
        initramfs_seed();
    } else {
        kprint("[VFS]     WARNING: failed to mount root filesystem\n");
    }
    kprint("\n");

    /* ── minit — miniature init ── */
    minit_init();

    /* ── Launch shell as PID 1 (Ring-1 service process) ── */
    kprint("[BOOT]    Spawning shell (Ring 1, PID 1)...\n");
    process_t *shell = proc_create(shell_main, "shell",
                                   RING_SERVICE, SCHED_QUANTUM_BASE, 0);
    if (!shell) {
        kprint("[BOOT]    FATAL: could not allocate shell process\n");
        for (;;) __asm__ volatile ("hlt");
    }
    proc_wake(shell);

    /* Register shell with minit — it will be restarted up to 3 times on crash */
    minit_watch(shell_main, "shell", shell);

    /* ── Hand off to scheduler — kernel becomes the idle loop ── */
    kprint("[BOOT]    Entering scheduler. Shell is PID ");
    kprint_uint64(shell->pid);
    kprint("\n\n");

    process_t *first = sched_pick();
    if (first) proc_switch(first);

    /* Idle loop — minit_tick() supervises watched processes each iteration */
    for (;;) {
        minit_tick();
        __asm__ volatile ("hlt");   /* sleep until next interrupt (timer tick) */
    }
}

