#ifndef _VGA_H
#define _VGA_H

#include <stdint.h>
#include <stddef.h>
#include <stdbool.h>

/* ── Text mode geometry ───────────────────────────────────────────────────── */
#define VGA_WIDTH   80
#define VGA_HEIGHT  25
#define VGA_ADDR    ((volatile uint16_t *)0xB8000)

/* ── VGA I/O ports (used only in VGA text-mode path) ─────────────────────── */
#define VGA_MISC_WRITE      0x3C2
#define VGA_MISC_READ       0x3CC
#define VGA_SEQ_INDEX       0x3C4
#define VGA_SEQ_DATA        0x3C5
#define VGA_GC_INDEX        0x3CE
#define VGA_GC_DATA         0x3CF
#define VGA_CRTC_INDEX      0x3D4
#define VGA_CRTC_DATA       0x3D5
#define VGA_AC_INDEX        0x3C0
#define VGA_AC_WRITE        0x3C0
#define VGA_AC_READ         0x3C1
#define VGA_INSTAT_READ     0x3DA

/* ── Colour attributes (VGA text-mode palette) ────────────────────────────── */
#define VGA_COLOR(fg, bg)   ((uint8_t)(((bg) << 4) | ((fg) & 0x0F)))

typedef enum {
    VGA_BLACK=0, VGA_BLUE, VGA_GREEN, VGA_CYAN,
    VGA_RED, VGA_MAGENTA, VGA_BROWN, VGA_LIGHT_GREY,
    VGA_DARK_GREY, VGA_LIGHT_BLUE, VGA_LIGHT_GREEN, VGA_LIGHT_CYAN,
    VGA_LIGHT_RED, VGA_LIGHT_MAGENTA, VGA_LIGHT_BROWN, VGA_WHITE,
} vga_color_t;

/* ── State (character-grid logical cursor) ────────────────────────────────── */
extern size_t  vga_col;
extern size_t  vga_row;
extern uint8_t vga_color;   /* current fg/bg attribute byte (VGA text palette) */

/* ── Helpers ──────────────────────────────────────────────────────────────── */
static inline uint16_t vga_entry(char c, uint8_t color) {
    return (uint16_t)(uint8_t)c | ((uint16_t)color << 8);
}

/* ── Initialisation ───────────────────────────────────────────────────────── */

/* BIOS / Multiboot 1 path: hardware VGA text mode (I/O port access) */
void vga_init(void);

/* GOP / Multiboot 2 path: software framebuffer renderer — no I/O ports */
void vga_init_gop(void);

/* ── Screen control ───────────────────────────────────────────────────────── */
void vga_clear(void);

/* (VGA text-mode only) hardware cursor */
void vga_cursor_move(size_t col, size_t row);
void vga_cursor_enable(uint8_t cursor_start, uint8_t cursor_end);
void vga_cursor_disable(void);

/* Move logical cursor without printing */
void vga_goto(size_t col, size_t row);

/* ── Print functions (work on both paths) ─────────────────────────────────── */
void kprint_char(char c);
void kprint(const char *str);
void kprint_color(const char *str, uint8_t color);
void kprint_uint64(uint64_t n);
void kprint_hex(uint64_t n);

#endif /* _VGA_H */

