221	static void handle_input(void) {
222	    int k = (int)syscall0(SYS_GETKEY_NB);
223	    if (k < 0) return;
224	
225	    if (k == 'q' || k == 'Q') { dead = 1; return; }
226	    if (k == 'p' || k == 'P') { paused ^= 1; return; }
227	
228	    int nd = cur_dir;
229	    if      ((k == 'w' || k == 'W' || k == KEY_UP)    && cur_dir != DIR_DOWN)  nd = DIR_UP;
230	    else if ((k == 's' || k == 'S' || k == KEY_DOWN)  && cur_dir != DIR_UP)    nd = DIR_DOWN;
231	    else if ((k == 'a' || k == 'A' || k == KEY_LEFT)  && cur_dir != DIR_RIGHT) nd = DIR_LEFT;
232	    else if ((k == 'd' || k == 'D' || k == KEY_RIGHT) && cur_dir != DIR_LEFT)  nd = DIR_RIGHT;
233	
234	    if (nd != cur_dir) {
235	        cur_dir = nd;
236	        if      (cur_dir == DIR_UP)    { dx =  0; dy = -1; }
237	        else if (cur_dir == DIR_DOWN)  { dx =  0; dy =  1; }
238	        else if (cur_dir == DIR_LEFT)  { dx = -1; dy =  0; }
239	        else if (cur_dir == DIR_RIGHT) { dx =  1; dy =  0; }
240	    }
241	}
242	
243	/* ── Game step ───────────────────────────────────────────────────────────── */
244	static void game_step(void) {
245	    int nx = sx[0] + dx;
246	    int ny = sy[0] + dy;
247	
248	    /* Wall collision */
249	    if (nx < 0 || nx >= BOARD_W || ny < 0 || ny >= BOARD_H) {
250	        dead = 1; return;
251	    }
252	    /* Self collision */
253	    for (int i = 0; i < slen; i++)
254	        if (sx[i] == nx && sy[i] == ny) { dead = 1; return; }
255	
256	    int ate = (nx == ax && ny == ay);
257	
258	    /* Erase tail (before shifting body) */
259	    if (!ate) erase_cell(sx[slen - 1], sy[slen - 1]);
260	
261	    /* Shift body */
262	    int new_len = ate ? slen + 1 : slen;
263	    if (new_len > MAX_LEN) new_len = MAX_LEN;
264	    for (int i = new_len - 1; i > 0; i--) {
265	        sx[i] = sx[i - 1];
266	        sy[i] = sy[i - 1];
267	    }
268	    sx[0] = nx; sy[0] = ny;
269	    slen = new_len;
270	
271	    if (ate) {
272	        score++;
273	        draw_hud();
274	        place_apple();
275	        draw_apple();
276	    }
277	
278	    draw_snake();
279	}
280	
281	/* ── Public entry point ──────────────────────────────────────────────────── */
282	void snake_main(void) {
283	    best = hs_load();
284	
285	    vga_clear_screen();
286	    draw_border();
287	    game_init();
288	    draw_hud();
289	    draw_apple();
290	    draw_snake();
291	
292	    /* Speed: 1 step every N timer ticks (100 Hz PIT).
293	     * Start at 12 ticks (~120 ms), speed up as score grows (min 5 ticks). */
294	    uint32_t last_tick = (uint32_t)timer_ticks;
295	
296	    for (;;) {
297	        handle_input();
298	
299	        if (dead) break;
300	
301	        if (!paused) {
302	            uint32_t speed = 12;
303	            if (score >= 10) speed = 9;
304	            if (score >= 20) speed = 7;
305	            if (score >= 35) speed = 5;
306	
307	            uint32_t now = (uint32_t)timer_ticks;
308	            if ((uint32_t)(now - last_tick) >= speed) {
309	                last_tick = now;
310	                game_step();
311	                if (dead) break;
312	            }
313	        }
314	
315	        syscall0(SYS_YIELD);
316	    }
317	
318	    /* Update and persist highscore if beaten */
319	    int new_best = (score > best);
320	    if (new_best) {
321	        best = score;
322	        hs_save(best);
323	    }
324	
325	    /* Game over screen */
326	    int cx = BOARD_X + BOARD_W / 2;
327	    int cy = BOARD_Y + BOARD_H / 2 - 1;
328	    vga_str(cx - 4, cy, "GAME OVER", COL(C_LRED, C_BLACK));
329	
330	    char sbuf[12];
331	    itoa_simple(score, sbuf);
332	    vga_str(cx - 5, cy + 1, "Score: ", COL(C_WHITE, C_BLACK));
333	    vga_str(cx + 2, cy + 1, sbuf,      COL(C_YELLOW, C_BLACK));
334	
335	    if (new_best) {
336	        vga_str(cx - 5, cy + 2, "New best!", COL(C_LGREEN, C_BLACK));
337	    } else {
338	        char bbuf[12];
339	        itoa_simple(best, bbuf);
340	        vga_str(cx - 5, cy + 2, "Best: ", COL(C_WHITE, C_BLACK));
341	        vga_str(cx + 1, cy + 2, bbuf,     COL(C_LGREEN, C_BLACK));
342	    }
343	
344	    vga_str(cx - 8, cy + 3, "Press any key...", COL(C_LGREY, C_BLACK));
345	
346	    /* Wait for a keypress then restore screen */
347	    syscall0(SYS_GETKEY);
348	    syscall0(SYS_CLEAR);
349	}
