/*
 * Snake game — Ring-1 userland, direct VGA + syscalls.
 * Snake: blue on black. Apple: magenta (closest to purple in VGA palette).
 * Controls: WASD or arrow keys. P = pause. Q = quit.
 * Highscore persisted to /tmp/snake_hi.
 */
#include <syscall.h>
#include <keyboard.h>
#include <timer.h>
#include <fs.h>
#include <stdint.h>
#include <stddef.h>

/* ── Highscore file ──────────────────────────────────────────────────────── */
#define HISCORE_PATH  "/tmp/snake_hi"

static int hs_atoi(const char *s) {
    int n = 0;
    while (*s >= '0' && *s <= '9') n = n * 10 + (*s++ - '0');
    return n;
}

static int hs_load(void) {
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)HISCORE_PATH, O_RDONLY, 0);
    if (fd < 0) return 0;
    char buf[16] = {0};
    syscall3(SYS_FS_READ, (uint64_t)fd, (uint64_t)buf, sizeof(buf) - 1);
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
    int v = hs_atoi(buf);
    return (v >= 0) ? v : 0;
}

static void hs_save(int hi) {
    /* Build decimal string */
    char buf[12]; int i = 0;
    if (hi == 0) { buf[i++] = '0'; }
    else {
        char tmp[12]; int t = 0;
        int n = hi;
        while (n > 0) { tmp[t++] = '0' + (n % 10); n /= 10; }
        while (t > 0) buf[i++] = tmp[--t];
    }
    buf[i] = '\0';

    int64_t fd = syscall3(SYS_FS_OPEN,
                          (uint64_t)HISCORE_PATH,
                          O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd < 0) return;
    syscall3(SYS_FS_WRITE, (uint64_t)fd, (uint64_t)buf, (uint64_t)i);
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
}

/* ── VGA direct access ───────────────────────────────────────────────────── */
#define VGA_ADDR  ((volatile uint16_t *)0xB8000)
#define VGA_W     80
#define VGA_H     25

#define COL(fg, bg)  ((uint8_t)(((bg) << 4) | ((fg) & 0x0F)))

/* VGA palette indices */
#define C_BLACK     0
#define C_BLUE      1
#define C_GREEN     2
#define C_CYAN      3
#define C_RED       4
#define C_MAGENTA   5
#define C_BROWN     6
#define C_LGREY     7
#define C_DGREY     8
#define C_LBLUE     9
#define C_LGREEN   10
#define C_LCYAN    11
#define C_LRED     12
#define C_LMAGENTA 13
#define C_YELLOW   14
#define C_WHITE    15

static void vga_put(int col, int row, char ch, uint8_t attr) {
    VGA_ADDR[row * VGA_W + col] = (uint16_t)(uint8_t)ch | ((uint16_t)attr << 8);
}

static void vga_clear_screen(void) {
    uint8_t attr = COL(C_LGREY, C_BLACK);
    for (int i = 0; i < VGA_W * VGA_H; i++)
        VGA_ADDR[i] = (uint16_t)' ' | ((uint16_t)attr << 8);
}

/* ── Simple string helpers (no libc) ─────────────────────────────────────── */
static void vga_str(int col, int row, const char *s, uint8_t attr) {
    while (*s) { vga_put(col++, row, *s++, attr); }
}

static void itoa_simple(int n, char *buf) {
    if (n == 0) { buf[0] = '0'; buf[1] = '\0'; return; }
    char tmp[12]; int i = 0;
    while (n > 0) { tmp[i++] = '0' + (n % 10); n /= 10; }
    int j = 0;
    while (i > 0) buf[j++] = tmp[--i];
    buf[j] = '\0';
}

/* ── Game geometry ────────────────────────────────────────────────────────── */
#define BOARD_X   1
#define BOARD_Y   2
#define BOARD_W   50
#define BOARD_H   20
#define MAX_LEN   (BOARD_W * BOARD_H)

/* ── Simple LCG RNG ──────────────────────────────────────────────────────── */
static uint32_t rng_state = 12345;
static uint32_t rng_next(void) {
    rng_state = rng_state * 1664525u + 1013904223u;
    return rng_state;
}

/* ── Game state ──────────────────────────────────────────────────────────── */
static int sx[MAX_LEN], sy[MAX_LEN];  /* snake body: sx[0],sy[0] = head */
static int slen;
static int dx, dy;
static int ax, ay;  /* apple position */
static int score;
static int best;    /* highscore loaded from /tmp/snake_hi */
static int paused;
static int dead;

/* Direction constants */
#define DIR_UP    0
#define DIR_DOWN  1
#define DIR_LEFT  2
#define DIR_RIGHT 3
static int cur_dir;

/* ── Drawing helpers ─────────────────────────────────────────────────────── */
static void draw_border(void) {
    uint8_t ba = COL(C_LGREY, C_BLACK);
    /* top / bottom */
    for (int x = 0; x < BOARD_W + 2; x++) {
        vga_put(BOARD_X - 1 + x, BOARD_Y - 1, '-', ba);
        vga_put(BOARD_X - 1 + x, BOARD_Y + BOARD_H, '-', ba);
    }
    /* sides */
    for (int y = 0; y < BOARD_H; y++) {
        vga_put(BOARD_X - 1, BOARD_Y + y, '|', ba);
        vga_put(BOARD_X + BOARD_W, BOARD_Y + y, '|', ba);
    }
}

static void draw_cell(int x, int y, char ch, uint8_t attr) {
    vga_put(BOARD_X + x, BOARD_Y + y, ch, attr);
}

static void erase_cell(int x, int y) {
    draw_cell(x, y, ' ', COL(C_LGREY, C_BLACK));
}

static void draw_hud(void) {
    uint8_t ha = COL(C_WHITE, C_BLACK);
    char sbuf[12];

    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y, "SNAKE", COL(C_LBLUE, C_BLACK));

    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y + 2, "Score:", ha);
    vga_str(BOARD_X + BOARD_W + 10, BOARD_Y + 2, "      ", ha);
    itoa_simple(score, sbuf);
    vga_str(BOARD_X + BOARD_W + 10, BOARD_Y + 2, sbuf, COL(C_YELLOW, C_BLACK));

    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y + 3, "Best: ", ha);
    vga_str(BOARD_X + BOARD_W + 10, BOARD_Y + 3, "      ", ha);
    itoa_simple(best, sbuf);
    vga_str(BOARD_X + BOARD_W + 10, BOARD_Y + 3, sbuf, COL(C_LGREEN, C_BLACK));

    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y + 5,  "WASD /",  ha);
    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y + 6,  "arrows",  ha);
    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y + 7,  "P pause", ha);
    vga_str(BOARD_X + BOARD_W + 3, BOARD_Y + 8,  "Q quit",  ha);
}

static void place_apple(void) {
    /* Pick a random cell not occupied by the snake */
    for (int attempts = 0; attempts < 1000; attempts++) {
        int nx = (int)(rng_next() % (uint32_t)BOARD_W);
        int ny = (int)(rng_next() % (uint32_t)BOARD_H);
        int ok = 1;
        for (int i = 0; i < slen; i++)
            if (sx[i] == nx && sy[i] == ny) { ok = 0; break; }
        if (ok) { ax = nx; ay = ny; return; }
    }
}

static void draw_snake(void) {
    /* Head: bright blue; body: blue */
    draw_cell(sx[0], sy[0], '@', COL(C_LBLUE, C_BLACK));
    for (int i = 1; i < slen; i++)
        draw_cell(sx[i], sy[i], 'o', COL(C_BLUE, C_BLACK));
}

static void draw_apple(void) {
    draw_cell(ax, ay, '*', COL(C_LMAGENTA, C_BLACK));
}

static void game_init(void) {
    rng_state ^= (uint32_t)timer_ticks;   /* seed from real time */

    slen = 3;
    dx = 1; dy = 0;
    cur_dir = DIR_RIGHT;
    score = 0;
    paused = 0;
    dead = 0;

    int hx = BOARD_W / 2, hy = BOARD_H / 2;
    for (int i = 0; i < slen; i++) {
        sx[i] = hx - i;
        sy[i] = hy;
    }

    place_apple();
}

/* ── Input handling ──────────────────────────────────────────────────────── */
static void handle_input(void) {
    int k = (int)syscall0(SYS_GETKEY_NB);
    if (k < 0) return;

    if (k == 'q' || k == 'Q') { dead = 1; return; }
    if (k == 'p' || k == 'P') { paused ^= 1; return; }

    int nd = cur_dir;
    if      ((k == 'w' || k == 'W' || k == KEY_UP)    && cur_dir != DIR_DOWN)  nd = DIR_UP;
    else if ((k == 's' || k == 'S' || k == KEY_DOWN)  && cur_dir != DIR_UP)    nd = DIR_DOWN;
    else if ((k == 'a' || k == 'A' || k == KEY_LEFT)  && cur_dir != DIR_RIGHT) nd = DIR_LEFT;
    else if ((k == 'd' || k == 'D' || k == KEY_RIGHT) && cur_dir != DIR_LEFT)  nd = DIR_RIGHT;

    if (nd != cur_dir) {
        cur_dir = nd;
        if      (cur_dir == DIR_UP)    { dx =  0; dy = -1; }
        else if (cur_dir == DIR_DOWN)  { dx =  0; dy =  1; }
        else if (cur_dir == DIR_LEFT)  { dx = -1; dy =  0; }
        else if (cur_dir == DIR_RIGHT) { dx =  1; dy =  0; }
    }
}

/* ── Game step ───────────────────────────────────────────────────────────── */
static void game_step(void) {
    int nx = sx[0] + dx;
    int ny = sy[0] + dy;

    /* Wall collision */
    if (nx < 0 || nx >= BOARD_W || ny < 0 || ny >= BOARD_H) {
        dead = 1; return;
    }
    /* Self collision */
    for (int i = 0; i < slen; i++)
        if (sx[i] == nx && sy[i] == ny) { dead = 1; return; }

    int ate = (nx == ax && ny == ay);

    /* Erase tail (before shifting body) */
    if (!ate) erase_cell(sx[slen - 1], sy[slen - 1]);

    /* Shift body */
    int new_len = ate ? slen + 1 : slen;
    if (new_len > MAX_LEN) new_len = MAX_LEN;
    for (int i = new_len - 1; i > 0; i--) {
        sx[i] = sx[i - 1];
        sy[i] = sy[i - 1];
    }
    sx[0] = nx; sy[0] = ny;
    slen = new_len;

    if (ate) {
        score++;
        draw_hud();
        place_apple();
        draw_apple();
    }

    draw_snake();
}

/* ── Public entry point ──────────────────────────────────────────────────── */
void snake_main(void) {
    best = hs_load();

    vga_clear_screen();
    draw_border();
    game_init();
    draw_hud();
    draw_apple();
    draw_snake();

    /* Speed: 1 step every N timer ticks (100 Hz PIT).
     * Start at 12 ticks (~120 ms), speed up as score grows (min 5 ticks). */
    uint32_t last_tick = (uint32_t)timer_ticks;

    for (;;) {
        handle_input();

        if (dead) break;

        if (!paused) {
            uint32_t speed = 12;
            if (score >= 10) speed = 9;
            if (score >= 20) speed = 7;
            if (score >= 35) speed = 5;

            uint32_t now = (uint32_t)timer_ticks;
            if ((uint32_t)(now - last_tick) >= speed) {
                last_tick = now;
                game_step();
                if (dead) break;
            }
        }

        syscall0(SYS_YIELD);
    }

    /* Update and persist highscore if beaten */
    int new_best = (score > best);
    if (new_best) {
        best = score;
        hs_save(best);
    }

    /* Game over screen */
    int cx = BOARD_X + BOARD_W / 2;
    int cy = BOARD_Y + BOARD_H / 2 - 1;
    vga_str(cx - 4, cy, "GAME OVER", COL(C_LRED, C_BLACK));

    char sbuf[12];
    itoa_simple(score, sbuf);
    vga_str(cx - 5, cy + 1, "Score: ", COL(C_WHITE, C_BLACK));
    vga_str(cx + 2, cy + 1, sbuf,      COL(C_YELLOW, C_BLACK));

    if (new_best) {
        vga_str(cx - 5, cy + 2, "New best!", COL(C_LGREEN, C_BLACK));
    } else {
        char bbuf[12];
        itoa_simple(best, bbuf);
        vga_str(cx - 5, cy + 2, "Best: ", COL(C_WHITE, C_BLACK));
        vga_str(cx + 1, cy + 2, bbuf,     COL(C_LGREEN, C_BLACK));
    }

    vga_str(cx - 8, cy + 3, "Press any key...", COL(C_LGREY, C_BLACK));

    /* Wait for a keypress then restore screen */
    syscall0(SYS_GETKEY);
    syscall0(SYS_CLEAR);
}

#ifndef _SYSCALL_H
#define _SYSCALL_H

#include <stdint.h>
#include <stddef.h>

/* ── I/O syscalls ─────────────────────────────────────────────────────────── */
#define SYS_PRINT      0   /* rdi=str, rsi=len (0=null-term)                  */
#define SYS_CLEAR      1   /* —                                               */
#define SYS_NEWLINE    2   /* —                                               */
#define SYS_READ_MEM   3   /* rdi=phys_addr → rax=uint64                      */
#define SYS_CPU_MODEL  4   /* rdi=buf, rsi=size                               */
#define SYS_SHUTDOWN   5   /* —                                               */
#define SYS_REBOOT     6   /* —                                               */

/* ── Process syscalls ─────────────────────────────────────────────────────── */
#define SYS_YIELD      7   /* — voluntarily relinquish CPU                    */
#define SYS_GETPID     8   /* — → rax = current pid                           */
#define SYS_SPAWN      9   /* rdi=entry, rsi=name_ptr, rdx=priority → pid     */
#define SYS_FORK      10   /* — → rax=child_pid (parent), 0 (child)           */
#define SYS_EXIT      11   /* rdi=exit_code — terminate calling process        */
#define SYS_KILL      12   /* rdi=pid — destroy target process                 */
#define SYS_WAIT      13   /* rdi=pid — block until target exits               */
#define SYS_SLEEP     14   /* rdi=ticks — block for N scheduler ticks          */
#define SYS_GETPNAME  15   /* rdi=pid, rsi=buf, rdx=size → name string         */

/* ── Input syscalls ─────────────────────────────────────────────────────── */
#define SYS_GETCHAR  16   /* — → rax = ASCII char (blocking)                  */
#define SYS_GETKEY   31   /* — → rax = int key code (KEY_* or ASCII)          */

/* ── Filesystem / process environment ────────────────────────────────────── */
#define SYS_CHDIR    32   /* rdi=path → 0 on success, -1 on error             */
#define SYS_GETCWD   33   /* rdi=buf, rsi=size → 0                            */

/* ── JS syscalls ─────────────────────────────────────────────────────────── */
#define SYS_JS_EXEC  17   /* rdi=source_ptr — run JS string, blocks           */

/* ── Time syscalls ────────────────────────────────────────────────────────── */
#define SYS_TIME          18   /* — → rax = seconds since boot (time_t)        */
#define SYS_CLOCK_GETTIME 19   /* rdi=*timespec, rsi=clockid → fills struct    */

/* ── Filesystem syscalls ──────────────────────────────────────────────────── */
#define SYS_FS_OPEN    20   /* rdi=path, rsi=flags, rdx=mode → fd            */
#define SYS_FS_CLOSE   21   /* rdi=fd → 0                                    */
#define SYS_FS_READ    22   /* rdi=fd, rsi=buf, rdx=len → bytes read         */
#define SYS_FS_WRITE   23   /* rdi=fd, rsi=buf, rdx=len → bytes written      */
#define SYS_FS_SEEK    24   /* rdi=fd, rsi=offset, rdx=whence → new offset   */
#define SYS_FS_STAT    25   /* rdi=path, rsi=stat_ptr → 0                    */
#define SYS_FS_FSTAT   26   /* rdi=fd, rsi=stat_ptr → 0                      */
#define SYS_FS_READDIR 27   /* rdi=fd, rsi=index, rdx=dirent_ptr → 0         */
#define SYS_FS_MKDIR   28   /* rdi=path, rsi=mode → 0                        */
#define SYS_FS_UNLINK  29   /* rdi=path → 0                                  */
#define SYS_FS_CREAT   30   /* rdi=path, rsi=mode → fd                       */

/* ── Process info ─────────────────────────────────────────────────────────── */
#define SYS_PS        34   /* rdi=buf (proc_snap_t*), rsi=max_entries → count  */

/* ── Non-blocking input ───────────────────────────────────────────────────── */
#define SYS_GETKEY_NB 35   /* — → rax = key code if pending, -1 if none        */

#define SYSCALL_COUNT 36

/* ── Return codes ─────────────────────────────────────────────────────────── */
#define ESYS_OK        0
#define ESYS_BADNUM   -1
#define ESYS_BADARG   -2
#define ESYS_NOMEM    -3   /* process table full                               */
#define ESYS_NOPROC   -4   /* no such PID                                      */
#define ESYS_PERM     -5   /* privilege violation                              */

/* ── Kernel-side init ─────────────────────────────────────────────────────── */
void syscall_init(void);

/* ── Inline invocation helpers (for Ring-1 code) ─────────────────────────── */
static inline int64_t syscall0(uint64_t num) {
    int64_t ret;
    __asm__ volatile ("int $0x80" : "=a"(ret) : "a"(num) : "memory");
    return ret;
}
static inline int64_t syscall1(uint64_t num, uint64_t a1) {
    int64_t ret;
    __asm__ volatile ("int $0x80" : "=a"(ret) : "a"(num), "D"(a1) : "memory");
    return ret;
}
static inline int64_t syscall2(uint64_t num, uint64_t a1, uint64_t a2) {
    int64_t ret;
    __asm__ volatile ("int $0x80" : "=a"(ret)
                      : "a"(num), "D"(a1), "S"(a2) : "memory");
    return ret;
}
static inline int64_t syscall3(uint64_t num, uint64_t a1, uint64_t a2, uint64_t a3) {
    int64_t ret;
    register uint64_t r10 __asm__("rdx") = a3;
    __asm__ volatile ("int $0x80" : "=a"(ret)
                      : "a"(num), "D"(a1), "S"(a2), "r"(r10) : "memory");
    return ret;
}

#endif /* _SYSCALL_H */

