130	/* SYS_YIELD: voluntarily give up CPU, scheduler picks next process */
131	static int64_t sys_yield(void) {
132	    if (!current_proc) return ESYS_OK;
133	    process_t *next = sched_pick();
134	    if (next && next != current_proc)
135	        proc_switch(next);
136	    return ESYS_OK;
