144	/*
145	 * SYS_SPAWN: rdi=entry_fn_ptr, rsi=name_ptr, rdx=priority
146	 * Creates and immediately enqueues a new Ring-1 process.
147	 * Returns new pid on success, negative on error.
148	 */
149	static int64_t sys_spawn(uint64_t entry, uint64_t name_ptr, uint64_t priority) {
150	    if (!entry) return ESYS_BADARG;
151	    const char *name = name_ptr ? (const char *)name_ptr : "proc";
152	    process_t *p = proc_create((void (*)(void))entry, name,
153	                                RING_SERVICE, SCHED_QUANTUM_BASE, (uint32_t)priority);
154	    if (!p) return ESYS_NOMEM;
155	    proc_wake(p);
156	    return (int64_t)p->pid;
157	}
