159	/*
160	 * SYS_FORK: duplicate calling process.
161	 * Returns child pid to parent, 0 to child.
162	 */
163	static int64_t sys_fork(void) {
164	    if (!current_proc) return ESYS_BADARG;
165	    process_t *child = proc_fork(current_proc);
166	    if (!child) return ESYS_NOMEM;
167	    /* Child gets 0 in rax after iretq — set it in child's saved context */
168	    /* The saved rax sits in the int_frame_t on child's stack; we zero it
169	     * by adjusting the iretq frame that ctx_switch will restore.         */
170	    child->ctx.rip = current_proc->ctx.rip;
171	    proc_wake(child);
172	    return (int64_t)child->pid;   /* parent sees child pid */
173	}
