175	/* SYS_EXIT: terminate calling process */
176	static int64_t sys_exit(uint64_t code) {
177	    (void)code;
178	    if (!current_proc) return ESYS_BADARG;
179	    proc_destroy(current_proc);
180	    /* Pick next runnable process */
181	    process_t *next = sched_pick();
182	    if (next) proc_switch(next);
183	    /* If no next process, idle */
184	    for (;;) __asm__ volatile ("hlt");
185	    return ESYS_OK;
186	}
