189	static int64_t sys_kill(uint64_t pid) {
190	    if (!pid) return ESYS_BADARG;
191	    process_t *p = proc_by_pid((uint32_t)pid);
192	    if (!p) return ESYS_NOPROC;
193	    /* Cannot kill the idle kernel task (pid 0 guard above) */
194	    proc_destroy(p);
