#define C_CYAN      3
#define C_RED       4
#define C_MAGENTA   5
#define C_BROWN     6
#define C_LGREY     7
#define C_DGREY     8
#define C_LBLUE     9
#define C_LGREEN   10
#define C_LCYAN    11
#define C_LRED     12
#define C_LMAGENTA 13
#define C_YELLOW   14
#define C_WHITE    15

#define COL(fg, bg)  ((uint8_t)(((bg) << 4) | ((fg) & 0x0F)))

/* Draw one character cell via kernel syscall — works on VGA and GOP */
static void scr_put(int col, int row, char ch, uint8_t attr) {
    uint64_t packed = (uint64_t)(uint8_t)ch | ((uint64_t)attr << 8);
    syscall3(SYS_PUTCELL, (uint64_t)col, (uint64_t)row, packed);
}

static void scr_clear(void) {
    syscall0(SYS_CLEAR);
}

static void scr_str(int col, int row, const char *s, uint8_t attr) {
    while (*s) scr_put(col++, row, *s++, attr);
}

static void itoa_simple(int n, char *buf) {
    if (n == 0) { buf[0] = '0'; buf[1] = '\0'; return; }
    char tmp[12]; int i = 0;
    while (n > 0) { tmp[i++] = '0' + (n % 10); n /= 10; }
    int j = 0;
    while (i > 0) buf[j++] = tmp[--i];
    buf[j] = '\0';
}

/* ── Game geometry ────────────────────────────────────────────────────────── */
#define BOARD_X   1
#define BOARD_Y   2
#define BOARD_W   50
#define BOARD_H   20
#define MAX_LEN   (BOARD_W * BOARD_H)

/* ── Simple LCG RNG ──────────────────────────────────────────────────────── */
static uint32_t rng_state = 12345;
static uint32_t rng_next(void) {
    rng_state = rng_state * 1664525u + 1013904223u;
    return rng_state;
}

/* ── Game state ──────────────────────────────────────────────────────────── */
static int sx[MAX_LEN], sy[MAX_LEN];
static int slen, dx, dy, ax, ay, score, best, paused, dead;

#define DIR_UP    0
#define DIR_DOWN  1
#define DIR_LEFT  2
#define DIR_RIGHT 3
static int cur_dir;

/* ── Drawing helpers ─────────────────────────────────────────────────────── */
static void draw_border(void) {
    uint8_t ba = COL(C_LGREY, C_BLACK);
    for (int x = 0; x < BOARD_W + 2; x++) {
        scr_put(BOARD_X - 1 + x, BOARD_Y - 1, '-', ba);
        scr_put(BOARD_X - 1 + x, BOARD_Y + BOARD_H, '-', ba);
    }
    for (int y = 0; y < BOARD_H; y++) {
        scr_put(BOARD_X - 1, BOARD_Y + y, '|', ba);
        scr_put(BOARD_X + BOARD_W, BOARD_Y + y, '|', ba);
    }
}

static void draw_cell(int x, int y, char ch, uint8_t attr) {
    scr_put(BOARD_X + x, BOARD_Y + y, ch, attr);
}

static void erase_cell(int x, int y) {
    draw_cell(x, y, ' ', COL(C_LGREY, C_BLACK));
}

static void draw_hud(void) {
    uint8_t ha = COL(C_WHITE, C_BLACK);
    char sbuf[12];

    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y,     "SNAKE",  COL(C_LBLUE, C_BLACK));
    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y + 2, "Score:", ha);
    scr_str(BOARD_X + BOARD_W + 10, BOARD_Y + 2, "      ", ha);
    itoa_simple(score, sbuf);
    scr_str(BOARD_X + BOARD_W + 10, BOARD_Y + 2, sbuf, COL(C_YELLOW, C_BLACK));

    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y + 3, "Best: ", ha);
    scr_str(BOARD_X + BOARD_W + 10, BOARD_Y + 3, "      ", ha);
    itoa_simple(best, sbuf);
    scr_str(BOARD_X + BOARD_W + 10, BOARD_Y + 3, sbuf, COL(C_LGREEN, C_BLACK));

    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y + 5, "WASD /",  ha);
    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y + 6, "arrows",  ha);
    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y + 7, "P pause", ha);
    scr_str(BOARD_X + BOARD_W + 3, BOARD_Y + 8, "Q quit",  ha);
}

static void place_apple(void) {
    for (int attempts = 0; attempts < 1000; attempts++) {
        int nx = (int)(rng_next() % (uint32_t)BOARD_W);
        int ny = (int)(rng_next() % (uint32_t)BOARD_H);
        int ok = 1;
        for (int i = 0; i < slen; i++)
            if (sx[i] == nx && sy[i] == ny) { ok = 0; break; }
        if (ok) { ax = nx; ay = ny; return; }
    }
}

static void draw_snake(void) {
    draw_cell(sx[0], sy[0], '@', COL(C_LBLUE, C_BLACK));
    for (int i = 1; i < slen; i++)
        draw_cell(sx[i], sy[i], 'o', COL(C_BLUE, C_BLACK));
}

static void draw_apple(void) {
    draw_cell(ax, ay, '*', COL(C_LMAGENTA, C_BLACK));
}

static void game_init(void) {
    rng_state ^= (uint32_t)timer_ticks;
    slen = 3; dx = 1; dy = 0;
    cur_dir = DIR_RIGHT;
    score = 0; paused = 0; dead = 0;

    int hx = BOARD_W / 2, hy = BOARD_H / 2;
    for (int i = 0; i < slen; i++) {
        sx[i] = hx - i;
        sy[i] = hy;
    }
    place_apple();
}

/* ── Input handling ──────────────────────────────────────────────────────── */
static void handle_input(void) {
    int k = (int)syscall0(SYS_GETKEY_NB);
    if (k < 0) return;

    if (k == 'q' || k == 'Q') { dead = 1; return; }
    if (k == 'p' || k == 'P') { paused ^= 1; return; }

    int nd = cur_dir;
    if      ((k == 'w' || k == 'W' || k == KEY_UP)    && cur_dir != DIR_DOWN)  nd = DIR_UP;
    else if ((k == 's' || k == 'S' || k == KEY_DOWN)  && cur_dir != DIR_UP)    nd = DIR_DOWN;
    else if ((k == 'a' || k == 'A' || k == KEY_LEFT)  && cur_dir != DIR_RIGHT) nd = DIR_LEFT;
    else if ((k == 'd' || k == 'D' || k == KEY_RIGHT) && cur_dir != DIR_LEFT)  nd = DIR_RIGHT;

    if (nd != cur_dir) {
        cur_dir = nd;
        if      (cur_dir == DIR_UP)    { dx =  0; dy = -1; }
        else if (cur_dir == DIR_DOWN)  { dx =  0; dy =  1; }
        else if (cur_dir == DIR_LEFT)  { dx = -1; dy =  0; }
        else if (cur_dir == DIR_RIGHT) { dx =  1; dy =  0; }
    }
}

/* ── Game step ───────────────────────────────────────────────────────────── */
static void game_step(void) {
    int nx = sx[0] + dx, ny = sy[0] + dy;

    if (nx < 0 || nx >= BOARD_W || ny < 0 || ny >= BOARD_H) { dead = 1; return; }
    for (int i = 0; i < slen; i++)
        if (sx[i] == nx && sy[i] == ny) { dead = 1; return; }

    int ate = (nx == ax && ny == ay);
    if (!ate) erase_cell(sx[slen - 1], sy[slen - 1]);

    int new_len = ate ? slen + 1 : slen;
    if (new_len > MAX_LEN) new_len = MAX_LEN;
    for (int i = new_len - 1; i > 0; i--) {
        sx[i] = sx[i - 1];
        sy[i] = sy[i - 1];
    }
    sx[0] = nx; sy[0] = ny;
    slen = new_len;

    if (ate) {
        score++;
        draw_hud();
        place_apple();
        draw_apple();
    }
    draw_snake();
}

/* ── Public entry point ──────────────────────────────────────────────────── */
void snake_main(void) {
    best = hs_load();

    scr_clear();
    draw_border();
    game_init();
    draw_hud();
    draw_apple();
    draw_snake();

    uint32_t last_tick = (uint32_t)timer_ticks;

    for (;;) {
        handle_input();
        if (dead) break;

        if (!paused) {
            uint32_t speed = 12;
            if (score >= 10) speed = 9;
            if (score >= 20) speed = 7;
            if (score >= 35) speed = 5;

            uint32_t now = (uint32_t)timer_ticks;
            if ((uint32_t)(now - last_tick) >= speed) {
                last_tick = now;
                game_step();
                if (dead) break;
            }
        }
        syscall0(SYS_YIELD);
    }

    /* Persist highscore */
    int new_best = (score > best);
    if (new_best) { best = score; hs_save(best); }

    /* Game over screen */
    int cx = BOARD_X + BOARD_W / 2;
    int cy = BOARD_Y + BOARD_H / 2 - 1;
    scr_str(cx - 4, cy,     "GAME OVER", COL(C_LRED, C_BLACK));

    char sbuf[12];
    itoa_simple(score, sbuf);
    scr_str(cx - 5, cy + 1, "Score: ",   COL(C_WHITE, C_BLACK));
    scr_str(cx + 2, cy + 1, sbuf,        COL(C_YELLOW, C_BLACK));

    if (new_best) {
        scr_str(cx - 5, cy + 2, "New best!", COL(C_LGREEN, C_BLACK));
    } else {
        char bbuf[12];
        itoa_simple(best, bbuf);
        scr_str(cx - 5, cy + 2, "Best: ",   COL(C_WHITE, C_BLACK));
        scr_str(cx + 1, cy + 2, bbuf,        COL(C_LGREEN, C_BLACK));
    }

    scr_str(cx - 8, cy + 3, "Press any key...", COL(C_LGREY, C_BLACK));

    syscall0(SYS_GETKEY);
    syscall0(SYS_CLEAR);
}

