#ifndef _IDT_H
#define _IDT_H

#include <stdint.h>

/* Gate types for the access byte */
#define IDT_INTERRUPT_GATE  0x8E    /* present, DPL=0, 64-bit interrupt gate */
#define IDT_TRAP_GATE       0x8F    /* present, DPL=0, 64-bit trap gate      */

typedef struct {
    uint16_t offset_low;
    uint16_t selector;      /* code segment selector — SEG_KCODE */
    uint8_t  ist;           /* IST index (0 = use current stack)  */
    uint8_t  type_attr;
    uint16_t offset_mid;
    uint32_t offset_high;
    uint32_t reserved;
} __attribute__((packed)) idt_entry_t;

typedef struct {
    uint16_t limit;
    uint64_t base;
} __attribute__((packed)) idtr_t;

/* Pushed by the CPU (and our stubs) before calling the C handler */
typedef struct {
    /* Saved by stub (in reverse push order) */
    uint64_t r15, r14, r13, r12, r11, r10, r9, r8;
    uint64_t rdi, rsi, rbp, rbx, rdx, rcx, rax;
    /* Pushed by stub */
    uint64_t vector;
    uint64_t error_code;    /* 0 for vectors that have no hardware error code */
    /* Pushed by CPU */
    uint64_t rip, cs, rflags, rsp, ss;
} __attribute__((packed)) int_frame_t;

void idt_init(void);

/* Default handler — prints vector + error code and halts */
void int_handler(int_frame_t *frame);

