/*
 * Snake — dual-renderer:
 *   GOP (MB2/UEFI): full pixel rendering, large board, colored rectangles.
 *   VGA (MB1/BIOS): ASCII character grid, 80×25 text mode.
 *
 * Controls: WASD / arrow keys. P = pause. Q = quit.
 * Highscore: /tmp/snake_hi
 */
#include <syscall.h>
#include <keyboard.h>
#include <timer.h>
#include <fs.h>
#include <stdint.h>
#include <stddef.h>

/* ────────────────────────────────────────────────────────────────────────────
 * Highscore helpers
 * ──────────────────────────────────────────────────────────────────────────*/
#define HISCORE_PATH "/tmp/snake_hi"

static int hs_atoi(const char *s) {
    int n = 0;
    while (*s >= '0' && *s <= '9') n = n * 10 + (*s++ - '0');
    return n;
}
static int hs_load(void) {
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)HISCORE_PATH, O_RDONLY, 0);
    if (fd < 0) return 0;
    char buf[16] = {0};
    syscall3(SYS_FS_READ, (uint64_t)fd, (uint64_t)buf, sizeof(buf)-1);
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
    return hs_atoi(buf);
}
static void hs_save(int hi) {
    char buf[12]; int i = 0;
    if (!hi) { buf[i++] = '0'; }
    else {
        char tmp[12]; int t = 0, n = hi;
        while (n) { tmp[t++] = '0' + n%10; n /= 10; }
        while (t)  buf[i++] = tmp[--t];
    }
    buf[i] = '\0';
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)HISCORE_PATH,
                          O_WRONLY|O_CREAT|O_TRUNC, 0644);
    if (fd < 0) return;
    syscall3(SYS_FS_WRITE, (uint64_t)fd, (uint64_t)buf, (uint64_t)i);
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
}

/* ────────────────────────────────────────────────────────────────────────────
 * Shared: VGA colour palette (text mode attributes + GOP RGB lookup)
 * ──────────────────────────────────────────────────────────────────────────*/
#define C_BLACK    0
#define C_BLUE     1
#define C_GREEN    2
#define C_CYAN     3
#define C_RED      4
#define C_MAGENTA  5
#define C_BROWN    6
#define C_LGREY    7
#define C_DGREY    8
#define C_LBLUE    9
#define C_LGREEN  10
#define C_LCYAN   11
#define C_LRED    12
#define C_LMAGENTA 13
#define C_YELLOW  14
#define C_WHITE   15

#define COL(fg,bg) ((uint8_t)(((bg)<<4)|((fg)&0x0F)))

/* ────────────────────────────────────────────────────────────────────────────
 * RNG
 * ──────────────────────────────────────────────────────────────────────────*/
static uint32_t rng_state = 12345;
static uint32_t rng_next(void) {
    rng_state = rng_state * 1664525u + 1013904223u;
    return rng_state;
}

/* ────────────────────────────────────────────────────────────────────────────
 * String helpers (no libc)
 * ──────────────────────────────────────────────────────────────────────────*/
static void itoa_s(int n, char *buf) {
    if (!n) { buf[0]='0'; buf[1]='\0'; return; }
    char tmp[12]; int i=0, j=0;
    while (n) { tmp[i++]='0'+n%10; n/=10; }
    while (i)  buf[j++]=tmp[--i];
    buf[j]='\0';
}
static int strlen_s(const char *s) { int n=0; while(*s++) n++; return n; }

/* ────────────────────────────────────────────────────────────────────────────
 * Direction
 * ──────────────────────────────────────────────────────────────────────────*/
#define DIR_UP    0
#define DIR_DOWN  1
#define DIR_LEFT  2
#define DIR_RIGHT 3

/* ════════════════════════════════════════════════════════════════════════════
 *  VGA TEXT-MODE RENDERER  (MB1 / BIOS path)
 * ════════════════════════════════════════════════════════════════════════════*/

#define VGA_BOARD_X  1
#define VGA_BOARD_Y  2
#define VGA_BOARD_W 50
#define VGA_BOARD_H 20
#define VGA_MAX_LEN (VGA_BOARD_W * VGA_BOARD_H)

static int  vsx[VGA_MAX_LEN], vsy[VGA_MAX_LEN];
static int  vslen, vdx, vdy, vax, vay, vscore, vbest, vpaused, vdead, vdir;

static void vga_put(int col, int row, char ch, uint8_t attr) {
    uint64_t packed = (uint64_t)(uint8_t)ch | ((uint64_t)attr << 8);
    syscall3(SYS_PUTCELL, (uint64_t)col, (uint64_t)row, packed);
}
static void vga_str(int col, int row, const char *s, uint8_t attr) {
    while (*s) vga_put(col++, row, *s++, attr);
}
static void vga_draw_cell(int x, int y, char ch, uint8_t attr) {
    vga_put(VGA_BOARD_X+x, VGA_BOARD_Y+y, ch, attr);
}
static void vga_erase_cell(int x, int y) {
    vga_draw_cell(x, y, ' ', COL(C_LGREY, C_BLACK));
}
static void vga_draw_border(void) {
    uint8_t ba = COL(C_LGREY, C_BLACK);
    for (int x=0; x<VGA_BOARD_W+2; x++) {
        vga_put(VGA_BOARD_X-1+x, VGA_BOARD_Y-1,         '-', ba);
        vga_put(VGA_BOARD_X-1+x, VGA_BOARD_Y+VGA_BOARD_H, '-', ba);
    }
    for (int y=0; y<VGA_BOARD_H; y++) {
        vga_put(VGA_BOARD_X-1,         VGA_BOARD_Y+y, '|', ba);
        vga_put(VGA_BOARD_X+VGA_BOARD_W, VGA_BOARD_Y+y, '|', ba);
    }
}
static void vga_draw_hud(void) {
    uint8_t ha = COL(C_WHITE, C_BLACK);
    int hx = VGA_BOARD_X + VGA_BOARD_W + 3;
    char buf[12];
    vga_str(hx, VGA_BOARD_Y,   "SNAKE",   COL(C_LBLUE, C_BLACK));
    vga_str(hx, VGA_BOARD_Y+2, "Score:",  ha);
    vga_str(hx+7, VGA_BOARD_Y+2, "      ", ha);
    itoa_s(vscore, buf); vga_str(hx+7, VGA_BOARD_Y+2, buf, COL(C_YELLOW,C_BLACK));
    vga_str(hx, VGA_BOARD_Y+3, "Best: ",  ha);
    vga_str(hx+7, VGA_BOARD_Y+3, "      ", ha);
    itoa_s(vbest, buf);  vga_str(hx+7, VGA_BOARD_Y+3, buf, COL(C_LGREEN,C_BLACK));
    vga_str(hx, VGA_BOARD_Y+5, "WASD/",   ha);
    vga_str(hx, VGA_BOARD_Y+6, "arrows",  ha);
    vga_str(hx, VGA_BOARD_Y+7, "P pause", ha);
    vga_str(hx, VGA_BOARD_Y+8, "Q quit",  ha);
}
static void vga_place_apple(void) {
    for (int a=0; a<1000; a++) {
        int nx=(int)(rng_next()%(uint32_t)VGA_BOARD_W);
        int ny=(int)(rng_next()%(uint32_t)VGA_BOARD_H);
        int ok=1;
        for (int i=0;i<vslen;i++) if(vsx[i]==nx&&vsy[i]==ny){ok=0;break;}
        if (ok){vax=nx;vay=ny;return;}
    }
}
static void vga_draw_snake(void) {
    vga_draw_cell(vsx[0],vsy[0],'@',COL(C_LBLUE,C_BLACK));
    for(int i=1;i<vslen;i++) vga_draw_cell(vsx[i],vsy[i],'o',COL(C_BLUE,C_BLACK));
}
static void vga_game_init(void) {
    rng_state ^= (uint32_t)timer_ticks;
    vslen=3; vdx=1; vdy=0; vdir=DIR_RIGHT;
    vscore=0; vpaused=0; vdead=0;
    int hx=VGA_BOARD_W/2, hy=VGA_BOARD_H/2;
    for(int i=0;i<vslen;i++){vsx[i]=hx-i;vsy[i]=hy;}
    vga_place_apple();
}
static void vga_step(void) {
    int nx=vsx[0]+vdx, ny=vsy[0]+vdy;
    if(nx<0||nx>=VGA_BOARD_W||ny<0||ny>=VGA_BOARD_H){vdead=1;return;}
    for(int i=0;i<vslen;i++) if(vsx[i]==nx&&vsy[i]==ny){vdead=1;return;}
    int ate=(nx==vax&&ny==vay);
    if(!ate) vga_erase_cell(vsx[vslen-1],vsy[vslen-1]);
    int nl=ate?vslen+1:vslen; if(nl>VGA_MAX_LEN)nl=VGA_MAX_LEN;
    for(int i=nl-1;i>0;i--){vsx[i]=vsx[i-1];vsy[i]=vsy[i-1];}
    vsx[0]=nx;vsy[0]=ny;vslen=nl;
    if(ate){vscore++;vga_draw_hud();vga_place_apple();
        vga_draw_cell(vax,vay,'*',COL(C_LMAGENTA,C_BLACK));}
    vga_draw_snake();
}

static void snake_vga(void) {
    vbest=hs_load();
    syscall0(SYS_CLEAR);
    vga_draw_border();
    vga_game_init();
    vga_draw_hud();
    vga_draw_cell(vax,vay,'*',COL(C_LMAGENTA,C_BLACK));
    vga_draw_snake();
    uint32_t last=(uint32_t)timer_ticks;
    for(;;){
        int k=(int)syscall0(SYS_GETKEY_NB);
        if(k>=0){
            if(k=='q'||k=='Q'){vdead=1;}
            else if(k=='p'||k=='P'){vpaused^=1;}
            else {
                int nd=vdir;
                if((k=='w'||k=='W'||k==KEY_UP)   &&vdir!=DIR_DOWN) nd=DIR_UP;
                if((k=='s'||k=='S'||k==KEY_DOWN)  &&vdir!=DIR_UP)   nd=DIR_DOWN;
                if((k=='a'||k=='A'||k==KEY_LEFT)  &&vdir!=DIR_RIGHT)nd=DIR_LEFT;
                if((k=='d'||k=='D'||k==KEY_RIGHT) &&vdir!=DIR_LEFT) nd=DIR_RIGHT;
                if(nd!=vdir){vdir=nd;
                    if(vdir==DIR_UP){vdx=0;vdy=-1;}
                    else if(vdir==DIR_DOWN){vdx=0;vdy=1;}
                    else if(vdir==DIR_LEFT){vdx=-1;vdy=0;}
                    else{vdx=1;vdy=0;}
                }
            }
        }
        if(vdead) break;
        if(!vpaused){
            uint32_t sp=12;
            if(vscore>=10)sp=9; if(vscore>=20)sp=7; if(vscore>=35)sp=5;
            uint32_t now=(uint32_t)timer_ticks;
            if((uint32_t)(now-last)>=sp){last=now;vga_step();if(vdead)break;}
        }
        syscall0(SYS_YIELD);
    }
    int nb=(vscore>vbest); if(nb){vbest=vscore;hs_save(vbest);}
    int cx=VGA_BOARD_X+VGA_BOARD_W/2, cy=VGA_BOARD_Y+VGA_BOARD_H/2-1;
    vga_str(cx-4,cy,"GAME OVER",COL(C_LRED,C_BLACK));
    char buf[12]; itoa_s(vscore,buf);
    vga_str(cx-5,cy+1,"Score: ",COL(C_WHITE,C_BLACK));
    vga_str(cx+2, cy+1,buf,COL(C_YELLOW,C_BLACK));
    if(nb) vga_str(cx-5,cy+2,"New best!",COL(C_LGREEN,C_BLACK));
    else { char bb[12]; itoa_s(vbest,bb);
        vga_str(cx-5,cy+2,"Best: ",COL(C_WHITE,C_BLACK));
        vga_str(cx+1,cy+2,bb,COL(C_LGREEN,C_BLACK));}
    vga_str(cx-8,cy+3,"Press any key...",COL(C_LGREY,C_BLACK));
    syscall0(SYS_GETKEY);
    syscall0(SYS_CLEAR);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  GOP PIXEL RENDERER  (MB2 / UEFI path)
 * ════════════════════════════════════════════════════════════════════════════
 *
 * Layout at 1280×800:
 *   Cell size: 20×20 px
 *   Board: 54 cols × 36 rows = 1080×720 px
 *   Board origin: x=20, y=40 (leaves room for title bar + right sidebar)
 *   Sidebar: x=1120, width=140 px
 *   Border: 4 px thick filled rect around the board
 */

/* packed 0x00RRGGBB → syscall arg */
#define RGB(r,g,b) ((uint32_t)(((uint32_t)(r)<<16)|((uint32_t)(g)<<8)|(uint32_t)(b)))

/* Palette for GOP — richer than VGA 16-colour */
#define COL_BG        RGB(0x0D,0x0D,0x1A)   /* near-black dark blue background  */
#define COL_BORDER    RGB(0x33,0x33,0x66)   /* dim purple border                */
#define COL_HEAD      RGB(0x00,0xFF,0x88)   /* bright green head                */
#define COL_BODY      RGB(0x00,0xCC,0x55)   /* medium green body                */
#define COL_APPLE     RGB(0xFF,0x33,0x44)   /* vivid red apple                  */
#define COL_SIDEBAR   RGB(0x11,0x11,0x22)   /* slightly lighter than BG         */
#define COL_TEXT      RGB(0xCC,0xCC,0xFF)   /* light lavender text              */
#define COL_TITLE     RGB(0x44,0xDD,0xFF)   /* cyan title                       */
#define COL_SCORE_V   RGB(0xFF,0xFF,0x44)   /* yellow score value               */
#define COL_BEST_V    RGB(0x44,0xFF,0x88)   /* green best value                 */
#define COL_DEAD      RGB(0xFF,0x22,0x22)   /* red game over text               */
#define COL_PAUSE     RGB(0xFF,0xCC,0x00)   /* amber pause overlay              */
#define COL_GRID      RGB(0x16,0x16,0x2A)   /* subtle grid lines                */
#define COL_CELL_EMPTY COL_BG

/* Board geometry — computed from framebuffer; stored at init */
static uint32_t G_cell;          /* cell size in pixels          */
static uint32_t G_bx, G_by;     /* board pixel origin           */
static uint32_t G_bw, G_bh;     /* board pixel size             */
static int      G_cols, G_rows;  /* board dimensions in cells    */
static uint32_t G_sbx;           /* sidebar x                    */
static uint32_t G_fbw, G_fbh;   /* framebuffer pixel dimensions */

#define GOP_MAX_LEN (128*128)
static int gsx[GOP_MAX_LEN], gsy[GOP_MAX_LEN];
static int gslen, gdx, gdy, gax, gay, gscore, gbest, gpaused, gdead, gdir;

/* ── Low-level fill rectangle via syscall ─────────────────────────────────── */
static void fill(uint32_t x, uint32_t y, uint32_t w, uint32_t h, uint32_t c) {
    syscall5(SYS_FB_FILLRECT, x, y, w, h, (uint64_t)c);
}

/* ── Draw a single game cell ──────────────────────────────────────────────── */
static void gop_draw_cell(int cx, int cy, uint32_t color) {
    uint32_t px = G_bx + (uint32_t)cx * G_cell + 1;
    uint32_t py = G_by + (uint32_t)cy * G_cell + 1;
    fill(px, py, G_cell-2, G_cell-2, color);
}

static void gop_erase_cell(int cx, int cy) {
    gop_draw_cell(cx, cy, COL_CELL_EMPTY);
}

/* ── Draw the grid lines (called once on init) ────────────────────────────── */
static void gop_draw_grid(void) {
    /* Horizontal lines */
    for (int r=0; r<=G_rows; r++)
        fill(G_bx, G_by+(uint32_t)r*G_cell, G_bw, 1, COL_GRID);
    /* Vertical lines */
    for (int c=0; c<=G_cols; c++)
        fill(G_bx+(uint32_t)c*G_cell, G_by, 1, G_bh, COL_GRID);
}

/* ── Inline bitmap font renderer via SYS_PUTCELL ─────────────────────────── */
/* We re-use the kernel's char renderer for sidebar text — it's already routed
   through GOP. We compute the char column/row from pixel coords. */
static void gop_text(uint32_t px, uint32_t py, const char *s, uint8_t attr) {
    uint32_t col = px / 8;
    uint32_t row = py / 16;
    while (*s) {
        uint64_t packed = (uint64_t)(uint8_t)*s | ((uint64_t)attr << 8);
        syscall3(SYS_PUTCELL, (uint64_t)col++, (uint64_t)row, packed);
        s++;
    }
}

/* Convenience: print integer at pixel position */
static void gop_text_int(uint32_t px, uint32_t py, int n, uint8_t attr) {
    char buf[12]; itoa_s(n, buf); gop_text(px, py, buf, attr);
}

/* ── Sidebar ──────────────────────────────────────────────────────────────── */
static void gop_draw_sidebar(void) {
    fill(G_sbx, 0, G_fbw - G_sbx, G_fbh, COL_SIDEBAR);

    uint32_t tx = G_sbx + 8;
    gop_text(tx, 20,  "SNAKE",   COL(C_CYAN,   C_BLACK));
    gop_text(tx, 60,  "Score",   COL(C_WHITE,  C_BLACK));
    gop_text(tx, 80,  "Best",    COL(C_WHITE,  C_BLACK));
    gop_text_int(tx, 76, gscore, COL(C_YELLOW, C_BLACK));
    gop_text_int(tx, 96, gbest,  COL(C_LGREEN, C_BLACK));
    gop_text(tx, 130, "WASD /",  COL(C_LGREY,  C_BLACK));
    gop_text(tx, 146, "arrows",  COL(C_LGREY,  C_BLACK));
    gop_text(tx, 162, "P pause", COL(C_LGREY,  C_BLACK));
    gop_text(tx, 178, "Q quit",  COL(C_LGREY,  C_BLACK));
}

static void gop_update_score(void) {
    uint32_t tx = G_sbx + 8;
    /* Blank the number areas */
    fill(tx, 76, 80, 16, COL_SIDEBAR);
    fill(tx, 96, 80, 16, COL_SIDEBAR);
    gop_text_int(tx, 76, gscore, COL(C_YELLOW, C_BLACK));
    gop_text_int(tx, 96, gbest,  COL(C_LGREEN, C_BLACK));
}

/* ── Title bar ────────────────────────────────────────────────────────────── */
static void gop_draw_title(void) {
    fill(0, 0, G_sbx, G_by, COL_BG);
    gop_text(G_bx, 12, "NephilimOS  Snake", COL(C_CYAN, C_BLACK));
}

/* ── Border around board ──────────────────────────────────────────────────── */
static void gop_draw_border(void) {
    uint32_t t = 3;   /* border thickness */
    fill(G_bx-t, G_by-t, G_bw+2*t, t,      COL_BORDER);  /* top    */
    fill(G_bx-t, G_by+G_bh, G_bw+2*t, t,   COL_BORDER);  /* bottom */
    fill(G_bx-t, G_by-t, t,      G_bh+2*t, COL_BORDER);  /* left   */
    fill(G_bx+G_bw, G_by-t, t,   G_bh+2*t, COL_BORDER);  /* right  */
}

/* ── Apple ────────────────────────────────────────────────────────────────── */
static void gop_place_apple(void) {
    int max = G_cols * G_rows;
    for (int a=0; a<1000; a++) {
        int nx=(int)(rng_next()%(uint32_t)G_cols);
        int ny=(int)(rng_next()%(uint32_t)G_rows);
        int ok=1;
        for(int i=0;i<gslen;i++) if(gsx[i]==nx&&gsy[i]==ny){ok=0;break;}
        if(ok){gax=nx;gay=ny;return;}
        (void)max;
    }
}

/* ── Snake render ─────────────────────────────────────────────────────────── */
static void gop_draw_snake(void) {
    gop_draw_cell(gsx[0], gsy[0], COL_HEAD);
    for(int i=1;i<gslen;i++) gop_draw_cell(gsx[i],gsy[i],COL_BODY);
}

/* ── Init ─────────────────────────────────────────────────────────────────── */
static void gop_game_init(void) {
    rng_state ^= (uint32_t)timer_ticks;
    gslen=5; gdx=1; gdy=0; gdir=DIR_RIGHT;
    gscore=0; gpaused=0; gdead=0;
    int hx=G_cols/2, hy=G_rows/2;
    for(int i=0;i<gslen;i++){gsx[i]=hx-i;gsy[i]=hy;}
    gop_place_apple();
}

/* ── Game step ────────────────────────────────────────────────────────────── */
static void gop_step(void) {
    int nx=gsx[0]+gdx, ny=gsy[0]+gdy;
    if(nx<0||nx>=G_cols||ny<0||ny>=G_rows){gdead=1;return;}
    for(int i=0;i<gslen;i++) if(gsx[i]==nx&&gsy[i]==ny){gdead=1;return;}
    int ate=(nx==gax&&ny==gay);
    if(!ate) gop_erase_cell(gsx[gslen-1],gsy[gslen-1]);
    int nl=ate?gslen+1:gslen; if(nl>GOP_MAX_LEN)nl=GOP_MAX_LEN;
    for(int i=nl-1;i>0;i--){gsx[i]=gsx[i-1];gsy[i]=gsy[i-1];}
    gsx[0]=nx;gsy[0]=ny;gslen=nl;
    if(ate){gscore++;gop_update_score();gop_place_apple();
        gop_draw_cell(gax,gay,COL_APPLE);}
    gop_draw_snake();
}

/* ── Overlay: centered message box ────────────────────────────────────────── */
static void gop_msg_box(const char *line1, const char *line2, const char *line3) {
    uint32_t bw=260, bh=80;
    uint32_t bx=(G_bx+G_bw/2)-bw/2, by=(G_by+G_bh/2)-bh/2;
    fill(bx-4,by-4,bw+8,bh+8, COL_BORDER);
    fill(bx,by,bw,bh, COL_BG);
    int cw1=strlen_s(line1), cw2=strlen_s(line2), cw3=strlen_s(line3);
    gop_text(bx+(bw-(uint32_t)cw1*8)/2, by+8,  line1, COL(C_LRED,   C_BLACK));
    gop_text(bx+(bw-(uint32_t)cw2*8)/2, by+30, line2, COL(C_YELLOW, C_BLACK));
    gop_text(bx+(bw-(uint32_t)cw3*8)/2, by+54, line3, COL(C_LGREY,  C_BLACK));
}

/* ── Main GOP game loop ───────────────────────────────────────────────────── */
static void snake_gop(fb_info_t *fbi) {
    G_fbw = fbi->fb_width;
    G_fbh = fbi->fb_height;

    /* Choose cell size so board fills ~85% of screen height */
    G_cell = 20;
    G_rows = (int)((G_fbh * 85 / 100) / G_cell);
    G_cols = G_rows * 3 / 2;          /* ~3:2 aspect */
    G_bw   = (uint32_t)G_cols * G_cell;
    G_bh   = (uint32_t)G_rows * G_cell;

    /* Center board horizontally, leave room for sidebar on right */
    uint32_t sidebar_w = 160;
    G_sbx = G_fbw - sidebar_w;
    G_bx  = (G_sbx - G_bw) / 2;
    G_by  = (G_fbh - G_bh) / 2 + 8;

    gbest = hs_load();

    /* Full screen clear */
    fill(0, 0, G_fbw, G_fbh, COL_BG);
    gop_draw_title();
    gop_draw_sidebar();
    gop_draw_border();
    gop_draw_grid();

    gop_game_init();
    gop_draw_cell(gax, gay, COL_APPLE);
    gop_draw_snake();

    uint32_t last = (uint32_t)timer_ticks;

    for(;;) {
        int k = (int)syscall0(SYS_GETKEY_NB);
        if (k >= 0) {
            if (k=='q'||k=='Q') { gdead=1; }
            else if (k=='p'||k=='P') {
                gpaused ^= 1;
                if (gpaused)
                    gop_msg_box("  PAUSED  ", "P to resume", "");
                else {
                    /* Redraw the board area to remove overlay */
                    fill(G_bx, G_by, G_bw, G_bh, COL_BG);
                    gop_draw_grid();
                    gop_draw_cell(gax, gay, COL_APPLE);
                    gop_draw_snake();
                }
            } else {
                int nd = gdir;
                if((k=='w'||k=='W'||k==KEY_UP)   &&gdir!=DIR_DOWN) nd=DIR_UP;
                if((k=='s'||k=='S'||k==KEY_DOWN)  &&gdir!=DIR_UP)   nd=DIR_DOWN;
                if((k=='a'||k=='A'||k==KEY_LEFT)  &&gdir!=DIR_RIGHT)nd=DIR_LEFT;
                if((k=='d'||k=='D'||k==KEY_RIGHT) &&gdir!=DIR_LEFT) nd=DIR_RIGHT;
                if(nd!=gdir){gdir=nd;
                    if(gdir==DIR_UP){gdx=0;gdy=-1;}
                    else if(gdir==DIR_DOWN){gdx=0;gdy=1;}
                    else if(gdir==DIR_LEFT){gdx=-1;gdy=0;}
                    else{gdx=1;gdy=0;}
                }
            }
        }
        if (gdead) break;
        if (!gpaused) {
            uint32_t sp = 10;
            if(gscore>=15)sp=8; if(gscore>=30)sp=6; if(gscore>=50)sp=4;
            uint32_t now=(uint32_t)timer_ticks;
            if((uint32_t)(now-last)>=sp){last=now;gop_step();if(gdead)break;}
        }
        syscall0(SYS_YIELD);
    }

    int nb=(gscore>gbest); if(nb){gbest=gscore;hs_save(gbest);}

    char score_line[32];
    char best_line[32];
    /* build "Score: NN" */
    const char *sp="Score: "; int si=0;
    while(sp[si]) score_line[si]=sp[si++];
    char snum[12]; itoa_s(gscore,snum);
    int sni=0; while(snum[sni]) score_line[si++]=snum[sni++]; score_line[si]='\0';

    if (nb) {
        const char *bp="New best!"; int bi=0;
        while(bp[bi]) best_line[bi]=bp[bi++]; best_line[bi]='\0';
    } else {
        const char *bp="Best: "; int bi=0;
        while(bp[bi]) best_line[bi]=bp[bi++];
        char bnum[12]; itoa_s(gbest,bnum);
        int bni=0; while(bnum[bni]) best_line[bi++]=bnum[bni++]; best_line[bi]='\0';
    }

    gop_msg_box("GAME OVER", score_line, "Press any key");
    syscall0(SYS_GETKEY);
    fill(0, 0, G_fbw, G_fbh, COL_BG);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  Entry point
 * ════════════════════════════════════════════════════════════════════════════*/
void snake_main(void) {
    fb_info_t fbi;
    syscall1(SYS_FB_INFO, (uint64_t)&fbi);

    if (fbi.mode == 1)
        snake_gop(&fbi);
    else
        snake_vga();
}

