#include <vga.h>
#include <gop.h>
#include <font.h>
#include <serial.h>
#include <string.h>
#include <stdint.h>
#include <stddef.h>
#include <stdbool.h>

/* ── Logical cursor state (character grid) ─────────────────────────────────── */
size_t  vga_col   = 0;
size_t  vga_row   = 0;
uint8_t vga_color = 0x0F;   /* white-on-black (VGA text palette) */

/* ── Active display path ───────────────────────────────────────────────────── */
static bool use_gop_path = false;

/* ── GOP text-rendering parameters ────────────────────────────────────────────
 *
 * We render an 80×25 character grid on top of the GOP framebuffer using the
 * 8×16 bitmap font.  GOP_CELL_W / GOP_CELL_H define glyph dimensions.
 *
 * Foreground: white (0xFF, 0xFF, 0xFF)
 * Background: black (0x00, 0x00, 0x00)
 *
 * These can be extended later to support 16-colour text like VGA.
 */
#define GOP_CELL_W  8
#define GOP_CELL_H  16

/* ── Port I/O (VGA text-mode path only) ────────────────────────────────────── */
static inline void outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}
static inline uint8_t inb(uint16_t port) {
    uint8_t val;
    __asm__ volatile ("inb %1, %0" : "=a"(val) : "Nd"(port));
    return val;
}

/* ── VGA hardware cursor ───────────────────────────────────────────────────── */
void vga_cursor_enable(uint8_t cursor_start, uint8_t cursor_end) {
    outb(VGA_CRTC_INDEX, 0x0A);
    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xC0) | (cursor_start & 0x1F));
    outb(VGA_CRTC_INDEX, 0x0B);
    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xE0) | (cursor_end & 0x1F));
}

void vga_cursor_disable(void) {
    outb(VGA_CRTC_INDEX, 0x0A);
    outb(VGA_CRTC_DATA,  0x20);
}

void vga_cursor_move(size_t col, size_t row) {
    uint16_t pos = (uint16_t)(row * VGA_WIDTH + col);
    outb(VGA_CRTC_INDEX, 0x0F);
    outb(VGA_CRTC_DATA,  (uint8_t)(pos & 0xFF));
    outb(VGA_CRTC_INDEX, 0x0E);
    outb(VGA_CRTC_DATA,  (uint8_t)((pos >> 8) & 0xFF));
}

/* ── VGA font upload (text-mode path only) ─────────────────────────────────── */
static void vga_load_font(void) {
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);
    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x04);
    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x07);
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);

    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x02);
    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x00);
    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x04);

    volatile uint8_t *plane2 = (volatile uint8_t *)0xA0000;
    for (int ch = 0; ch < 256; ch++) {
        for (int row = 0; row < 16; row++)
            plane2[ch * 32 + row] = font8x16[ch][row];
        for (int row = 16; row < 32; row++)
            plane2[ch * 32 + row] = 0x00;
    }

    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);
    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x03);
    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x03);
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);

    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x00);
    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x10);
    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x0E);
}

static void vga_set_80x25(void) {
    outb(VGA_CRTC_INDEX, 0x11);
    uint8_t r11 = inb(VGA_CRTC_DATA) & ~0x80u;
    outb(VGA_CRTC_DATA, r11);
    outb(VGA_CRTC_INDEX, 0x09);
    uint8_t r09 = (inb(VGA_CRTC_DATA) & 0x60u) | 0x0Fu;
    outb(VGA_CRTC_DATA, r09);
}

/* ── Initialisation ────────────────────────────────────────────────────────── */

void vga_init(void) {
    use_gop_path = false;
    vga_load_font();
    vga_set_80x25();
    vga_cursor_enable(14, 15);
    vga_cursor_move(0, 0);
    vga_col = 0;
    vga_row = 0;
}

void vga_init_gop(void) {
    use_gop_path = true;
    vga_col = 0;
    vga_row = 0;
    /* No I/O port access — framebuffer is the display */
}

/* ── GOP: convert a VGA palette index to a 32-bit GOP colour ───────────────── */
static uint32_t vga_pal_to_gop(uint8_t idx) {
    /* Standard VGA 16-colour palette in (R, G, B) */
    static const uint8_t pal[16][3] = {
        {0x00,0x00,0x00}, /* 0  black         */
        {0x00,0x00,0xAA}, /* 1  blue          */
        {0x00,0xAA,0x00}, /* 2  green         */
        {0x00,0xAA,0xAA}, /* 3  cyan          */
        {0xAA,0x00,0x00}, /* 4  red           */
        {0xAA,0x00,0xAA}, /* 5  magenta       */
        {0xAA,0x55,0x00}, /* 6  brown         */
        {0xAA,0xAA,0xAA}, /* 7  light grey    */
        {0x55,0x55,0x55}, /* 8  dark grey     */
        {0x55,0x55,0xFF}, /* 9  light blue    */
        {0x55,0xFF,0x55}, /* 10 light green   */
        {0x55,0xFF,0xFF}, /* 11 light cyan    */
        {0xFF,0x55,0x55}, /* 12 light red     */
        {0xFF,0x55,0xFF}, /* 13 light magenta */
        {0xFF,0xFF,0x55}, /* 14 yellow        */
        {0xFF,0xFF,0xFF}, /* 15 white         */
    };
    idx &= 0x0F;
    return gop_pack_color(pal[idx][0], pal[idx][1], pal[idx][2]);
}

/* ── GOP text renderer: draw one glyph at the logical cursor position ──────── */
static void gop_render_char(char c, uint8_t attr) {
    uint32_t fg = vga_pal_to_gop(attr & 0x0F);
    uint32_t bg = vga_pal_to_gop((attr >> 4) & 0x0F);
    uint32_t px = (uint32_t)vga_col * GOP_CELL_W;
    uint32_t py = (uint32_t)vga_row * GOP_CELL_H;
    gop_draw_glyph(px, py, font8x16[(uint8_t)c], 16, fg, bg);
}

/* Erase a character cell to background colour */
static void gop_erase_cell(size_t col, size_t row) {
    uint32_t bg = vga_pal_to_gop((vga_color >> 4) & 0x0F);
    uint32_t px = (uint32_t)col * GOP_CELL_W;
    uint32_t py = (uint32_t)row * GOP_CELL_H;
    gop_fill_rect(px, py, GOP_CELL_W, GOP_CELL_H, bg);
}

/* ── Scrolling ─────────────────────────────────────────────────────────────── */
static void vga_scroll(void) {
    if (!use_gop_path) {
        memmove((void *)VGA_ADDR,
                (const void *)(VGA_ADDR + VGA_WIDTH),
                (VGA_HEIGHT - 1) * VGA_WIDTH * sizeof(uint16_t));
        uint16_t blank = vga_entry(' ', vga_color);
        for (size_t col = 0; col < VGA_WIDTH; col++)
            VGA_ADDR[(VGA_HEIGHT - 1) * VGA_WIDTH + col] = blank;
    } else {
        /* Blit rows 1..24 up to rows 0..23 */
        uint32_t src_y = GOP_CELL_H;
        uint32_t dst_y = 0;
        uint32_t copy_h = (VGA_HEIGHT - 1) * GOP_CELL_H;
        uint32_t row_bytes = (uint32_t)gop_fb.width * (gop_fb.bpp / 8u);

        for (uint32_t y = 0; y < copy_h; y++) {
            volatile uint8_t *dst = (volatile uint8_t *)(uintptr_t)
                (gop_fb.addr + (uint64_t)(dst_y + y) * gop_fb.pitch);
            volatile uint8_t *src = (volatile uint8_t *)(uintptr_t)
                (gop_fb.addr + (uint64_t)(src_y + y) * gop_fb.pitch);
            for (uint32_t x = 0; x < row_bytes; x++)
                dst[x] = src[x];
        }

        /* Clear the bottom row */
        uint32_t bg = vga_pal_to_gop((vga_color >> 4) & 0x0F);
        gop_fill_rect(0, (uint32_t)(VGA_HEIGHT - 1) * GOP_CELL_H,
                      gop_fb.width, GOP_CELL_H, bg);
    }
    vga_row = VGA_HEIGHT - 1;
}

/* ── Screen clear ──────────────────────────────────────────────────────────── */
void vga_clear(void) {
    if (!use_gop_path) {
        for (size_t i = 0; i < VGA_WIDTH * VGA_HEIGHT; i++)
            VGA_ADDR[i] = vga_entry(' ', vga_color);
        vga_cursor_move(0, 0);
    } else {
        uint32_t bg = vga_pal_to_gop((vga_color >> 4) & 0x0F);
        gop_clear(bg);
    }
    vga_col = 0;
    vga_row = 0;
}

/* ── Logical cursor ────────────────────────────────────────────────────────── */
void vga_goto(size_t col, size_t row) {
    if (col >= VGA_WIDTH)  col = VGA_WIDTH  - 1;
    if (row >= VGA_HEIGHT) row = VGA_HEIGHT - 1;
    vga_col = col;
    vga_row = row;
    if (!use_gop_path) vga_cursor_move(col, row);
}

/* ── Character output ──────────────────────────────────────────────────────── */
static void vga_putchar(char c) {
    if (c == '\n') {
        vga_col = 0;
        if (++vga_row >= VGA_HEIGHT) vga_scroll();
        return;
    }
    if (c == '\r') { vga_col = 0; return; }
    if (c == '\t') {
        vga_col = (vga_col + 8) & ~7u;
        if (vga_col >= VGA_WIDTH) {
            vga_col = 0;
            if (++vga_row >= VGA_HEIGHT) vga_scroll();
        }
        return;
    }
    if (c == '\b') {
        if (vga_col > 0) vga_col--;
        if (!use_gop_path)
            VGA_ADDR[vga_row * VGA_WIDTH + vga_col] = vga_entry(' ', vga_color);
        else
            gop_erase_cell(vga_col, vga_row);
        return;
    }

    if (!use_gop_path) {
        VGA_ADDR[vga_row * VGA_WIDTH + vga_col] = vga_entry(c, vga_color);
    } else {
        gop_render_char(c, vga_color);
    }

    if (++vga_col >= VGA_WIDTH) {
        vga_col = 0;
        if (++vga_row >= VGA_HEIGHT) vga_scroll();
    }
}

/* ── Print API ─────────────────────────────────────────────────────────────── */
void kprint_char(char c) {
    vga_putchar(c);
    if (!use_gop_path) vga_cursor_move(vga_col, vga_row);
}

void kprint(const char *str) {
    serial_print(str);
    for (size_t i = 0; str[i]; i++)
        vga_putchar(str[i]);
    if (!use_gop_path) vga_cursor_move(vga_col, vga_row);
}

void kprint_color(const char *str, uint8_t color) {
    uint8_t saved = vga_color;
    vga_color = color;
    kprint(str);
    vga_color = saved;
}

void kprint_uint64(uint64_t n) {
    if (n == 0) { kprint("0"); return; }
    char buf[21]; int i = 20; buf[i] = '\0';
    while (n) { buf[--i] = '0' + (int)(n % 10); n /= 10; }
    kprint(buf + i);
}

void kprint_hex(uint64_t n) {
    static const char hex[] = "0123456789ABCDEF";
    char buf[19]; buf[0]='0'; buf[1]='x'; int i = 18; buf[i] = '\0';
    if (n == 0) { kprint("0x0"); return; }
    while (n) { buf[--i] = hex[n & 0xF]; n >>= 4; }
    kprint(buf + i - 2);
}

