#include <vga.h>
#include <gop.h>
#include <font.h>
#include <serial.h>
#include <string.h>
#include <stdint.h>
#include <stddef.h>
#include <stdbool.h>

/* ── Logical cursor state (character grid) ─────────────────────────────────── */
size_t  vga_col   = 0;
size_t  vga_row   = 0;
uint8_t vga_color = 0x0F;   /* white-on-black (VGA text palette) */

/* ── Active display path ───────────────────────────────────────────────────── */
static bool use_gop_path = false;

/* ── GOP text-rendering parameters ────────────────────────────────────────────
 *
 * We render an 80×25 character grid on top of the GOP framebuffer using the
 * 8×16 bitmap font.  GOP_CELL_W / GOP_CELL_H define glyph dimensions.
 *
 * Foreground: white (0xFF, 0xFF, 0xFF)
 * Background: black (0x00, 0x00, 0x00)
 *
 * These can be extended later to support 16-colour text like VGA.
 */
#define GOP_CELL_W  8
#define GOP_CELL_H  16

/* ── Port I/O (VGA text-mode path only) ────────────────────────────────────── */
static inline void outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}
static inline uint8_t inb(uint16_t port) {
    uint8_t val;
    __asm__ volatile ("inb %1, %0" : "=a"(val) : "Nd"(port));
    return val;
}

/* ── VGA hardware cursor ───────────────────────────────────────────────────── */
void vga_cursor_enable(uint8_t cursor_start, uint8_t cursor_end) {
    outb(VGA_CRTC_INDEX, 0x0A);
    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xC0) | (cursor_start & 0x1F));
    outb(VGA_CRTC_INDEX, 0x0B);
    outb(VGA_CRTC_DATA,  (inb(VGA_CRTC_DATA) & 0xE0) | (cursor_end & 0x1F));
}

void vga_cursor_disable(void) {
    outb(VGA_CRTC_INDEX, 0x0A);
    outb(VGA_CRTC_DATA,  0x20);
}

void vga_cursor_move(size_t col, size_t row) {
    uint16_t pos = (uint16_t)(row * VGA_WIDTH + col);
    outb(VGA_CRTC_INDEX, 0x0F);
    outb(VGA_CRTC_DATA,  (uint8_t)(pos & 0xFF));
    outb(VGA_CRTC_INDEX, 0x0E);
    outb(VGA_CRTC_DATA,  (uint8_t)((pos >> 8) & 0xFF));
}

/* ── VGA font upload (text-mode path only) ─────────────────────────────────── */
static void vga_load_font(void) {
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);
    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x04);
    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x07);
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);

    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x02);
    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x00);
    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x04);

    volatile uint8_t *plane2 = (volatile uint8_t *)0xA0000;
    for (int ch = 0; ch < 256; ch++) {
        for (int row = 0; row < 16; row++)
            plane2[ch * 32 + row] = font8x16[ch][row];
        for (int row = 16; row < 32; row++)
            plane2[ch * 32 + row] = 0x00;
    }

    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x01);
    outb(VGA_SEQ_INDEX, 0x02); outb(VGA_SEQ_DATA, 0x03);
    outb(VGA_SEQ_INDEX, 0x04); outb(VGA_SEQ_DATA, 0x03);
    outb(VGA_SEQ_INDEX, 0x00); outb(VGA_SEQ_DATA, 0x03);

    outb(VGA_GC_INDEX,  0x04); outb(VGA_GC_DATA,  0x00);
    outb(VGA_GC_INDEX,  0x05); outb(VGA_GC_DATA,  0x10);
    outb(VGA_GC_INDEX,  0x06); outb(VGA_GC_DATA,  0x0E);
}

static void vga_set_80x25(void) {
    outb(VGA_CRTC_INDEX, 0x11);
    uint8_t r11 = inb(VGA_CRTC_DATA) & ~0x80u;
    outb(VGA_CRTC_DATA, r11);
    outb(VGA_CRTC_INDEX, 0x09);
    uint8_t r09 = (inb(VGA_CRTC_DATA) & 0x60u) | 0x0Fu;
    outb(VGA_CRTC_DATA, r09);
}

/* ── Initialisation ────────────────────────────────────────────────────────── */

void vga_init(void) {
    use_gop_path = false;
    vga_load_font();
    vga_set_80x25();
    vga_cursor_enable(14, 15);
    vga_cursor_move(0, 0);
    vga_col = 0;
    vga_row = 0;
}

void vga_init_gop(void) {
    use_gop_path = true;
    vga_col = 0;
    vga_row = 0;
    /* No I/O port access — framebuffer is the display */
}

/* ── GOP: convert a VGA palette index to a 32-bit GOP colour ───────────────── */
static uint32_t vga_pal_to_gop(uint8_t idx) {
    /* Standard VGA 16-colour palette in (R, G, B) */
    static const uint8_t pal[16][3] = {
        {0x00,0x00,0x00}, /* 0  black         */
        {0x00,0x00,0xAA}, /* 1  blue          */
        {0x00,0xAA,0x00}, /* 2  green         */
        {0x00,0xAA,0xAA}, /* 3  cyan          */
        {0xAA,0x00,0x00}, /* 4  red           */
        {0xAA,0x00,0xAA}, /* 5  magenta       */
        {0xAA,0x55,0x00}, /* 6  brown         */
        {0xAA,0xAA,0xAA}, /* 7  light grey    */
        {0x55,0x55,0x55}, /* 8  dark grey     */
        {0x55,0x55,0xFF}, /* 9  light blue    */
        {0x55,0xFF,0x55}, /* 10 light green   */
        {0x55,0xFF,0xFF}, /* 11 light cyan    */
        {0xFF,0x55,0x55}, /* 12 light red     */
        {0xFF,0x55,0xFF}, /* 13 light magenta */
        {0xFF,0xFF,0x55}, /* 14 yellow        */
        {0xFF,0xFF,0xFF}, /* 15 white         */
    };
    idx &= 0x0F;
    return gop_pack_color(pal[idx][0], pal[idx][1], pal[idx][2]);
}

/* ── GOP text renderer: draw one glyph at the logical cursor position ──────── */
static void gop_render_char(char c, uint8_t attr) {
    uint32_t fg = vga_pal_to_gop(attr & 0x0F);
    uint32_t bg = vga_pal_to_gop((attr >> 4) & 0x0F);
    uint32_t px = (uint32_t)vga_col * GOP_CELL_W;
    uint32_t py = (uint32_t)vga_row * GOP_CELL_H;
    gop_draw_glyph(px, py, font8x16[(uint8_t)c], 16, fg, bg);
}

/* Erase a character cell to background colour */
static void gop_erase_cell(size_t col, size_t row) {
    uint32_t bg = vga_pal_to_gop((vga_color >> 4) & 0x0F);
    uint32_t px = (uint32_t)col * GOP_CELL_W;
    uint32_t py = (uint32_t)row * GOP_CELL_H;
    gop_fill_rect(px, py, GOP_CELL_W, GOP_CELL_H, bg);
}

/* ── Scrolling ─────────────────────────────────────────────────────────────── */
static void vga_scroll(void) {
    size_t gc = grid_cols(), gr = grid_rows();
    if (!use_gop_path) {
        memmove((void *)VGA_ADDR,
                (const void *)(VGA_ADDR + gc),
                (gr - 1) * gc * sizeof(uint16_t));
        uint16_t blank = vga_entry(' ', vga_color);
        for (size_t col = 0; col < gc; col++)
            VGA_ADDR[(gr - 1) * gc + col] = blank;
    } else {
        uint32_t src_y = GOP_CELL_H;
        uint32_t copy_h = (uint32_t)(gr - 1) * GOP_CELL_H;
        uint32_t row_bytes = (uint32_t)gop_fb.width * (gop_fb.bpp / 8u);
        for (uint32_t y = 0; y < copy_h; y++) {
            volatile uint8_t *dst = (volatile uint8_t *)(uintptr_t)
                (gop_fb.addr + (uint64_t)y * gop_fb.pitch);
            volatile uint8_t *src = (volatile uint8_t *)(uintptr_t)
                (gop_fb.addr + (uint64_t)(src_y + y) * gop_fb.pitch);
            for (uint32_t x = 0; x < row_bytes; x++)
                dst[x] = src[x];
        }
        uint32_t bg = vga_pal_to_gop((vga_color >> 4) & 0x0F);
        gop_fill_rect(0, (uint32_t)(gr - 1) * GOP_CELL_H,
                      gop_fb.width, GOP_CELL_H, bg);
    }
    vga_row = gr - 1;
}

/* ── Screen clear ──────────────────────────────────────────────────────────── */
void vga_clear(void) {
    if (!use_gop_path) {
        for (size_t i = 0; i < VGA_WIDTH * VGA_HEIGHT; i++)
            VGA_ADDR[i] = vga_entry(' ', vga_color);
        vga_cursor_move(0, 0);
    } else {
        uint32_t bg = vga_pal_to_gop((vga_color >> 4) & 0x0F);
        gop_clear(bg);
    }
    vga_col = 0;
    vga_row = 0;
}

/* ── Logical cursor ────────────────────────────────────────────────────────── */

/* Grid dimensions — VGA text mode is always 80×25; GOP uses the full fb. */
static inline size_t grid_cols(void) {
    return use_gop_path ? (size_t)(gop_fb.width  / GOP_CELL_W) : (size_t)VGA_WIDTH;
}
static inline size_t grid_rows(void) {
    return use_gop_path ? (size_t)(gop_fb.height / GOP_CELL_H) : (size_t)VGA_HEIGHT;
}

void vga_goto(size_t col, size_t row) {
    size_t gc = grid_cols(), gr = grid_rows();
    if (col >= gc) col = gc - 1;
    if (row >= gr) row = gr - 1;
    vga_col = col;
    vga_row = row;
    if (!use_gop_path) vga_cursor_move(col, row);
}

/* ── Character output ──────────────────────────────────────────────────────── */
static void vga_putchar(char c) {
    size_t gc = grid_cols(), gr = grid_rows();
    if (c == '\n') {
        vga_col = 0;
        if (++vga_row >= gr) vga_scroll();
        return;
    }
    if (c == '\r') { vga_col = 0; return; }
    if (c == '\t') {
        vga_col = (vga_col + 8) & ~7u;
        if (vga_col >= gc) {
            vga_col = 0;
            if (++vga_row >= gr) vga_scroll();
        }
        return;
    }
    if (c == '\b') {
        if (vga_col > 0) vga_col--;
        if (!use_gop_path)
            VGA_ADDR[vga_row * gc + vga_col] = vga_entry(' ', vga_color);
        else
            gop_erase_cell(vga_col, vga_row);
        return;
    }

    if (!use_gop_path) {
        VGA_ADDR[vga_row * gc + vga_col] = vga_entry(c, vga_color);
    } else {
        gop_render_char(c, vga_color);
    }

    if (++vga_col >= gc) {
        vga_col = 0;
        if (++vga_row >= gr) vga_scroll();
    }
}

/* ── Print API ─────────────────────────────────────────────────────────────── */
void kprint_char(char c) {
    vga_putchar(c);
    if (!use_gop_path) vga_cursor_move(vga_col, vga_row);
}

void kprint(const char *str) {
    serial_print(str);
    for (size_t i = 0; str[i]; i++)
        vga_putchar(str[i]);
    if (!use_gop_path) vga_cursor_move(vga_col, vga_row);
}

void kprint_color(const char *str, uint8_t color) {
    uint8_t saved = vga_color;
    vga_color = color;
    kprint(str);
    vga_color = saved;
}

void kprint_uint64(uint64_t n) {
    if (n == 0) { kprint("0"); return; }
    char buf[21]; int i = 20; buf[i] = '\0';
    while (n) { buf[--i] = '0' + (int)(n % 10); n /= 10; }
    kprint(buf + i);
}

void kprint_hex(uint64_t n) {
    static const char hex[] = "0123456789ABCDEF";
    char buf[19]; buf[0]='0'; buf[1]='x'; int i = 18; buf[i] = '\0';
    if (n == 0) { kprint("0x0"); return; }
    while (n) { buf[--i] = hex[n & 0xF]; n >>= 4; }
    kprint(buf + i - 2);
}

#ifndef _SYSCALL_H
#define _SYSCALL_H

#include <stdint.h>
#include <stddef.h>

/* ── I/O syscalls ─────────────────────────────────────────────────────────── */
#define SYS_PRINT      0   /* rdi=str, rsi=len (0=null-term)                  */
#define SYS_CLEAR      1   /* —                                               */
#define SYS_NEWLINE    2   /* —                                               */
#define SYS_READ_MEM   3   /* rdi=phys_addr → rax=uint64                      */
#define SYS_CPU_MODEL  4   /* rdi=buf, rsi=size                               */
#define SYS_SHUTDOWN   5   /* —                                               */
#define SYS_REBOOT     6   /* —                                               */

/* ── Process syscalls ─────────────────────────────────────────────────────── */
#define SYS_YIELD      7   /* — voluntarily relinquish CPU                    */
#define SYS_GETPID     8   /* — → rax = current pid                           */
#define SYS_SPAWN      9   /* rdi=entry, rsi=name_ptr, rdx=priority → pid     */
#define SYS_FORK      10   /* — → rax=child_pid (parent), 0 (child)           */
#define SYS_EXIT      11   /* rdi=exit_code — terminate calling process        */
#define SYS_KILL      12   /* rdi=pid — destroy target process                 */
#define SYS_WAIT      13   /* rdi=pid — block until target exits               */
#define SYS_SLEEP     14   /* rdi=ticks — block for N scheduler ticks          */
#define SYS_GETPNAME  15   /* rdi=pid, rsi=buf, rdx=size → name string         */

/* ── Input syscalls ─────────────────────────────────────────────────────── */
#define SYS_GETCHAR  16   /* — → rax = ASCII char (blocking)                  */
#define SYS_GETKEY   31   /* — → rax = int key code (KEY_* or ASCII)          */

/* ── Filesystem / process environment ────────────────────────────────────── */
#define SYS_CHDIR    32   /* rdi=path → 0 on success, -1 on error             */
#define SYS_GETCWD   33   /* rdi=buf, rsi=size → 0                            */

/* ── JS syscalls ─────────────────────────────────────────────────────────── */
#define SYS_JS_EXEC  17   /* rdi=source_ptr — run JS string, blocks           */

/* ── Time syscalls ────────────────────────────────────────────────────────── */
#define SYS_TIME          18   /* — → rax = seconds since boot (time_t)        */
#define SYS_CLOCK_GETTIME 19   /* rdi=*timespec, rsi=clockid → fills struct    */

/* ── Filesystem syscalls ──────────────────────────────────────────────────── */
#define SYS_FS_OPEN    20   /* rdi=path, rsi=flags, rdx=mode → fd            */
#define SYS_FS_CLOSE   21   /* rdi=fd → 0                                    */
#define SYS_FS_READ    22   /* rdi=fd, rsi=buf, rdx=len → bytes read         */
#define SYS_FS_WRITE   23   /* rdi=fd, rsi=buf, rdx=len → bytes written      */
#define SYS_FS_SEEK    24   /* rdi=fd, rsi=offset, rdx=whence → new offset   */
#define SYS_FS_STAT    25   /* rdi=path, rsi=stat_ptr → 0                    */
#define SYS_FS_FSTAT   26   /* rdi=fd, rsi=stat_ptr → 0                      */
#define SYS_FS_READDIR 27   /* rdi=fd, rsi=index, rdx=dirent_ptr → 0         */
#define SYS_FS_MKDIR   28   /* rdi=path, rsi=mode → 0                        */
#define SYS_FS_UNLINK  29   /* rdi=path → 0                                  */
#define SYS_FS_CREAT   30   /* rdi=path, rsi=mode → fd                       */

/* ── Process info ─────────────────────────────────────────────────────────── */
#define SYS_PS        34   /* rdi=buf (proc_snap_t*), rsi=max_entries → count  */

/* ── Non-blocking input ───────────────────────────────────────────────────── */
#define SYS_GETKEY_NB 35   /* — → rax = key code if pending, -1 if none        */

/* ── Display syscalls ─────────────────────────────────────────────────────── */
#define SYS_DISPLAY_MODE 36  /* — → 0=VGA text, 1=GOP framebuffer              */
#define SYS_PUTCELL      37  /* rdi=col, rsi=row, rdx=packed(char|attr<<8)      */
#define SYS_SETCURSOR    38  /* rdi=col, rsi=row                                */
#define SYS_FB_INFO      39  /* rdi=fb_info_t* → fills struct, returns 0        */
#define SYS_FB_FILLRECT  40  /* rdi=x,rsi=y,rdx=w, rcx=h, r8=rgb32             */

#define SYSCALL_COUNT 41

/* ── fb_info_t: returned by SYS_FB_INFO ──────────────────────────────────── */
typedef struct {
    uint32_t fb_width;    /* framebuffer width in pixels  (0 if VGA text mode) */
    uint32_t fb_height;   /* framebuffer height in pixels (0 if VGA text mode) */
    uint32_t char_cols;   /* character grid width  (80 for VGA, fb_w/8 for GOP)*/
    uint32_t char_rows;   /* character grid height (25 for VGA, fb_h/16 for GOP*/
    uint32_t cell_w;      /* pixels per character cell width                   */
    uint32_t cell_h;      /* pixels per character cell height                  */
    uint8_t  mode;        /* 0=VGA text, 1=GOP                                 */
} fb_info_t;

/* ── Return codes ─────────────────────────────────────────────────────────── */
#define ESYS_OK        0
#define ESYS_BADNUM   -1
#define ESYS_BADARG   -2
#define ESYS_NOMEM    -3   /* process table full                               */
#define ESYS_NOPROC   -4   /* no such PID                                      */
#define ESYS_PERM     -5   /* privilege violation                              */

/* ── Kernel-side init ─────────────────────────────────────────────────────── */
void syscall_init(void);

/* ── Inline invocation helpers (for Ring-1 code) ─────────────────────────── */
static inline int64_t syscall0(uint64_t num) {
    int64_t ret;
    __asm__ volatile ("int $0x80" : "=a"(ret) : "a"(num) : "memory");
    return ret;
}
static inline int64_t syscall1(uint64_t num, uint64_t a1) {
    int64_t ret;
    __asm__ volatile ("int $0x80" : "=a"(ret) : "a"(num), "D"(a1) : "memory");
    return ret;
}
static inline int64_t syscall2(uint64_t num, uint64_t a1, uint64_t a2) {
    int64_t ret;
    __asm__ volatile ("int $0x80" : "=a"(ret)
                      : "a"(num), "D"(a1), "S"(a2) : "memory");
    return ret;
}
static inline int64_t syscall3(uint64_t num, uint64_t a1, uint64_t a2, uint64_t a3) {
    int64_t ret;
    register uint64_t r10 __asm__("rdx") = a3;
    __asm__ volatile ("int $0x80" : "=a"(ret)
                      : "a"(num), "D"(a1), "S"(a2), "r"(r10) : "memory");
    return ret;
}
static inline int64_t syscall4(uint64_t num, uint64_t a1, uint64_t a2,
                                uint64_t a3, uint64_t a4) {
    int64_t ret;
    register uint64_t _a3 __asm__("rdx") = a3;
    register uint64_t _a4 __asm__("rcx") = a4;
    __asm__ volatile ("int $0x80" : "=a"(ret)
                      : "a"(num), "D"(a1), "S"(a2), "r"(_a3), "r"(_a4)
                      : "memory");
    return ret;
}
static inline int64_t syscall5(uint64_t num, uint64_t a1, uint64_t a2,
                                uint64_t a3, uint64_t a4, uint64_t a5) {
    int64_t ret;
    register uint64_t _a3 __asm__("rdx") = a3;
    register uint64_t _a4 __asm__("rcx") = a4;
    register uint64_t _a5 __asm__("r8")  = a5;
    __asm__ volatile ("int $0x80" : "=a"(ret)
                      : "a"(num), "D"(a1), "S"(a2), "r"(_a3), "r"(_a4), "r"(_a5)
                      : "memory");
    return ret;
}

#endif /* _SYSCALL_H */

