21	static int hs_atoi(const char *s) {
22	    int n = 0;
23	    while (*s >= '0' && *s <= '9') n = n * 10 + (*s++ - '0');
24	    return n;
25	}
26	static int hs_load(void) {
27	    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)HISCORE_PATH, O_RDONLY, 0);
28	    if (fd < 0) return 0;
29	    char buf[16] = {0};
30	    syscall3(SYS_FS_READ, (uint64_t)fd, (uint64_t)buf, sizeof(buf)-1);
31	    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
32	    return hs_atoi(buf);
33	}
34	static void hs_save(int hi) {
35	    char buf[12]; int i = 0;
36	    if (!hi) { buf[i++] = '0'; }
37	    else {
38	        char tmp[12]; int t = 0, n = hi;
39	        while (n) { tmp[t++] = '0' + n%10; n /= 10; }
40	        while (t)  buf[i++] = tmp[--t];
41	    }
42	    buf[i] = '\0';
43	    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)HISCORE_PATH,
44	                          O_WRONLY|O_CREAT|O_TRUNC, 0644);
45	    if (fd < 0) return;
46	    syscall3(SYS_FS_WRITE, (uint64_t)fd, (uint64_t)buf, (uint64_t)i);
47	    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
