121	static void vga_draw_cell(int x, int y, char ch, uint8_t attr) {
122	    vga_put(VGA_BOARD_X+x, VGA_BOARD_Y+y, ch, attr);
123	}
124	static void vga_erase_cell(int x, int y) {
125	    vga_draw_cell(x, y, ' ', COL(C_LGREY, C_BLACK));
126	}
127	static void vga_draw_border(void) {
128	    uint8_t ba = COL(C_LGREY, C_BLACK);
129	    for (int x=0; x<VGA_BOARD_W+2; x++) {
130	        vga_put(VGA_BOARD_X-1+x, VGA_BOARD_Y-1,         '-', ba);
131	        vga_put(VGA_BOARD_X-1+x, VGA_BOARD_Y+VGA_BOARD_H, '-', ba);
132	    }
133	    for (int y=0; y<VGA_BOARD_H; y++) {
134	        vga_put(VGA_BOARD_X-1,         VGA_BOARD_Y+y, '|', ba);
135	        vga_put(VGA_BOARD_X+VGA_BOARD_W, VGA_BOARD_Y+y, '|', ba);
136	    }
137	}
138	static void vga_draw_hud(void) {
139	    uint8_t ha = COL(C_WHITE, C_BLACK);
140	    int hx = VGA_BOARD_X + VGA_BOARD_W + 3;
141	    char buf[12];
142	    vga_str(hx, VGA_BOARD_Y,   "SNAKE",   COL(C_LBLUE, C_BLACK));
143	    vga_str(hx, VGA_BOARD_Y+2, "Score:",  ha);
144	    vga_str(hx+7, VGA_BOARD_Y+2, "      ", ha);
145	    itoa_s(vscore, buf); vga_str(hx+7, VGA_BOARD_Y+2, buf, COL(C_YELLOW,C_BLACK));
146	    vga_str(hx, VGA_BOARD_Y+3, "Best: ",  ha);
147	    vga_str(hx+7, VGA_BOARD_Y+3, "      ", ha);
148	    itoa_s(vbest, buf);  vga_str(hx+7, VGA_BOARD_Y+3, buf, COL(C_LGREEN,C_BLACK));
149	    vga_str(hx, VGA_BOARD_Y+5, "WASD/",   ha);
150	    vga_str(hx, VGA_BOARD_Y+6, "arrows",  ha);
151	    vga_str(hx, VGA_BOARD_Y+7, "P pause", ha);
152	    vga_str(hx, VGA_BOARD_Y+8, "Q quit",  ha);
153	}
154	static void vga_place_apple(void) {
155	    for (int a=0; a<1000; a++) {
156	        int nx=(int)(rng_next()%(uint32_t)VGA_BOARD_W);
157	        int ny=(int)(rng_next()%(uint32_t)VGA_BOARD_H);
158	        int ok=1;
159	        for (int i=0;i<vslen;i++) if(vsx[i]==nx&&vsy[i]==ny){ok=0;break;}
160	        if (ok){vax=nx;vay=ny;return;}
161	    }
162	}
163	static void vga_draw_snake(void) {
164	    vga_draw_cell(vsx[0],vsy[0],'@',COL(C_LBLUE,C_BLACK));
165	    for(int i=1;i<vslen;i++) vga_draw_cell(vsx[i],vsy[i],'o',COL(C_BLUE,C_BLACK));
166	}
167	static void vga_game_init(void) {
168	    rng_state ^= (uint32_t)timer_ticks;
169	    vslen=3; vdx=1; vdy=0; vdir=DIR_RIGHT;
170	    vscore=0; vpaused=0; vdead=0;
171	    int hx=VGA_BOARD_W/2, hy=VGA_BOARD_H/2;
172	    for(int i=0;i<vslen;i++){vsx[i]=hx-i;vsy[i]=hy;}
173	    vga_place_apple();
174	}
175	static void vga_step(void) {
176	    int nx=vsx[0]+vdx, ny=vsy[0]+vdy;
177	    if(nx<0||nx>=VGA_BOARD_W||ny<0||ny>=VGA_BOARD_H){vdead=1;return;}
178	    for(int i=0;i<vslen;i++) if(vsx[i]==nx&&vsy[i]==ny){vdead=1;return;}
179	    int ate=(nx==vax&&ny==vay);
180	    if(!ate) vga_erase_cell(vsx[vslen-1],vsy[vslen-1]);
181	    int nl=ate?vslen+1:vslen; if(nl>VGA_MAX_LEN)nl=VGA_MAX_LEN;
182	    for(int i=nl-1;i>0;i--){vsx[i]=vsx[i-1];vsy[i]=vsy[i-1];}
183	    vsx[0]=nx;vsy[0]=ny;vslen=nl;
184	    if(ate){vscore++;vga_draw_hud();vga_place_apple();
185	        vga_draw_cell(vax,vay,'*',COL(C_LMAGENTA,C_BLACK));}
186	    vga_draw_snake();
187	}
188	
189	static void snake_vga(void) {
190	    vbest=hs_load();
191	    syscall0(SYS_CLEAR);
192	    vga_draw_border();
193	    vga_game_init();
194	    vga_draw_hud();
195	    vga_draw_cell(vax,vay,'*',COL(C_LMAGENTA,C_BLACK));
196	    vga_draw_snake();
197	    uint32_t last=(uint32_t)timer_ticks;
198	    for(;;){
199	        int k=(int)syscall0(SYS_GETKEY_NB);
200	        if(k>=0){
201	            if(k=='q'||k=='Q'){vdead=1;}
202	            else if(k=='p'||k=='P'){vpaused^=1;}
203	            else {
204	                int nd=vdir;
205	                if((k=='w'||k=='W'||k==KEY_UP)   &&vdir!=DIR_DOWN) nd=DIR_UP;
206	                if((k=='s'||k=='S'||k==KEY_DOWN)  &&vdir!=DIR_UP)   nd=DIR_DOWN;
207	                if((k=='a'||k=='A'||k==KEY_LEFT)  &&vdir!=DIR_RIGHT)nd=DIR_LEFT;
208	                if((k=='d'||k=='D'||k==KEY_RIGHT) &&vdir!=DIR_LEFT) nd=DIR_RIGHT;
209	                if(nd!=vdir){vdir=nd;
210	                    if(vdir==DIR_UP){vdx=0;vdy=-1;}
211	                    else if(vdir==DIR_DOWN){vdx=0;vdy=1;}
212	                    else if(vdir==DIR_LEFT){vdx=-1;vdy=0;}
213	                    else{vdx=1;vdy=0;}
214	                }
215	            }
216	        }
217	        if(vdead) break;
218	        if(!vpaused){
219	            uint32_t sp=12;
220	            if(vscore>=10)sp=9; if(vscore>=20)sp=7; if(vscore>=35)sp=5;
221	            uint32_t now=(uint32_t)timer_ticks;
222	            if((uint32_t)(now-last)>=sp){last=now;vga_step();if(vdead)break;}
223	        }
224	        syscall0(SYS_YIELD);
225	    }
226	    int nb=(vscore>vbest); if(nb){vbest=vscore;hs_save(vbest);}
227	    int cx=VGA_BOARD_X+VGA_BOARD_W/2, cy=VGA_BOARD_Y+VGA_BOARD_H/2-1;
228	    vga_str(cx-4,cy,"GAME OVER",COL(C_LRED,C_BLACK));
229	    char buf[12]; itoa_s(vscore,buf);
230	    vga_str(cx-5,cy+1,"Score: ",COL(C_WHITE,C_BLACK));
231	    vga_str(cx+2, cy+1,buf,COL(C_YELLOW,C_BLACK));
232	    if(nb) vga_str(cx-5,cy+2,"New best!",COL(C_LGREEN,C_BLACK));
233	    else { char bb[12]; itoa_s(vbest,bb);
234	        vga_str(cx-5,cy+2,"Best: ",COL(C_WHITE,C_BLACK));
235	        vga_str(cx+1,cy+2,bb,COL(C_LGREEN,C_BLACK));}
236	    vga_str(cx-8,cy+3,"Press any key...",COL(C_LGREY,C_BLACK));
237	    syscall0(SYS_GETKEY);
238	    syscall0(SYS_CLEAR);
239	}
