241	/* ════════════════════════════════════════════════════════════════════════════
242	 *  GOP PIXEL RENDERER  (MB2 / UEFI path)
243	 * ════════════════════════════════════════════════════════════════════════════
244	 *
245	 * Layout at 1280×800:
246	 *   Cell size: 20×20 px
247	 *   Board: 54 cols × 36 rows = 1080×720 px
248	 *   Board origin: x=20, y=40 (leaves room for title bar + right sidebar)
249	 *   Sidebar: x=1120, width=140 px
250	 *   Border: 4 px thick filled rect around the board
251	 */
252	
253	/* packed 0x00RRGGBB → syscall arg */
254	#define RGB(r,g,b) ((uint32_t)(((uint32_t)(r)<<16)|((uint32_t)(g)<<8)|(uint32_t)(b)))
255	
256	/* ── Colour schemes ──────────────────────────────────────────────────────────
257	 * Scheme 0: Green snake / Red fruit  (classic)
258	 * Scheme 1: Blue snake  / Purple fruit
259	 * ──────────────────────────────────────────────────────────────────────────*/
260	#define NUM_SCHEMES 2
261	static int g_scheme = 0;
262	
263	typedef struct {
264	    uint32_t bg;
265	    uint32_t border;
266	    uint32_t grid;
267	    uint32_t head;
268	    uint32_t body;
269	    uint32_t fruit;
270	    uint32_t sidebar;
271	    uint8_t  title_attr;
272	    uint8_t  score_attr;
273	    uint8_t  best_attr;
274	} color_scheme_t;
275	
276	static const color_scheme_t schemes[NUM_SCHEMES] = {
277	    /* 0 — Green / Red */
278	    {
279	        .bg       = RGB(0x0D,0x0D,0x1A),
280	        .border   = RGB(0x33,0x55,0x33),
281	        .grid     = RGB(0x14,0x1E,0x14),
282	        .head     = RGB(0x00,0xFF,0x88),
283	        .body     = RGB(0x00,0xCC,0x44),
284	        .fruit    = RGB(0xFF,0x22,0x33),
285	        .sidebar  = RGB(0x0A,0x14,0x0A),
286	        .title_attr  = COL(C_LGREEN, C_BLACK),
287	        .score_attr  = COL(C_YELLOW, C_BLACK),
288	        .best_attr   = COL(C_LGREEN, C_BLACK),
289	    },
290	    /* 1 — Blue / Purple */
291	    {
292	        .bg       = RGB(0x08,0x08,0x18),
293	        .border   = RGB(0x33,0x33,0x77),
294	        .grid     = RGB(0x10,0x10,0x22),
295	        .head     = RGB(0x44,0xAA,0xFF),
296	        .body     = RGB(0x22,0x66,0xCC),
297	        .fruit    = RGB(0xCC,0x44,0xFF),
298	        .sidebar  = RGB(0x08,0x08,0x20),
299	        .title_attr  = COL(C_LCYAN,  C_BLACK),
300	        .score_attr  = COL(C_LBLUE,  C_BLACK),
