310	/* Board geometry — computed from framebuffer; stored at init */
311	static uint32_t G_cell;          /* cell size in pixels          */
312	static uint32_t G_bx, G_by;     /* board pixel origin           */
313	static uint32_t G_bw, G_bh;     /* board pixel size             */
314	static int      G_cols, G_rows;  /* board dimensions in cells    */
315	static uint32_t G_sbx;           /* sidebar x                    */
316	static uint32_t G_fbw, G_fbh;   /* framebuffer pixel dimensions */
317	
318	#define GOP_MAX_LEN (128*128)
319	static int gsx[GOP_MAX_LEN], gsy[GOP_MAX_LEN];
320	static int gslen, gdx, gdy, gax, gay, gscore, gbest, gpaused, gdead, gdir;
321	
322	/* ── Low-level fill rectangle via syscall ─────────────────────────────────── */
323	static void fill(uint32_t x, uint32_t y, uint32_t w, uint32_t h, uint32_t c) {
324	    syscall5(SYS_FB_FILLRECT, x, y, w, h, (uint64_t)c);
325	}
326	
327	/* ── Draw a single game cell ──────────────────────────────────────────────── */
328	static void gop_draw_cell(int cx, int cy, uint32_t color) {
329	    uint32_t px = G_bx + (uint32_t)cx * G_cell + 1;
330	    uint32_t py = G_by + (uint32_t)cy * G_cell + 1;
331	    fill(px, py, G_cell-2, G_cell-2, color);
332	}
333	
334	static void gop_erase_cell(int cx, int cy) {
335	    gop_draw_cell(cx, cy, COL_CELL_EMPTY);
336	}
337	
338	/* ── Draw the grid lines ──────────────────────────────────────────────────── */
339	static void gop_draw_grid(void) {
340	    for (int r=0; r<=G_rows; r++)
341	        fill(G_bx, G_by+(uint32_t)r*G_cell, G_bw, 1, S.grid);
342	    for (int c=0; c<=G_cols; c++)
343	        fill(G_bx+(uint32_t)c*G_cell, G_by, 1, G_bh, S.grid);
344	}
345	
346	/* ── Inline bitmap font renderer via SYS_PUTCELL ─────────────────────────── */
347	/* We re-use the kernel's char renderer for sidebar text — it's already routed
348	   through GOP. We compute the char column/row from pixel coords. */
349	static void gop_text(uint32_t px, uint32_t py, const char *s, uint8_t attr) {
350	    uint32_t col = px / 8;
351	    uint32_t row = py / 16;
352	    while (*s) {
353	        uint64_t packed = (uint64_t)(uint8_t)*s | ((uint64_t)attr << 8);
354	        syscall3(SYS_PUTCELL, (uint64_t)col++, (uint64_t)row, packed);
355	        s++;
356	    }
357	}
358	
359	/* Convenience: print integer at pixel position */
360	static void gop_text_int(uint32_t px, uint32_t py, int n, uint8_t attr) {
361	    char buf[12]; itoa_s(n, buf); gop_text(px, py, buf, attr);
362	}
