364	/* ── Sidebar ──────────────────────────────────────────────────────────────── */
365	static void gop_draw_sidebar(void) {
366	    fill(G_sbx, 0, G_fbw - G_sbx, G_fbh, S.sidebar);
367	
368	    uint32_t tx = G_sbx + 8;
369	    gop_text(tx, 20,  "SNAKE",         S.title_attr);
370	    gop_text(tx, 56,  "Score",         COL(C_WHITE, C_BLACK));
371	    gop_text(tx, 88,  "Best",          COL(C_WHITE, C_BLACK));
372	    gop_text_int(tx, 72, gscore,       S.score_attr);
373	    gop_text_int(tx, 104, gbest,       S.best_attr);
374	    gop_text(tx, 144, "WASD/arrows",   COL(C_LGREY, C_BLACK));
375	    gop_text(tx, 160, "P  pause",      COL(C_LGREY, C_BLACK));
376	    gop_text(tx, 176, "Q  quit",       COL(C_LGREY, C_BLACK));
377	    gop_text(tx, 192, "C  colors",     COL(C_LGREY, C_BLACK));
378	
379	    /* Scheme indicator dot */
380	    uint32_t dot_c = (g_scheme == 0) ? S.head : S.head;
381	    fill(G_sbx + 8, 216, 12, 12, dot_c);
382	    gop_text(tx + 16, 216,
383	             g_scheme == 0 ? "Green/Red" : "Blue/Purp",
384	             COL(C_LGREY, C_BLACK));
385	}
