387	static void gop_update_score(void) {
388	    uint32_t tx = G_sbx + 8;
389	    fill(tx, 72,  96, 16, S.sidebar);
390	    fill(tx, 104, 96, 16, S.sidebar);
391	    gop_text_int(tx, 72,  gscore, S.score_attr);
392	    gop_text_int(tx, 104, gbest,  S.best_attr);
393	}
