404	/* ── Border around board ──────────────────────────────────────────────────── */
405	static void gop_draw_border(void) {
406	    uint32_t t = 3;
407	    fill(G_bx-t, G_by-t, G_bw+2*t, t,      S.border);
408	    fill(G_bx-t, G_by+G_bh, G_bw+2*t, t,   S.border);
409	    fill(G_bx-t, G_by-t, t,      G_bh+2*t, S.border);
410	    fill(G_bx+G_bw, G_by-t, t,   G_bh+2*t, S.border);
411	}
