413	/* ── Apple ────────────────────────────────────────────────────────────────── */
414	static void gop_place_apple(void) {
415	    int max = G_cols * G_rows;
416	    for (int a=0; a<1000; a++) {
417	        int nx=(int)(rng_next()%(uint32_t)G_cols);
418	        int ny=(int)(rng_next()%(uint32_t)G_rows);
419	        int ok=1;
420	        for(int i=0;i<gslen;i++) if(gsx[i]==nx&&gsy[i]==ny){ok=0;break;}
421	        if(ok){gax=nx;gay=ny;return;}
422	        (void)max;
423	    }
424	}
