426	/* ── Snake render ─────────────────────────────────────────────────────────── */
427	static void gop_draw_snake(void) {
428	    gop_draw_cell(gsx[0], gsy[0], S.head);
429	    for(int i=1;i<gslen;i++) gop_draw_cell(gsx[i],gsy[i],S.body);
430	}
