432	/* ── Init ─────────────────────────────────────────────────────────────────── */
433	static void gop_game_init(void) {
434	    rng_state ^= (uint32_t)timer_ticks;
435	    gslen=5; gdx=1; gdy=0; gdir=DIR_RIGHT;
436	    gscore=0; gpaused=0; gdead=0;
437	    int hx=G_cols/2, hy=G_rows/2;
438	    for(int i=0;i<gslen;i++){gsx[i]=hx-i;gsy[i]=hy;}
439	    gop_place_apple();
440	}
