442	/* ── Game step ────────────────────────────────────────────────────────────── */
443	static void gop_step(void) {
444	    int nx=gsx[0]+gdx, ny=gsy[0]+gdy;
445	    if(nx<0||nx>=G_cols||ny<0||ny>=G_rows){gdead=1;return;}
446	    for(int i=0;i<gslen;i++) if(gsx[i]==nx&&gsy[i]==ny){gdead=1;return;}
447	    int ate=(nx==gax&&ny==gay);
448	    if(!ate) gop_erase_cell(gsx[gslen-1],gsy[gslen-1]);
449	    int nl=ate?gslen+1:gslen; if(nl>GOP_MAX_LEN)nl=GOP_MAX_LEN;
450	    for(int i=nl-1;i>0;i--){gsx[i]=gsx[i-1];gsy[i]=gsy[i-1];}
451	    gsx[0]=nx;gsy[0]=ny;gslen=nl;
452	    if(ate){gscore++;gop_update_score();gop_place_apple();
453	        gop_draw_cell(gax,gay,S.fruit);}
454	    gop_draw_snake();
455	}
