457	/* ── Overlay: centered message box ────────────────────────────────────────── */
458	static void gop_msg_box(const char *line1, const char *line2, const char *line3) {
459	    uint32_t bw=260, bh=80;
460	    uint32_t bx=(G_bx+G_bw/2)-bw/2, by=(G_by+G_bh/2)-bh/2;
461	    fill(bx-4,by-4,bw+8,bh+8, COL_BORDER);
462	    fill(bx,by,bw,bh, COL_BG);
463	    int cw1=strlen_s(line1), cw2=strlen_s(line2), cw3=strlen_s(line3);
464	    gop_text(bx+(bw-(uint32_t)cw1*8)/2, by+8,  line1, COL(C_LRED,   C_BLACK));
465	    gop_text(bx+(bw-(uint32_t)cw2*8)/2, by+30, line2, COL(C_YELLOW, C_BLACK));
466	    gop_text(bx+(bw-(uint32_t)cw3*8)/2, by+54, line3, COL(C_LGREY,  C_BLACK));
467	}
