469	/* ── Full repaint (scheme switch while paused) ────────────────────────────── */
470	static void gop_repaint_all(void) {
471	    fill(0, 0, G_fbw, G_fbh, S.bg);
472	    gop_draw_title();
473	    gop_draw_sidebar();
474	    gop_draw_border();
475	    fill(G_bx, G_by, G_bw, G_bh, S.bg);
476	    gop_draw_grid();
477	    gop_draw_cell(gax, gay, S.fruit);
478	    gop_draw_snake();
479	}
