481	/* ── Main GOP game loop ───────────────────────────────────────────────────── */
482	static void snake_gop(fb_info_t *fbi) {
483	    G_fbw = fbi->fb_width;
484	    G_fbh = fbi->fb_height;
485	
486	    /* Choose cell size so board fills ~85% of screen height */
487	    G_cell = 20;
488	    G_rows = (int)((G_fbh * 85 / 100) / G_cell);
489	    G_cols = G_rows * 3 / 2;          /* ~3:2 aspect */
490	    G_bw   = (uint32_t)G_cols * G_cell;
491	    G_bh   = (uint32_t)G_rows * G_cell;
492	
493	    /* Center board horizontally, leave room for sidebar on right */
494	    uint32_t sidebar_w = 160;
495	    G_sbx = G_fbw - sidebar_w;
496	    G_bx  = (G_sbx - G_bw) / 2;
497	    G_by  = (G_fbh - G_bh) / 2 + 8;
498	
499	    gbest = hs_load();
500	
501	    fill(0, 0, G_fbw, G_fbh, S.bg);
502	    gop_draw_title();
503	    gop_draw_sidebar();
504	    gop_draw_border();
505	    gop_draw_grid();
506	
507	    gop_game_init();
508	    gop_draw_cell(gax, gay, S.fruit);
509	    gop_draw_snake();
510	
511	    uint32_t last = (uint32_t)timer_ticks;
512	
513	    for(;;) {
514	        int k = (int)syscall0(SYS_GETKEY_NB);
515	        if (k >= 0) {
516	            if (k=='q'||k=='Q') { gdead=1; }
517	            else if (k=='c'||k=='C') {
518	                g_scheme = (g_scheme + 1) % NUM_SCHEMES;
519	                gop_repaint_all();
520	            } else if (k=='p'||k=='P') {
521	                gpaused ^= 1;
522	                if (gpaused)
523	                    gop_msg_box("  PAUSED  ", "P to resume", "C for colors");
524	                else {
525	                    fill(G_bx, G_by, G_bw, G_bh, S.bg);
526	                    gop_draw_grid();
527	                    gop_draw_cell(gax, gay, S.fruit);
528	                    gop_draw_snake();
529	                }
530	            } else {
531	                int nd = gdir;
532	                if((k=='w'||k=='W'||k==KEY_UP)   &&gdir!=DIR_DOWN) nd=DIR_UP;
533	                if((k=='s'||k=='S'||k==KEY_DOWN)  &&gdir!=DIR_UP)   nd=DIR_DOWN;
534	                if((k=='a'||k=='A'||k==KEY_LEFT)  &&gdir!=DIR_RIGHT)nd=DIR_LEFT;
535	                if((k=='d'||k=='D'||k==KEY_RIGHT) &&gdir!=DIR_LEFT) nd=DIR_RIGHT;
536	                if(nd!=gdir){gdir=nd;
537	                    if(gdir==DIR_UP){gdx=0;gdy=-1;}
538	                    else if(gdir==DIR_DOWN){gdx=0;gdy=1;}
539	                    else if(gdir==DIR_LEFT){gdx=-1;gdy=0;}
540	                    else{gdx=1;gdy=0;}
541	                }
542	            }
543	        }
544	        if (gdead) break;
545	        if (!gpaused) {
546	            uint32_t sp = 10;
547	            if(gscore>=15)sp=8; if(gscore>=30)sp=6; if(gscore>=50)sp=4;
548	            uint32_t now=(uint32_t)timer_ticks;
549	            if((uint32_t)(now-last)>=sp){last=now;gop_step();if(gdead)break;}
550	        }
551	        syscall0(SYS_YIELD);
552	    }
553	
554	    int nb=(gscore>gbest); if(nb){gbest=gscore;hs_save(gbest);}
555	
556	    char score_line[32];
557	    char best_line[32];
558	    /* build "Score: NN" */
559	    const char *sp="Score: "; int si=0;
560	    while(sp[si]) score_line[si]=sp[si++];
561	    char snum[12]; itoa_s(gscore,snum);
562	    int sni=0; while(snum[sni]) score_line[si++]=snum[sni++]; score_line[si]='\0';
563	
564	    if (nb) {
565	        const char *bp="New best!"; int bi=0;
566	        while(bp[bi]) best_line[bi]=bp[bi++]; best_line[bi]='\0';
567	    } else {
568	        const char *bp="Best: "; int bi=0;
569	        while(bp[bi]) best_line[bi]=bp[bi++];
570	        char bnum[12]; itoa_s(gbest,bnum);
571	        int bni=0; while(bnum[bni]) best_line[bi++]=bnum[bni++]; best_line[bi]='\0';
572	    }
573	
574	    gop_msg_box("GAME OVER", score_line, "Press any key");
575	    syscall0(SYS_GETKEY);
576	    fill(0, 0, G_fbw, G_fbh, S.bg);
577	}
578	
579	/* ════════════════════════════════════════════════════════════════════════════
580	 *  Entry point
581	 * ════════════════════════════════════════════════════════════════════════════*/
582	void snake_main(void) {
583	    fb_info_t fbi;
584	    syscall1(SYS_FB_INFO, (uint64_t)&fbi);
585	
586	    if (fbi.mode == 1)
587	        snake_gop(&fbi);
588	    else
589	        snake_vga();
590	}
