365	
366	static int64_t sys_fb_fillrect(uint64_t x, uint64_t y, uint64_t w,
367	                                uint64_t h, uint64_t rgb32) {
368	    extern bool gop_available;
369	    if (!gop_available) return ESYS_OK;   /* no-op on VGA text */
370	    gop_fill_rect((uint32_t)x, (uint32_t)y,
371	                  (uint32_t)w, (uint32_t)h, (uint32_t)rgb32);
372	    return ESYS_OK;
373	}
374	
375	/* SYS_PUTCELL: draw one character cell at (col, row) without moving the
376	 * global cursor.  packed = char | (attr << 8).  Works on both display paths. */
377	static int64_t sys_putcell(uint64_t col, uint64_t row, uint64_t packed) {
378	    char    ch   = (char)(packed & 0xFF);
379	    uint8_t attr = (uint8_t)((packed >> 8) & 0xFF);
380	
381	    /* Snapshot and restore every piece of mutable display state */
382	    size_t  sc = vga_col, sr = vga_row;
383	    uint8_t sa = vga_color;
384	
385	    vga_color = attr;
386	    /* Directly set position — bypass vga_goto's clamping side-effects */
387	    vga_col = (size_t)col;
388	    vga_row = (size_t)row;
389	
390	    /* Draw the character in-place via the path-aware renderer */
391	    extern bool gop_available;
392	    if (gop_available) {
393	        /* GOP: render glyph directly at pixel position, never advance cursor */
394	        extern void gop_draw_glyph(uint32_t px, uint32_t py,
395	                                   const uint8_t *bitmap, uint32_t rows,
396	                                   uint32_t fg, uint32_t bg);
397	        extern const uint8_t font8x16[256][16];
398	        extern gop_info_t gop_fb;
399	
400	        /* Translate VGA palette attr to 32-bit GOP colours */
401	        static const uint8_t pal[16][3] = {
402	            {0x00,0x00,0x00},{0x00,0x00,0xAA},{0x00,0xAA,0x00},{0x00,0xAA,0xAA},
403	            {0xAA,0x00,0x00},{0xAA,0x00,0xAA},{0xAA,0x55,0x00},{0xAA,0xAA,0xAA},
404	            {0x55,0x55,0x55},{0x55,0x55,0xFF},{0x55,0xFF,0x55},{0x55,0xFF,0xFF},
405	            {0xFF,0x55,0x55},{0xFF,0x55,0xFF},{0xFF,0xFF,0x55},{0xFF,0xFF,0xFF},
406	        };
407	        uint8_t fi = attr & 0x0F, bi = (attr >> 4) & 0x0F;
408	        uint32_t fg = ((uint32_t)pal[fi][0] << gop_fb.red_pos)
409	                    | ((uint32_t)pal[fi][1] << gop_fb.green_pos)
410	                    | ((uint32_t)pal[fi][2] << gop_fb.blue_pos);
411	        uint32_t bg = ((uint32_t)pal[bi][0] << gop_fb.red_pos)
412	                    | ((uint32_t)pal[bi][1] << gop_fb.green_pos)
413	                    | ((uint32_t)pal[bi][2] << gop_fb.blue_pos);
414	
415	        gop_draw_glyph((uint32_t)col * 8u, (uint32_t)row * 16u,
416	                       font8x16[(uint8_t)ch], 16, fg, bg);
417	    } else {
418	        /* VGA text mode: write directly to text RAM */
419	        volatile uint16_t *vram = (volatile uint16_t *)0xB8000;
420	        vram[row * 80 + col] = (uint16_t)(uint8_t)ch | ((uint16_t)attr << 8);
421	    }
422	
423	    vga_col   = sc;
424	    vga_row   = sr;
425	    vga_color = sa;
426	    return ESYS_OK;
427	}
428	
429	static int64_t sys_setcursor(uint64_t col, uint64_t row) {
430	    vga_goto(col, row);
431	    return ESYS_OK;
432	}
433	
434	/* SYS_PS: fill caller buf with proc_snap_t entries for all live processes */
435	static int64_t sys_ps(uint64_t buf_ptr, uint64_t max_entries) {
436	    if (!buf_ptr || max_entries == 0) return ESYS_BADARG;
437	    return (int64_t)proc_snapshot((proc_snap_t *)buf_ptr, (int)max_entries);
438	}
439	
440	/* ── Dispatch ─────────────────────────────────────────────────────────────── */
441	void syscall_dispatch(int_frame_t *frame) {
442	    uint64_t num  = frame->rax;
443	    uint64_t arg1 = frame->rdi;
444	    uint64_t arg2 = frame->rsi;
445	    uint64_t arg3 = frame->rdx;
446	    uint64_t arg4 = frame->rcx;
447	    uint64_t arg5 = frame->r8;
448	
449	    int64_t ret;
450	    switch (num) {
451	        /* I/O */
452	        case SYS_PRINT:     ret = sys_print(arg1, arg2);             break;
453	        case SYS_CLEAR:     ret = sys_clear();                        break;
454	        case SYS_NEWLINE:   ret = sys_newline();                      break;
455	        case SYS_READ_MEM:  ret = sys_read_mem(arg1);                 break;
456	        case SYS_CPU_MODEL: ret = sys_cpu_model(arg1, arg2);          break;
457	        case SYS_SHUTDOWN:  ret = sys_shutdown();                     break;
458	        case SYS_REBOOT:    ret = sys_reboot();                       break;
459	        case SYS_GETCHAR:   ret = sys_getchar();                      break;
460	        case SYS_GETKEY:    ret = sys_getkey();                       break;
461	        case SYS_CHDIR:     ret = sys_chdir(arg1);                    break;
462	        case SYS_GETCWD:    ret = sys_getcwd(arg1, arg2);             break;
463	        /* Process */
464	        case SYS_YIELD:     ret = sys_yield();                        break;
465	        case SYS_GETPID:    ret = sys_getpid();                       break;
466	        case SYS_SPAWN:     ret = sys_spawn(arg1, arg2, arg3);        break;
467	        case SYS_FORK:      ret = sys_fork();                         break;
468	        case SYS_EXIT:      ret = sys_exit(arg1);                     break;
469	        case SYS_KILL:      ret = sys_kill(arg1);                     break;
470	        case SYS_WAIT:      ret = sys_wait(arg1);                     break;
471	        case SYS_SLEEP:     ret = sys_sleep(arg1);                    break;
472	        case SYS_GETPNAME:  ret = sys_getpname(arg1, arg2, arg3);     break;
473	        /* JS */
474	        case SYS_JS_EXEC:        ret = sys_js_exec(arg1);              break;
475	        /* Time */
476	        case SYS_TIME:           ret = sys_time();                     break;
477	        case SYS_CLOCK_GETTIME:  ret = sys_clock_gettime(arg1, arg2);  break;
478	        /* Filesystem */
479	        case SYS_FS_OPEN:    ret = sys_fs_open(arg1, arg2, arg3);    break;
480	        case SYS_FS_CLOSE:   ret = sys_fs_close(arg1);               break;
481	        case SYS_FS_READ:    ret = sys_fs_read(arg1, arg2, arg3);    break;
482	        case SYS_FS_WRITE:   ret = sys_fs_write(arg1, arg2, arg3);   break;
483	        case SYS_FS_SEEK:    ret = sys_fs_seek(arg1, arg2, arg3);    break;
484	        case SYS_FS_STAT:    ret = sys_fs_stat(arg1, arg2);          break;
485	        case SYS_FS_FSTAT:   ret = sys_fs_fstat(arg1, arg2);         break;
486	        case SYS_FS_READDIR: ret = sys_fs_readdir(arg1, arg2, arg3); break;
487	        case SYS_FS_MKDIR:   ret = sys_fs_mkdir(arg1, arg2);         break;
488	        case SYS_FS_UNLINK:  ret = sys_fs_unlink(arg1);              break;
489	        case SYS_FS_CREAT:   ret = sys_fs_creat(arg1, arg2);         break;
490	        case SYS_PS:           ret = sys_ps(arg1, arg2);               break;
491	        case SYS_GETKEY_NB:    ret = (int64_t)keyboard_getkey_nonblock(); break;
492	        case SYS_DISPLAY_MODE: ret = sys_display_mode();                          break;
493	        case SYS_PUTCELL:      ret = sys_putcell(arg1, arg2, arg3);              break;
494	        case SYS_SETCURSOR:    ret = sys_setcursor(arg1, arg2);                  break;
495	        case SYS_FB_INFO:      ret = sys_fb_info(arg1);                          break;
496	        case SYS_FB_FILLRECT:  ret = sys_fb_fillrect(arg1, arg2, arg3, arg4, arg5); break;
497	        default:
498	            ret = ESYS_BADNUM;
499	            kprint("[SYSCALL] unknown #"); kprint_uint64(num); kprint("\n");
500	            break;
501	    }
502	
503	    frame->rax = (uint64_t)ret;
504	}
505	
506	/* ── IDT hook ─────────────────────────────────────────────────────────────── */
507	void syscall_init(void) {
508	    idt[0x80].type_attr = 0xAE;   /* present, DPL=1, 64-bit interrupt gate */
509	}
