#include <syscall.h>
#include <idt.h>
#include <vga.h>
#include <gop.h>
#include <process.h>
#include <sched.h>
#include <keyboard.h>
#include <js_runtime.h>
#include <timer.h>
#include <time.h>
#include <fs.h>
#include <libtranslateunix.h>
#include <stdint.h>
#include <stddef.h>
#include <string.h>

/* ── Port I/O helpers ─────────────────────────────────────────────────────── */
static inline void outw(uint16_t port, uint16_t val) {
    __asm__ volatile ("outw %0, %1" : : "a"(val), "Nd"(port));
}
static inline void outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}

/* ── I/O syscalls ─────────────────────────────────────────────────────────── */

static int64_t sys_print(uint64_t ptr, uint64_t len) {
    if (!ptr) return ESYS_BADARG;
    const char *s = (const char *)ptr;
    if (len == 0) {
        kprint(s);
    } else {
        for (uint64_t i = 0; i < len; i++)
            kprint_char(s[i]);
    }
    return ESYS_OK;
}

static int64_t sys_clear(void)   { vga_clear(); return ESYS_OK; }
static int64_t sys_newline(void) { kprint("\n"); return ESYS_OK; }

static int64_t sys_read_mem(uint64_t addr) {
    if (!addr) return ESYS_BADARG;
    return (int64_t)(*(volatile uint64_t *)addr);
}

static int64_t sys_cpu_model(uint64_t buf_ptr, uint64_t buf_size) {
    if (!buf_ptr || buf_size == 0) return ESYS_BADARG;
    /* Use the brand string cached at boot — no CPUID in interrupt context */
    extern char boot_cpu_brand[64];
    char *dst = (char *)buf_ptr;
    strncpy(dst, boot_cpu_brand, buf_size - 1);
    dst[buf_size - 1] = '\0';
    return ESYS_OK;
}

static int64_t sys_shutdown(void) {
    outw(0x604, 0x2000);
    outw(0xB004, 0x2000);
    for (;;) __asm__ volatile ("hlt");
    return ESYS_OK;
}

static int64_t sys_reboot(void) {
    uint8_t val;
    do { __asm__ volatile ("inb %1, %0" : "=a"(val) : "Nd"((uint16_t)0x64)); }
    while (val & 0x02);
    outb(0x64, 0xFE);
    for (;;) __asm__ volatile ("hlt");
    return ESYS_OK;
}

static int64_t sys_getchar(void) {
    return (int64_t)(uint8_t)keyboard_getchar();
}

static int64_t sys_getkey(void) {
    return (int64_t)keyboard_getkey();
}

/* ── CWD — kernel-global, shared across shell and JS ─────────────────────── */
char kernel_cwd[256] = "/";

static int64_t sys_chdir(uint64_t path_ptr) {
    if (!path_ptr) return -1;
    const char *path = (const char *)path_ptr;

    /* Validate: try to open as directory */
    int fd = vfs_open(path, O_RDONLY, 0);
    if (fd < 0) return -1;
    vfs_close(fd);

    /* Store the new cwd — simple strcpy with bounds */
    size_t i = 0;
    while (path[i] && i < sizeof(kernel_cwd) - 1) { kernel_cwd[i] = path[i]; i++; }
    kernel_cwd[i] = '\0';
    return 0;
}

static int64_t sys_getcwd(uint64_t buf_ptr, uint64_t size) {
    if (!buf_ptr || size == 0) return -1;
    char *dst = (char *)buf_ptr;
    size_t i = 0;
    while (kernel_cwd[i] && i < (size_t)size - 1) { dst[i] = kernel_cwd[i]; i++; }
    dst[i] = '\0';
    return 0;
}

static int64_t sys_js_exec(uint64_t src_ptr) {
    if (!src_ptr) return ESYS_BADARG;
    js_runtime_run((const char *)src_ptr);
    return ESYS_OK;
}

/* ── Time syscalls ────────────────────────────────────────────────────────── */

static int64_t sys_time(void) {
    return (int64_t)timer_seconds;
}

static int64_t sys_clock_gettime(uint64_t ts_ptr, uint64_t clk_id) {
    if (!ts_ptr) return ESYS_BADARG;
    (void)clk_id;
    struct timespec *ts = (struct timespec *)ts_ptr;
    timer_gettime((uint64_t *)&ts->tv_sec, &ts->tv_nsec);
    return ESYS_OK;
}

/* ── Process syscalls ─────────────────────────────────────────────────────── */

/* SYS_YIELD: voluntarily give up CPU, scheduler picks next process */
static int64_t sys_yield(void) {
    if (!current_proc) return ESYS_OK;
    process_t *next = sched_pick();
    if (next && next != current_proc)
        proc_switch(next);
    return ESYS_OK;
}

/* SYS_GETPID */
static int64_t sys_getpid(void) {
    return current_proc ? (int64_t)current_proc->pid : 0;
}

/*
 * SYS_SPAWN: rdi=entry_fn_ptr, rsi=name_ptr, rdx=priority
 * Creates and immediately enqueues a new Ring-1 process.
 * Returns new pid on success, negative on error.
 */
static int64_t sys_spawn(uint64_t entry, uint64_t name_ptr, uint64_t priority) {
    if (!entry) return ESYS_BADARG;
    const char *name = name_ptr ? (const char *)name_ptr : "proc";
    process_t *p = proc_create((void (*)(void))entry, name,
                                RING_SERVICE, SCHED_QUANTUM_BASE, (uint32_t)priority);
    if (!p) return ESYS_NOMEM;
    proc_wake(p);
    return (int64_t)p->pid;
}

/*
 * SYS_FORK: duplicate calling process.
 * Returns child pid to parent, 0 to child.
 */
static int64_t sys_fork(void) {
    if (!current_proc) return ESYS_BADARG;
    process_t *child = proc_fork(current_proc);
    if (!child) return ESYS_NOMEM;
    /* Child gets 0 in rax after iretq — set it in child's saved context */
    /* The saved rax sits in the int_frame_t on child's stack; we zero it
     * by adjusting the iretq frame that ctx_switch will restore.         */
    child->ctx.rip = current_proc->ctx.rip;
    proc_wake(child);
    return (int64_t)child->pid;   /* parent sees child pid */
}

/* SYS_EXIT: terminate calling process */
static int64_t sys_exit(uint64_t code) {
    (void)code;
    if (!current_proc) return ESYS_BADARG;
    proc_destroy(current_proc);
    /* Pick next runnable process */
    process_t *next = sched_pick();
    if (next) proc_switch(next);
    /* If no next process, idle */
    for (;;) __asm__ volatile ("hlt");
    return ESYS_OK;
}

/* SYS_KILL: destroy a process by pid */
static int64_t sys_kill(uint64_t pid) {
    if (!pid) return ESYS_BADARG;
    process_t *p = proc_by_pid((uint32_t)pid);
    if (!p) return ESYS_NOPROC;
    /* Cannot kill the idle kernel task (pid 0 guard above) */
    proc_destroy(p);
    return ESYS_OK;
}

/*
 * SYS_WAIT: busy-spin yielding until target pid exits.
 * A real implementation would block; for now we yield repeatedly.
 */
static int64_t sys_wait(uint64_t pid) {
    if (!pid) return ESYS_BADARG;
    while (proc_by_pid((uint32_t)pid) != NULL)
        sys_yield();
    return ESYS_OK;
}

/* SYS_SLEEP: yield for at least N scheduler ticks */
static int64_t sys_sleep(uint64_t ticks) {
    uint64_t wake = sched_ticks + ticks;
    while (sched_ticks < wake)
        sys_yield();
    return ESYS_OK;
}

/* SYS_GETPNAME: copy process name into buffer */
static int64_t sys_getpname(uint64_t pid, uint64_t buf_ptr, uint64_t buf_size) {
    if (!buf_ptr || buf_size == 0) return ESYS_BADARG;
    process_t *p = pid ? proc_by_pid((uint32_t)pid)
                       : current_proc;
    if (!p) return ESYS_NOPROC;
    strncpy((char *)buf_ptr, p->name, buf_size - 1);
    ((char *)buf_ptr)[buf_size - 1] = '\0';
    return ESYS_OK;
}

/* ── Filesystem syscalls ──────────────────────────────────────────────────── */

static int64_t sys_fs_open(uint64_t path_ptr, uint64_t flags, uint64_t mode) {
    if (!path_ptr) return -EINVAL;
    int fd = vfs_open((const char *)path_ptr, (int)flags, (uint16_t)mode);
    if (fd < 0) { fs_err_to_errno(fd); return -1; }
    return fd;
}

static int64_t sys_fs_close(uint64_t fd) {
    int r = vfs_close((int)fd);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return 0;
}

static int64_t sys_fs_read(uint64_t fd, uint64_t buf_ptr, uint64_t len) {
    if (!buf_ptr) return -EINVAL;
    int r = vfs_read((int)fd, (void *)buf_ptr, (size_t)len);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return r;
}

static int64_t sys_fs_write(uint64_t fd, uint64_t buf_ptr, uint64_t len) {
    if (!buf_ptr) return -EINVAL;
    int r = vfs_write((int)fd, (const void *)buf_ptr, (size_t)len);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return r;
}

static int64_t sys_fs_seek(uint64_t fd, uint64_t offset, uint64_t whence) {
    int r = vfs_seek((int)fd, (int32_t)offset, (int)whence);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return r;
}

static int64_t sys_fs_stat(uint64_t path_ptr, uint64_t stat_ptr) {
    if (!path_ptr || !stat_ptr) return -EINVAL;
    fs_stat_t fs;
    int r = vfs_stat((const char *)path_ptr, &fs);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    struct stat *st = (struct stat *)stat_ptr;
    st->st_dev   = 0;
    st->st_ino   = fs.st_ino;
    st->st_mode  = fs.st_mode;
    st->st_nlink = 1;
    st->st_uid   = 0; st->st_gid = 0; st->st_rdev = 0;
    st->st_size  = fs.st_size;
    st->st_atime = fs.st_ctime;
    st->st_mtime = fs.st_mtime;
    st->st_ctime = fs.st_ctime;
    return 0;
}

static int64_t sys_fs_fstat(uint64_t fd, uint64_t stat_ptr) {
    if (!stat_ptr) return -EINVAL;
    fs_stat_t fs;
    int r = vfs_fstat((int)fd, &fs);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    struct stat *st = (struct stat *)stat_ptr;
    st->st_dev   = 0;
    st->st_ino   = fs.st_ino;
    st->st_mode  = fs.st_mode;
    st->st_nlink = 1;
    st->st_uid   = 0; st->st_gid = 0; st->st_rdev = 0;
    st->st_size  = fs.st_size;
    st->st_atime = fs.st_ctime;
    st->st_mtime = fs.st_mtime;
    st->st_ctime = fs.st_ctime;
    return 0;
}

static int64_t sys_fs_readdir(uint64_t fd, uint64_t index, uint64_t dirent_ptr) {
    if (!dirent_ptr) return -EINVAL;
    fs_dirent_t fde;
    int r = vfs_readdir((int)fd, (uint32_t)index, &fde);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    struct dirent *de = (struct dirent *)dirent_ptr;
    de->d_ino = fde.inode;
    size_t n = strlen(fde.name);
    if (n > 255) n = 255;
    memcpy(de->d_name, fde.name, n);
    de->d_name[n] = '\0';
    return 0;
}

static int64_t sys_fs_mkdir(uint64_t path_ptr, uint64_t mode) {
    if (!path_ptr) return -EINVAL;
    int r = vfs_mkdir((const char *)path_ptr, (uint16_t)mode);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return 0;
}

static int64_t sys_fs_unlink(uint64_t path_ptr) {
    if (!path_ptr) return -EINVAL;
    int r = vfs_unlink((const char *)path_ptr);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return 0;
}

static int64_t sys_fs_creat(uint64_t path_ptr, uint64_t mode) {
    if (!path_ptr) return -EINVAL;
    int r = vfs_creat((const char *)path_ptr, (uint16_t)mode);
    if (r < 0) { fs_err_to_errno(r); return -1; }
    return r;
}

/* ── Display syscalls ─────────────────────────────────────────────────────── */

static int64_t sys_display_mode(void) {
    extern bool gop_available;
    return gop_available ? 1 : 0;
}

static int64_t sys_fb_info(uint64_t ptr) {
    if (!ptr) return ESYS_BADARG;
    fb_info_t *info = (fb_info_t *)ptr;
    extern bool gop_available;
    if (gop_available) {
        info->fb_width  = gop_fb.width;
        info->fb_height = gop_fb.height;
        info->cell_w    = 8;
        info->cell_h    = 16;
        info->char_cols = gop_fb.width  / 8;
        info->char_rows = gop_fb.height / 16;
        info->mode      = 1;
    } else {
        info->fb_width  = 0;
        info->fb_height = 0;
        info->cell_w    = 8;
        info->cell_h    = 16;
        info->char_cols = 80;
        info->char_rows = 25;
        info->mode      = 0;
    }
    return ESYS_OK;
}

static int64_t sys_fb_fillrect(uint64_t x, uint64_t y, uint64_t w,
                                uint64_t h, uint64_t rgb32) {
    extern bool gop_available;
    if (!gop_available) return ESYS_OK;   /* no-op on VGA text */
    gop_fill_rect((uint32_t)x, (uint32_t)y,
                  (uint32_t)w, (uint32_t)h, (uint32_t)rgb32);
    return ESYS_OK;
}

/* SYS_PUTCELL: draw one character cell at (col, row) without moving the
 * global cursor.  packed = char | (attr << 8).  Works on both display paths. */
static int64_t sys_putcell(uint64_t col, uint64_t row, uint64_t packed) {
    char    ch   = (char)(packed & 0xFF);
    uint8_t attr = (uint8_t)((packed >> 8) & 0xFF);

    /* Snapshot and restore every piece of mutable display state */
    size_t  sc = vga_col, sr = vga_row;
    uint8_t sa = vga_color;

    vga_color = attr;
    /* Directly set position — bypass vga_goto's clamping side-effects */
    vga_col = (size_t)col;
    vga_row = (size_t)row;

    /* Draw the character in-place via the path-aware renderer */
    extern bool gop_available;
    if (gop_available) {
        /* GOP: render glyph directly at pixel position, never advance cursor */
        extern void gop_draw_glyph(uint32_t px, uint32_t py,
                                   const uint8_t *bitmap, uint32_t rows,
                                   uint32_t fg, uint32_t bg);
        extern const uint8_t font8x16[256][16];
        extern gop_info_t gop_fb;

        /* Translate VGA palette attr to 32-bit GOP colours */
        static const uint8_t pal[16][3] = {
            {0x00,0x00,0x00},{0x00,0x00,0xAA},{0x00,0xAA,0x00},{0x00,0xAA,0xAA},
            {0xAA,0x00,0x00},{0xAA,0x00,0xAA},{0xAA,0x55,0x00},{0xAA,0xAA,0xAA},
            {0x55,0x55,0x55},{0x55,0x55,0xFF},{0x55,0xFF,0x55},{0x55,0xFF,0xFF},
            {0xFF,0x55,0x55},{0xFF,0x55,0xFF},{0xFF,0xFF,0x55},{0xFF,0xFF,0xFF},
        };
        uint8_t fi = attr & 0x0F, bi = (attr >> 4) & 0x0F;
        uint32_t fg = ((uint32_t)pal[fi][0] << gop_fb.red_pos)
                    | ((uint32_t)pal[fi][1] << gop_fb.green_pos)
                    | ((uint32_t)pal[fi][2] << gop_fb.blue_pos);
        uint32_t bg = ((uint32_t)pal[bi][0] << gop_fb.red_pos)
                    | ((uint32_t)pal[bi][1] << gop_fb.green_pos)
                    | ((uint32_t)pal[bi][2] << gop_fb.blue_pos);

        gop_draw_glyph((uint32_t)col * 8u, (uint32_t)row * 16u,
                       font8x16[(uint8_t)ch], 16, fg, bg);
    } else {
        /* VGA text mode: write directly to text RAM */
        volatile uint16_t *vram = (volatile uint16_t *)0xB8000;
        vram[row * 80 + col] = (uint16_t)(uint8_t)ch | ((uint16_t)attr << 8);
    }

    vga_col   = sc;
    vga_row   = sr;
    vga_color = sa;
    return ESYS_OK;
}

static int64_t sys_setcursor(uint64_t col, uint64_t row) {
    vga_goto(col, row);
    return ESYS_OK;
}

/* SYS_PS: fill caller buf with proc_snap_t entries for all live processes */
static int64_t sys_ps(uint64_t buf_ptr, uint64_t max_entries) {
    if (!buf_ptr || max_entries == 0) return ESYS_BADARG;
    return (int64_t)proc_snapshot((proc_snap_t *)buf_ptr, (int)max_entries);
}

/* ── Dispatch ─────────────────────────────────────────────────────────────── */
void syscall_dispatch(int_frame_t *frame) {
    uint64_t num  = frame->rax;
    uint64_t arg1 = frame->rdi;
    uint64_t arg2 = frame->rsi;
    uint64_t arg3 = frame->rdx;
    uint64_t arg4 = frame->rcx;
    uint64_t arg5 = frame->r8;

    int64_t ret;
    switch (num) {
        /* I/O */
        case SYS_PRINT:     ret = sys_print(arg1, arg2);             break;
        case SYS_CLEAR:     ret = sys_clear();                        break;
        case SYS_NEWLINE:   ret = sys_newline();                      break;
        case SYS_READ_MEM:  ret = sys_read_mem(arg1);                 break;
        case SYS_CPU_MODEL: ret = sys_cpu_model(arg1, arg2);          break;
        case SYS_SHUTDOWN:  ret = sys_shutdown();                     break;
        case SYS_REBOOT:    ret = sys_reboot();                       break;
        case SYS_GETCHAR:   ret = sys_getchar();                      break;
        case SYS_GETKEY:    ret = sys_getkey();                       break;
        case SYS_CHDIR:     ret = sys_chdir(arg1);                    break;
        case SYS_GETCWD:    ret = sys_getcwd(arg1, arg2);             break;
        /* Process */
        case SYS_YIELD:     ret = sys_yield();                        break;
        case SYS_GETPID:    ret = sys_getpid();                       break;
        case SYS_SPAWN:     ret = sys_spawn(arg1, arg2, arg3);        break;
        case SYS_FORK:      ret = sys_fork();                         break;
        case SYS_EXIT:      ret = sys_exit(arg1);                     break;
        case SYS_KILL:      ret = sys_kill(arg1);                     break;
        case SYS_WAIT:      ret = sys_wait(arg1);                     break;
        case SYS_SLEEP:     ret = sys_sleep(arg1);                    break;
        case SYS_GETPNAME:  ret = sys_getpname(arg1, arg2, arg3);     break;
        /* JS */
        case SYS_JS_EXEC:        ret = sys_js_exec(arg1);              break;
        /* Time */
        case SYS_TIME:           ret = sys_time();                     break;
        case SYS_CLOCK_GETTIME:  ret = sys_clock_gettime(arg1, arg2);  break;
        /* Filesystem */
        case SYS_FS_OPEN:    ret = sys_fs_open(arg1, arg2, arg3);    break;
        case SYS_FS_CLOSE:   ret = sys_fs_close(arg1);               break;
        case SYS_FS_READ:    ret = sys_fs_read(arg1, arg2, arg3);    break;
        case SYS_FS_WRITE:   ret = sys_fs_write(arg1, arg2, arg3);   break;
        case SYS_FS_SEEK:    ret = sys_fs_seek(arg1, arg2, arg3);    break;
        case SYS_FS_STAT:    ret = sys_fs_stat(arg1, arg2);          break;
        case SYS_FS_FSTAT:   ret = sys_fs_fstat(arg1, arg2);         break;
        case SYS_FS_READDIR: ret = sys_fs_readdir(arg1, arg2, arg3); break;
        case SYS_FS_MKDIR:   ret = sys_fs_mkdir(arg1, arg2);         break;
        case SYS_FS_UNLINK:  ret = sys_fs_unlink(arg1);              break;
        case SYS_FS_CREAT:   ret = sys_fs_creat(arg1, arg2);         break;
        case SYS_PS:           ret = sys_ps(arg1, arg2);               break;
        case SYS_GETKEY_NB:    ret = (int64_t)keyboard_getkey_nonblock(); break;
        case SYS_DISPLAY_MODE: ret = sys_display_mode();                          break;
        case SYS_PUTCELL:      ret = sys_putcell(arg1, arg2, arg3);              break;
        case SYS_SETCURSOR:    ret = sys_setcursor(arg1, arg2);                  break;
        case SYS_FB_INFO:      ret = sys_fb_info(arg1);                          break;
        case SYS_FB_FILLRECT:  ret = sys_fb_fillrect(arg1, arg2, arg3, arg4, arg5); break;
        default:
            ret = ESYS_BADNUM;
            kprint("[SYSCALL] unknown #"); kprint_uint64(num); kprint("\n");
            break;
    }

    frame->rax = (uint64_t)ret;
}

/* ── IDT hook ─────────────────────────────────────────────────────────────── */
void syscall_init(void) {
    idt[0x80].type_attr = 0xAE;   /* present, DPL=1, 64-bit interrupt gate */
}

