/* ── History ring ─────────────────────────────────────────────────────────── */
static char hist[HIST_MAX][INPUT_BUF_SIZE];
static int  hist_count = 0;
static int  hist_head  = 0;

static void hist_push(const char *s) {
    if (!s || !s[0]) return;
    if (hist_count > 0) {
        int prev = (hist_head - 1 + HIST_MAX) % HIST_MAX;
        const char *a = hist[prev], *b = s;
        while (*a && *a == *b) { a++; b++; }
        if (*a == '\0' && *b == '\0') return;   /* duplicate */
    }
    size_t i = 0;
    while (s[i] && i < INPUT_BUF_SIZE - 1) { hist[hist_head][i] = s[i]; i++; }
    hist[hist_head][i] = '\0';
    hist_head = (hist_head + 1) % HIST_MAX;
    if (hist_count < HIST_MAX) hist_count++;
}

static const char *hist_get(int offset) {
    if (offset <= 0 || offset > hist_count) return (const char *)0;
    int idx = (hist_head - offset + HIST_MAX * 2) % HIST_MAX;
    return hist[idx];
}

