/*
 * kernel/minit.c — miniature init (minit)
 *
 * minit is NephilimOS's lightweight process supervisor, launched by the kernel
 * before the shell. It is not monolithic — it has no service dependency graph,
 * no socket activation, and no unit files. Its only job is:
 *
 *   1. Keep a table of watched processes (entry function + name + PID).
 *   2. On each minit_tick(), detect processes that have died (PROC_UNUSED).
 *   3. Restart them up to MINIT_MAX_RETRY times.
 *   4. If retries are exhausted, log a warning and stop watching that entry.
 *
 * minit_tick() is called from kernel_main's idle loop, so it runs in Ring-0
 * context without any additional process overhead.
 */

#include <minit.h>
#include <process.h>
#include <vga.h>
#include <string.h>

/* ── Watch table entry ───────────────────────────────────────────────────── */
typedef struct {
    void       (*entry)(void);           /* re-spawn function pointer          */
    char         name[PROC_NAME_LEN];    /* display name                       */
    uint32_t     pid;                    /* PID of the currently-running child */
    uint8_t      retries;                /* restart attempts so far            */
    uint8_t      active;                 /* 1 = slot in use                    */
} watch_t;

static watch_t watch_table[MINIT_MAX_WATCH];
static int     watch_count = 0;

/* ── Helpers ─────────────────────────────────────────────────────────────── */

static void minit_log(const char *msg, const char *name) {
    kprint("[minit]   ");
    kprint(msg);
    if (name && name[0]) { kprint(" '"); kprint(name); kprint("'"); }
    kprint("\n");
}

/* ── Public API ──────────────────────────────────────────────────────────── */

void minit_init(void) {
    memset(watch_table, 0, sizeof(watch_table));
    watch_count = 0;
    kprint("[minit]   miniature init ready\n");
}

int minit_watch(void (*entry)(void), const char *name, process_t *p) {
    if (watch_count >= MINIT_MAX_WATCH) return -1;

    for (int i = 0; i < MINIT_MAX_WATCH; i++) {
        if (watch_table[i].active) continue;

        watch_table[i].entry   = entry;
        watch_table[i].pid     = p->pid;
        watch_table[i].retries = 0;
        watch_table[i].active  = 1;

        size_t n = 0;
        while (name[n] && n < PROC_NAME_LEN - 1) {
            watch_table[i].name[n] = name[n]; n++;
        }
        watch_table[i].name[n] = '\0';

        watch_count++;
        return 0;
    }
    return -1;
}

void minit_tick(void) {
    for (int i = 0; i < MINIT_MAX_WATCH; i++) {
        watch_t *w = &watch_table[i];
        if (!w->active) continue;

        /* Check if the watched process is still alive */
        process_t *p = proc_by_pid(w->pid);
        if (p && p->state != PROC_UNUSED && p->state != PROC_ZOMBIE) {
            continue;   /* still running — nothing to do */
        }

        /* Process has died */
        if (w->retries >= MINIT_MAX_RETRY) {
            minit_log("giving up on", w->name);
            memset(w, 0, sizeof(watch_t));
            watch_count--;
            continue;
        }

        w->retries++;
        kprint("[minit]   restarting '");
        kprint(w->name);
        kprint("' (attempt ");
        /* print digit inline — no printf available here */
        char retry_ch[2] = { '0' + w->retries, '\0' };
        kprint(retry_ch);
        kprint("/");
        char max_ch[2]   = { '0' + MINIT_MAX_RETRY, '\0' };
        kprint(max_ch);
        kprint(")\n");

        process_t *np = proc_create(w->entry, w->name,
                                    RING_SERVICE, SCHED_QUANTUM_BASE, 0);
        if (!np) {
            minit_log("proc_create failed for", w->name);
            /* Count this as a failed attempt; will retry next tick */
            continue;
        }

        w->pid = np->pid;
        proc_wake(np);
    }
}

#ifndef _MINIT_H
#define _MINIT_H

#include <process.h>

#define MINIT_MAX_WATCH  16   /* max processes minit can supervise             */
#define MINIT_MAX_RETRY   3   /* restart attempts before giving up             */

/* Register a process to be supervised by minit.
 * entry    — function pointer used to re-spawn on failure
 * name     — human-readable name (for log messages)
 * p        — already-created process_t (minit records its initial PID)
 *
 * Returns 0 on success, -1 if the watch table is full. */
int minit_watch(void (*entry)(void), const char *name, process_t *p);

/* Called from the kernel idle loop on every tick.
 * Checks each watched process; restarts dead ones up to MINIT_MAX_RETRY times.
 * When retries are exhausted the entry is removed and a warning is printed. */
void minit_tick(void);

/* One-time init — clears the watch table. */
void minit_init(void);

#endif /* _MINIT_H */

