#include <timer.h>
#include <idt.h>
#include <stdint.h>

/* ── PIT port definitions ──────────────────────────────────────────────────── */
#define PIT_CHANNEL0   0x40
#define PIT_COMMAND    0x43
#define PIT_CMD_LOBYTE_HIBYTE  0x36   /* channel 0, lobyte/hibyte, mode 3 */

/* 8259 PIC ports */
#define PIC1_CMD   0x20
#define PIC1_DATA  0x21
#define PIC2_CMD   0xA0
#define PIC2_DATA  0xA1
#define PIC_EOI    0x20

/* PIT base frequency */
#define PIT_BASE_HZ  1193182UL

/* ── State ─────────────────────────────────────────────────────────────────── */
volatile uint64_t timer_ticks   = 0;
volatile uint64_t timer_seconds = 0;
volatile uint32_t timer_ms      = 0;

/* ── Port helpers ──────────────────────────────────────────────────────────── */
static inline void outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}
static inline uint8_t inb(uint16_t port) {
    uint8_t val;
    __asm__ volatile ("inb %1, %0" : "=a"(val) : "Nd"(port));
    return val;
}

/* ── PIC remapping ─────────────────────────────────────────────────────────── */
static void pic_remap(void) {
    /* Save masks */
    uint8_t m1 = inb(PIC1_DATA);
    uint8_t m2 = inb(PIC2_DATA);

    /* ICW1: start init, ICW4 needed */
    outb(PIC1_CMD,  0x11);
    outb(PIC2_CMD,  0x11);
    /* ICW2: vector offsets — IRQ0–7 → vectors 32–39, IRQ8–15 → 40–47 */
    outb(PIC1_DATA, 0x20);
    outb(PIC2_DATA, 0x28);
    /* ICW3: cascade */
    outb(PIC1_DATA, 0x04);
    outb(PIC2_DATA, 0x02);
    /* ICW4: 8086 mode */
    outb(PIC1_DATA, 0x01);
    outb(PIC2_DATA, 0x01);

    /* Restore masks */
    outb(PIC1_DATA, m1);
    outb(PIC2_DATA, m2);
}

/* ── IRQ0 handler (called from int_handler via vector 32) ─────────────────── */
void timer_irq_handler(void) {
    timer_ticks++;
    timer_ms = (uint32_t)((timer_ticks % TIMER_HZ) * 1000 / TIMER_HZ);
    if (timer_ticks % TIMER_HZ == 0)
        timer_seconds++;

    /* EOI is sent by the central IRQ handler in idt.c */
}

/* ── Init ──────────────────────────────────────────────────────────────────── */
void timer_init(void) {
    pic_remap();

    /* Program PIT channel 0 at TIMER_HZ */
    uint32_t divisor = PIT_BASE_HZ / TIMER_HZ;
    outb(PIT_COMMAND, PIT_CMD_LOBYTE_HIBYTE);
    outb(PIT_CHANNEL0, (uint8_t)(divisor & 0xFF));
    outb(PIT_CHANNEL0, (uint8_t)((divisor >> 8) & 0xFF));

    /* Unmask IRQ0 only */
    uint8_t mask = inb(PIC1_DATA);
    mask &= ~(1 << 0);
    outb(PIC1_DATA, mask);
}

/* ── Query ─────────────────────────────────────────────────────────────────── */
void timer_gettime(uint64_t *sec_out, uint32_t *nsec_out) {
    /* Read atomically by sampling twice until consistent */
    uint64_t s1, s2;
    uint32_t ms;
    do {
        s1 = timer_seconds;
        ms = timer_ms;
        s2 = timer_seconds;
    } while (s1 != s2);

    *sec_out  = s1;
    *nsec_out = ms * 1000000U;
}

