#ifndef _VOICEBOX_H
#define _VOICEBOX_H

#include <stdint.h>
#include <stdbool.h>

/* ── Audio backend IDs ────────────────────────────────────────────────────────
 *
 * Priority order during probe:
 *   SB16  — Sound Blaster 16 (ISA, I/O 0x220, IRQ 5, DMA 1/5)
 *   AC97  — Intel AC'97 controller (PCI device 0x8086:0x2415)
 *   ISA   — PC speaker via PIT channel 2 (always available, no hardware needed)
 *   HDA   — Intel HD Audio (PCI device 0x8086:0x2668, experimental stub)
 *   NONE  — no audio hardware found or all probes failed
 */
typedef enum {
    VB_BACKEND_NONE = 0,
    VB_BACKEND_ISA,
    VB_BACKEND_SB16,
    VB_BACKEND_AC97,
    VB_BACKEND_HDA,
} vb_backend_t;

/* ── VoiceBox public API ──────────────────────────────────────────────────── */

/* Probe available audio hardware and activate the best backend.
 * Called once at boot by voicebox_main / kernel init. */
void vb_init(void);

/* Play a square-wave tone at freq_hz for duration_ms milliseconds.
 * Blocks the caller for the duration (busy-waits on timer_ticks).
 * freq_hz == 0 → silence for duration_ms (useful for note spacing).
 * Safe to call from kernel or Ring-1 userland via SYS_BEEP. */
void vb_beep(uint32_t freq_hz, uint32_t duration_ms);

/* Stop any ongoing tone immediately (e.g. on shutdown). */
void vb_stop(void);

/* Return the active backend. */
vb_backend_t vb_active_backend(void);

/* Human-readable name of the active backend. */
const char *vb_backend_name(void);

/* minit entry point — probes hardware, logs result, then idles. */
void voicebox_main(void);

#endif /* _VOICEBOX_H */

