/*
 * drivers/voicebox.c — VoiceBox audio driver
 *
 * Probes for audio hardware in priority order and exposes a unified
 * vb_beep(freq_hz, duration_ms) API to the rest of the kernel.
 *
 * Backend priority (highest first):
 *   SB16  — Sound Blaster 16 (ISA, base I/O 0x220)
 *   AC97  — Intel AC'97 codec (PCI 0x8086:0x2415, I/O via PCI BAR)
 *   ISA   — PC speaker via PIT channel 2 + port 0x61 (always works)
 *   HDA   — Intel HD Audio (PCI 0x8086:0x2668, experimental — probe only)
 *
 * The ISA speaker backend never fails — it is the final fallback.
 * All four probe functions are always called in order so the log shows
 * exactly what hardware was found.
 */

#include <voicebox.h>
#include <timer.h>
#include <vga.h>
#include <stdint.h>
#include <stdbool.h>

/* ── PIT base frequency ───────────────────────────────────────────────────── */
#define PIT_BASE_HZ  1193182UL

/* ── Port I/O helpers (local — not shared with timer.c) ───────────────────── */
static inline void vb_outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}
static inline void vb_outw(uint16_t port, uint16_t val) {
    __asm__ volatile ("outw %0, %1" : : "a"(val), "Nd"(port));
}
static inline uint8_t vb_inb(uint16_t port) {
    uint8_t v;
    __asm__ volatile ("inb %1, %0" : "=a"(v) : "Nd"(port));
    return v;
}
static inline uint16_t vb_inw(uint16_t port) {
    uint16_t v;
    __asm__ volatile ("inw %1, %0" : "=a"(v) : "Nd"(port));
    return v;
}

/* Short I/O delay — one dummy read from a safe port */
static inline void vb_iodelay(void) { vb_inb(0x80); }

/* ── PCI config access (type-1, port CF8/CFC) ─────────────────────────────── */
static inline uint32_t pci_read32(uint8_t bus, uint8_t dev,
                                   uint8_t fn,  uint8_t reg) {
    uint32_t addr = 0x80000000u
                  | ((uint32_t)bus << 16)
                  | ((uint32_t)dev << 11)
                  | ((uint32_t)fn  <<  8)
                  | (reg & 0xFC);
    __asm__ volatile ("outl %0, $0xCF8" : : "a"(addr));
    uint32_t val;
    __asm__ volatile ("inl $0xCFC, %0" : "=a"(val));
    return val;
}

/* Scan PCI bus 0–7 for a device matching vendor:device.
 * Returns bus<<8|dev<<3|fn encoded in a uint32_t, or 0xFFFFFFFF if not found. */
static uint32_t pci_find(uint16_t vendor, uint16_t device) {
    for (uint8_t bus = 0; bus < 8; bus++) {
        for (uint8_t dev = 0; dev < 32; dev++) {
            for (uint8_t fn = 0; fn < 8; fn++) {
                uint32_t id = pci_read32(bus, dev, fn, 0x00);
                if (id == 0xFFFFFFFF || id == 0x00000000) continue;
                if ((uint16_t)(id & 0xFFFF)       == vendor &&
                    (uint16_t)((id >> 16) & 0xFFFF) == device)
                    return ((uint32_t)bus << 16) | ((uint32_t)dev << 8) | fn;
            }
        }
    }
    return 0xFFFFFFFF;
}

/* Read I/O BAR from a PCI device (BAR0 or BAR1).
 * Returns base I/O address (low bit cleared), or 0 if not an I/O BAR. */
static uint16_t pci_io_bar(uint32_t bdf, uint8_t bar_idx) {
    uint8_t bus = (uint8_t)((bdf >> 16) & 0xFF);
    uint8_t dev = (uint8_t)((bdf >>  8) & 0xFF);
    uint8_t fn  = (uint8_t)( bdf        & 0xFF);
    uint32_t bar = pci_read32(bus, dev, fn, 0x10 + bar_idx * 4);
    if (!(bar & 1)) return 0;          /* memory BAR, not I/O */
    return (uint16_t)(bar & 0xFFFC);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  Backend state
 * ════════════════════════════════════════════════════════════════════════════*/

static vb_backend_t g_backend = VB_BACKEND_NONE;

/* SB16 base I/O (default 0x220, could be 0x240/0x260/0x280) */
static uint16_t g_sb16_base = 0;

/* AC97: two I/O base addresses from PCI BARs */
static uint16_t g_ac97_nam  = 0;   /* Native Audio Mixer (BAR0) */
static uint16_t g_ac97_nabm = 0;   /* Native Audio Bus Master (BAR1) */

/* HDA: MMIO base (we only probe, never actually DMA on this path) */
static uint32_t g_hda_found = 0xFFFFFFFF;

/* ════════════════════════════════════════════════════════════════════════════
 *  ISA speaker backend  (PIT channel 2 + port 0x61)
 * ════════════════════════════════════════════════════════════════════════════*/

static void isa_tone_start(uint32_t freq_hz) {
    if (freq_hz == 0) {
        /* Silence: gate off */
        vb_outb(0x61, vb_inb(0x61) & 0xFC);
        return;
    }
    uint32_t div = (uint32_t)(PIT_BASE_HZ / freq_hz);
    if (div == 0) div = 1;
    /* Program PIT channel 2, mode 3 (square wave), lobyte/hibyte */
    vb_outb(0x43, 0xB6);
    vb_outb(0x42, (uint8_t)(div & 0xFF));
    vb_outb(0x42, (uint8_t)((div >> 8) & 0xFF));
    /* Enable speaker gate (bits 0 and 1 of port 0x61) */
    vb_outb(0x61, vb_inb(0x61) | 0x03);
}

static void isa_tone_stop(void) {
    vb_outb(0x61, vb_inb(0x61) & 0xFC);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  SB16 backend  (ISA Plug-and-Play, fixed at 0x220 by default)
 * ════════════════════════════════════════════════════════════════════════════
 *
 * We use the DSP "speaker" command path for simple square-wave beeps.
 * Full PCM DMA playback requires additional setup and is not implemented here.
 * For the purposes of vb_beep(), SB16 also falls through to the ISA speaker
 * for tone generation — the difference is that SB16 presence is detected and
 * logged, giving userland a better story ("SB16 detected") while still
 * producing audio through the PC speaker gate.
 *
 * A proper PCM path can be added later once DMA and IRQ handlers are wired up.
 */

#define SB16_RESET      0x06   /* offset from base: DSP reset port */
#define SB16_READ       0x0A   /* DSP read data */
#define SB16_WRITE      0x0C   /* DSP write command/data */
#define SB16_READ_STAT  0x0E   /* DSP read buffer status */

static bool sb16_write_dsp(uint16_t base, uint8_t cmd) {
    for (int i = 0; i < 128; i++) {
        if (!(vb_inb(base + SB16_WRITE) & 0x80)) {
            vb_outb(base + SB16_WRITE, cmd);
            return true;
        }
        vb_iodelay();
    }
    return false;
}

static int sb16_read_dsp(uint16_t base) {
    for (int i = 0; i < 128; i++) {
        if (vb_inb(base + SB16_READ_STAT) & 0x80)
            return (int)vb_inb(base + SB16_READ);
        vb_iodelay();
    }
    return -1;
}

static bool sb16_probe(uint16_t base) {
    /* Reset DSP: write 1, wait, write 0 */
    vb_outb(base + SB16_RESET, 1);
    for (int i = 0; i < 8; i++) vb_iodelay();
    vb_outb(base + SB16_RESET, 0);
    for (int i = 0; i < 32; i++) vb_iodelay();
    /* Card responds with 0xAA */
    int r = sb16_read_dsp(base);
    if (r != 0xAA) return false;
    /* Get DSP version — version ≥ 4.x is SB16 */
    if (!sb16_write_dsp(base, 0xE1)) return false;
    int major = sb16_read_dsp(base);
    int minor = sb16_read_dsp(base);
    (void)minor;
    return (major >= 4);
}

static bool sb16_try_probe(void) {
    static const uint16_t bases[] = { 0x220, 0x240, 0x260, 0x280 };
    for (int i = 0; i < 4; i++) {
        if (sb16_probe(bases[i])) {
            g_sb16_base = bases[i];
            return true;
        }
    }
    return false;
}

/* SB16 speaker enable/disable */
static void sb16_speaker_on(void)  { sb16_write_dsp(g_sb16_base, 0xD1); }
static void sb16_speaker_off(void) { sb16_write_dsp(g_sb16_base, 0xD3); }

/* ════════════════════════════════════════════════════════════════════════════
 *  AC97 backend  (PCI Intel 82801AA / PIIX4 AC97)
 * ════════════════════════════════════════════════════════════════════════════
 *
 * AC97 has no hardware tone generator — it is a full PCM mixer.
 * For vb_beep() we initialise the codec and fall back to ISA speaker for
 * actual tone output.  The key value is detecting AC97 and bringing the
 * codec out of reset so userland can later build a PCM path on top.
 */

/* AC97 mixer register offsets */
#define AC97_RESET          0x00
#define AC97_MASTER_VOL     0x02
#define AC97_MONO_VOL       0x06
#define AC97_PCM_VOL        0x18
#define AC97_POWERDOWN      0x26

/* NABM: bus-master control */
#define NABM_PCM_OUT_CR     0x1B   /* PCM out control byte */
#define NABM_GLOB_CTRL      0x2C   /* global control */
#define NABM_GLOB_STA       0x30   /* global status */

static bool ac97_probe(void) {
    /* Try known vendor:device combos */
    static const uint32_t ids[][2] = {
        { 0x8086, 0x2415 },   /* Intel 82801AA (ICH)  */
        { 0x8086, 0x2425 },   /* Intel 82801AB (ICH0) */
        { 0x8086, 0x2445 },   /* Intel 82801BA (ICH2) */
        { 0x8086, 0x2485 },   /* Intel ICH3           */
        { 0x8086, 0x24C5 },   /* Intel ICH4           */
        { 0x1022, 0x7445 },   /* AMD AC97             */
    };
    for (int i = 0; i < 6; i++) {
        uint32_t bdf = pci_find((uint16_t)ids[i][0], (uint16_t)ids[i][1]);
        if (bdf == 0xFFFFFFFF) continue;
        g_ac97_nam  = pci_io_bar(bdf, 0);
        g_ac97_nabm = pci_io_bar(bdf, 1);
        if (!g_ac97_nam || !g_ac97_nabm) continue;
        /* Cold reset codec */
        vb_outw(g_ac97_nam + AC97_RESET, 0x0000);
        vb_iodelay(); vb_iodelay();
        /* Set master volume to max (unmuted) */
        vb_outw(g_ac97_nam + AC97_MASTER_VOL, 0x0000);
        vb_outw(g_ac97_nam + AC97_PCM_VOL,    0x0000);
        return true;
    }
    return false;
}

/* ════════════════════════════════════════════════════════════════════════════
 *  HDA backend  (Intel HD Audio — probe only, no playback)
 * ════════════════════════════════════════════════════════════════════════════
 *
 * HDA requires MMIO, codec verb communication, stream descriptors, and DMA.
 * This backend only detects the PCI device and records it.  A full HDA driver
 * is experimental and out of scope for the initial VoiceBox release.
 */

static bool hda_probe(void) {
    static const uint32_t ids[][2] = {
        { 0x8086, 0x2668 },   /* Intel ICH6 HDA        */
        { 0x8086, 0x27D8 },   /* Intel ICH7 HDA        */
        { 0x8086, 0x293E },   /* Intel ICH9 HDA        */
        { 0x8086, 0x3B56 },   /* Intel 5 Series HDA    */
        { 0x8086, 0x1C20 },   /* Intel 6 Series HDA    */
        { 0x8086, 0x1E20 },   /* Intel 7 Series HDA    */
        { 0x8086, 0x8C20 },   /* Intel 8 Series HDA    */
        { 0x1002, 0x4383 },   /* AMD/ATI HDA           */
        { 0x10DE, 0x0E0F },   /* NVIDIA HDA            */
    };
    for (int i = 0; i < 9; i++) {
        uint32_t bdf = pci_find((uint16_t)ids[i][0], (uint16_t)ids[i][1]);
        if (bdf != 0xFFFFFFFF) {
            g_hda_found = bdf;
            return true;
        }
    }
    return false;
}

/* ════════════════════════════════════════════════════════════════════════════
 *  Unified tone API
 * ════════════════════════════════════════════════════════════════════════════*/

/* Busy-wait for ms milliseconds using timer_ticks */
static void vb_wait_ms(uint32_t ms) {
    if (!ms) return;
    uint64_t ticks_needed = ((uint64_t)ms * TIMER_HZ + 999) / 1000;
    uint64_t start = timer_ticks;
    while ((timer_ticks - start) < ticks_needed)
        __asm__ volatile ("pause");
}

void vb_stop(void) {
    switch (g_backend) {
        case VB_BACKEND_SB16:
            sb16_speaker_off();
            isa_tone_stop();
            break;
        case VB_BACKEND_AC97:
        case VB_BACKEND_HDA:
        case VB_BACKEND_ISA:
        default:
            isa_tone_stop();
            break;
    }
}

void vb_beep(uint32_t freq_hz, uint32_t duration_ms) {
    if (g_backend == VB_BACKEND_NONE) return;

    switch (g_backend) {
        case VB_BACKEND_SB16:
            sb16_speaker_on();
            isa_tone_start(freq_hz);
            vb_wait_ms(duration_ms);
            isa_tone_stop();
            sb16_speaker_off();
            break;

        case VB_BACKEND_AC97:
        case VB_BACKEND_HDA:
            /* No hardware tone generator — fall through to ISA speaker */
        case VB_BACKEND_ISA:
        default:
            isa_tone_start(freq_hz);
            vb_wait_ms(duration_ms);
            isa_tone_stop();
            break;
    }
}

vb_backend_t vb_active_backend(void) { return g_backend; }

const char *vb_backend_name(void) {
    switch (g_backend) {
        case VB_BACKEND_SB16: return "SB16";
        case VB_BACKEND_AC97: return "AC97";
        case VB_BACKEND_HDA:  return "HDA (stub)";
        case VB_BACKEND_ISA:  return "ISA speaker";
        default:              return "none";
    }
}

/* ════════════════════════════════════════════════════════════════════════════
 *  Probe + init
 * ════════════════════════════════════════════════════════════════════════════*/

void vb_init(void) {
    kprint("[VoiceBox] probing audio hardware...\n");

    /* SB16 — highest priority */
    if (sb16_try_probe()) {
        g_backend = VB_BACKEND_SB16;
        kprint("[VoiceBox] SB16 detected at I/O 0x");
        kprint_hex(g_sb16_base);
        kprint(" (primary)\n");
    } else {
        kprint("[VoiceBox] SB16 not found\n");
    }

    /* AC97 — secondary */
    if (ac97_probe()) {
        if (g_backend == VB_BACKEND_NONE)
            g_backend = VB_BACKEND_AC97;
        kprint("[VoiceBox] AC97 codec detected");
        if (g_ac97_nam) {
            kprint(" NAM=0x"); kprint_hex(g_ac97_nam);
            kprint(" NABM=0x"); kprint_hex(g_ac97_nabm);
        }
        kprint(g_backend == VB_BACKEND_AC97 ? " (primary)\n" : " (secondary)\n");
    } else {
        kprint("[VoiceBox] AC97 not found\n");
    }

    /* HDA — experimental, probe-only */
    if (hda_probe()) {
        kprint("[VoiceBox] HDA detected (experimental, no playback)\n");
        if (g_backend == VB_BACKEND_NONE)
            g_backend = VB_BACKEND_HDA;
    } else {
        kprint("[VoiceBox] HDA not found\n");
    }

    /* ISA speaker — always the final fallback */
    if (g_backend == VB_BACKEND_NONE)
        g_backend = VB_BACKEND_ISA;

    kprint("[VoiceBox] active backend: ");
    kprint(vb_backend_name());
    kprint("\n");

    /* Boot chime: two short tones */
    vb_beep(880, 60);
    vb_wait_ms(30);
    vb_beep(1320, 80);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  minit entry point
 * ════════════════════════════════════════════════════════════════════════════*/

void voicebox_main(void) {
    vb_init();
    /* VoiceBox is a pure driver — after init it idles forever.
     * minit will restart it if it somehow exits. */
    for (;;) __asm__ volatile ("hlt");
}

