/*
 * drivers/voicebox.c — VoiceBox audio driver
 *
 * Probes for audio hardware in priority order and exposes a unified
 * vb_beep(freq_hz, duration_ms) API to the rest of the kernel.
 *
 * Backend priority (highest first):
 *   SB16  — Sound Blaster 16 (ISA, base I/O 0x220)
 *   AC97  — Intel AC'97 codec (PCI 0x8086:0x2415, I/O via PCI BAR)
 *   ISA   — PC speaker via PIT channel 2 + port 0x61 (always works)
 *   HDA   — Intel HD Audio (PCI 0x8086:0x2668, experimental — probe only)
 *
 * The ISA speaker backend never fails — it is the final fallback.
 * All four probe functions are always called in order so the log shows
 * exactly what hardware was found.
 */

#include <voicebox.h>
#include <timer.h>
#include <vga.h>
#include <stdint.h>
#include <stdbool.h>

/* ── PIT base frequency ───────────────────────────────────────────────────── */
#define PIT_BASE_HZ  1193182UL

/* ── Port I/O helpers (local — not shared with timer.c) ───────────────────── */
static inline void vb_outb(uint16_t port, uint8_t val) {
    __asm__ volatile ("outb %0, %1" : : "a"(val), "Nd"(port));
}
static inline void vb_outw(uint16_t port, uint16_t val) {
    __asm__ volatile ("outw %0, %1" : : "a"(val), "Nd"(port));
}
static inline uint8_t vb_inb(uint16_t port) {
    uint8_t v;
    __asm__ volatile ("inb %1, %0" : "=a"(v) : "Nd"(port));
    return v;
}
static inline uint16_t vb_inw(uint16_t port) {
    uint16_t v;
    __asm__ volatile ("inw %1, %0" : "=a"(v) : "Nd"(port));
    return v;
}

/* Short I/O delay — one dummy read from a safe port */
static inline void vb_iodelay(void) { vb_inb(0x80); }

/* ── PCI config access (type-1, port CF8/CFC) ─────────────────────────────── */
static inline uint32_t pci_read32(uint8_t bus, uint8_t dev,
                                   uint8_t fn,  uint8_t reg) {
    uint32_t addr = 0x80000000u
                  | ((uint32_t)bus << 16)
                  | ((uint32_t)dev << 11)
                  | ((uint32_t)fn  <<  8)
                  | (reg & 0xFC);
    __asm__ volatile ("outl %0, $0xCF8" : : "a"(addr));
    uint32_t val;
    __asm__ volatile ("inl $0xCFC, %0" : "=a"(val));
    return val;
}

/* Scan PCI bus 0–7 for a device matching vendor:device.
 * Returns bus<<8|dev<<3|fn encoded in a uint32_t, or 0xFFFFFFFF if not found. */
static uint32_t pci_find(uint16_t vendor, uint16_t device) {
    for (uint8_t bus = 0; bus < 8; bus++) {
        for (uint8_t dev = 0; dev < 32; dev++) {
            for (uint8_t fn = 0; fn < 8; fn++) {
                uint32_t id = pci_read32(bus, dev, fn, 0x00);
                if (id == 0xFFFFFFFF || id == 0x00000000) continue;
                if ((uint16_t)(id & 0xFFFF)       == vendor &&
                    (uint16_t)((id >> 16) & 0xFFFF) == device)
                    return ((uint32_t)bus << 16) | ((uint32_t)dev << 8) | fn;
            }
        }
    }
    return 0xFFFFFFFF;
}

/* Read I/O BAR from a PCI device (BAR0 or BAR1).
 * Returns base I/O address (low bit cleared), or 0 if not an I/O BAR. */
static uint16_t pci_io_bar(uint32_t bdf, uint8_t bar_idx) {
    uint8_t bus = (uint8_t)((bdf >> 16) & 0xFF);
    uint8_t dev = (uint8_t)((bdf >>  8) & 0xFF);
    uint8_t fn  = (uint8_t)( bdf        & 0xFF);
    uint32_t bar = pci_read32(bus, dev, fn, 0x10 + bar_idx * 4);
    if (!(bar & 1)) return 0;          /* memory BAR, not I/O */
    return (uint16_t)(bar & 0xFFFC);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  Backend state
 * ════════════════════════════════════════════════════════════════════════════*/

static vb_backend_t g_backend = VB_BACKEND_NONE;

/* SB16 base I/O (default 0x220, could be 0x240/0x260/0x280) */
static uint16_t g_sb16_base = 0;

/* AC97: two I/O base addresses from PCI BARs */
static uint16_t g_ac97_nam  = 0;   /* Native Audio Mixer (BAR0) */
static uint16_t g_ac97_nabm = 0;   /* Native Audio Bus Master (BAR1) */

/* HDA: MMIO base (we only probe, never actually DMA on this path) */
static uint32_t g_hda_found = 0xFFFFFFFF;

/* ════════════════════════════════════════════════════════════════════════════
 *  ISA speaker backend  (PIT channel 2 + port 0x61)
 * ════════════════════════════════════════════════════════════════════════════*/

static void isa_tone_start(uint32_t freq_hz) {
    if (freq_hz == 0) {
        /* Silence: gate off */
        vb_outb(0x61, vb_inb(0x61) & 0xFC);
        return;
    }
    uint32_t div = (uint32_t)(PIT_BASE_HZ / freq_hz);
    if (div == 0) div = 1;
    /* Program PIT channel 2, mode 3 (square wave), lobyte/hibyte */
    vb_outb(0x43, 0xB6);
    vb_outb(0x42, (uint8_t)(div & 0xFF));
    vb_outb(0x42, (uint8_t)((div >> 8) & 0xFF));
    /* Enable speaker gate (bits 0 and 1 of port 0x61) */
    vb_outb(0x61, vb_inb(0x61) | 0x03);
}

static void isa_tone_stop(void) {
    vb_outb(0x61, vb_inb(0x61) & 0xFC);
}

/* ════════════════════════════════════════════════════════════════════════════
 *  SB16 backend  (ISA Plug-and-Play, fixed at 0x220 by default)
 * ════════════════════════════════════════════════════════════════════════════
 *
 * We use the DSP "speaker" command path for simple square-wave beeps.
 * Full PCM DMA playback requires additional setup and is not implemented here.
 * For the purposes of vb_beep(), SB16 also falls through to the ISA speaker
 * for tone generation — the difference is that SB16 presence is detected and
 * logged, giving userland a better story ("SB16 detected") while still
 * producing audio through the PC speaker gate.
 *
 * A proper PCM path can be added later once DMA and IRQ handlers are wired up.
