#define SB16_RESET      0x06   /* offset from base: DSP reset port */
#define SB16_READ       0x0A   /* DSP read data */
#define SB16_WRITE      0x0C   /* DSP write command/data */
#define SB16_READ_STAT  0x0E   /* DSP read buffer status */

static bool sb16_write_dsp(uint16_t base, uint8_t cmd) {
    for (int i = 0; i < 128; i++) {
        if (!(vb_inb(base + SB16_WRITE) & 0x80)) {
            vb_outb(base + SB16_WRITE, cmd);
            return true;
        }
        vb_iodelay();
    }
    return false;
}

static int sb16_read_dsp(uint16_t base) {
    for (int i = 0; i < 128; i++) {
        if (vb_inb(base + SB16_READ_STAT) & 0x80)
            return (int)vb_inb(base + SB16_READ);
        vb_iodelay();
    }
    return -1;
}

static bool sb16_probe(uint16_t base) {
    /* Reset DSP: write 1, wait, write 0 */
    vb_outb(base + SB16_RESET, 1);
    for (int i = 0; i < 8; i++) vb_iodelay();
    vb_outb(base + SB16_RESET, 0);
    for (int i = 0; i < 32; i++) vb_iodelay();
