#include <stddef.h>
#include <stdint.h>
#include <stdbool.h>
#include <detect.h>
#include <vga.h>
#include <gop.h>
#include <gdt.h>
#include <idt.h>
#include <syscall.h>
#include <timer.h>
#include <process.h>
#include <sched.h>
#include <keyboard.h>
#include <pmm.h>
#include <vmm.h>
#include <fs.h>
#include <rawfs.h>
#include <seed.h>
#include <serial.h>
#include <minit.h>
#include <voicebox.h>

/* ── Multiboot magic constants ─────────────────────────────────────────────── */
#define MB1_MAGIC 0x2BADB002u
#define MB2_MAGIC 0x36D76289u

/* ── MB2 tag types we care about at kernel level ───────────────────────────── */
#define MB2_TAG_END         0u
#define MB2_TAG_BASIC_MEM   4u
#define MB2_TAG_FRAMEBUFFER 8u

typedef struct { uint32_t type; uint32_t size; } __attribute__((packed)) mb2_tag_hdr_t;
typedef struct {
    uint32_t type; uint32_t size;
    uint32_t mem_lower; uint32_t mem_upper;
} __attribute__((packed)) mb2_basic_mem_t;

/* ── Globals readable by syscall handlers ──────────────────────────────────── */
uint64_t nephilim_ram_kb  = 0;
char     boot_cpu_brand[64] = {0};

extern void shell_main(void);

/* ── MB2 tag walker ────────────────────────────────────────────────────────── */

/*
 * Scan the MB2 info struct for a specific tag type.
 * Returns a pointer to the first matching tag, or NULL.
 */
static const mb2_tag_hdr_t *mb2_find_tag(uint32_t mb2_info_phys, uint32_t want_type) {
    uintptr_t ptr = (uintptr_t)mb2_info_phys + 8u; /* skip fixed 8-byte header */
    uint32_t  total_size = *(volatile uint32_t *)(uintptr_t)mb2_info_phys;
    uintptr_t end = (uintptr_t)mb2_info_phys + total_size;

    while (ptr < end) {
        const mb2_tag_hdr_t *tag = (const mb2_tag_hdr_t *)ptr;
        if (tag->type == MB2_TAG_END) break;
        if (tag->type == want_type)   return tag;
        ptr += (tag->size + 7u) & ~7u;   /* tags are 8-byte aligned */
    }
    return (void *)0;
}

/* ── Boot entry ─────────────────────────────────────────────────────────────── */

void kernel_main(uint32_t mb_magic, uint32_t mb_info_phys) {
    serial_init();
    serial_print("[BOOT] kernel_main entered\n");

    /* ── Display: try GOP (MB2), fall back to VGA text mode ── */
    bool use_gop = false;

    if (mb_magic == MB2_MAGIC) {
        serial_print("[BOOT] MB2 boot detected\n");

        const gop_mb2_tag_t *fb_tag =
            (const gop_mb2_tag_t *)mb2_find_tag(mb_info_phys, MB2_TAG_FRAMEBUFFER);

        if (!fb_tag) {
            serial_print("[BOOT] no framebuffer tag found\n");
        } else {
            serial_print("[BOOT] fb tag: addr=");
            serial_print_hex(fb_tag->framebuffer_addr);
            serial_print(" w=");    serial_print_uint(fb_tag->framebuffer_width);
            serial_print(" h=");    serial_print_uint(fb_tag->framebuffer_height);
            serial_print(" bpp=");  serial_print_uint(fb_tag->framebuffer_bpp);
            serial_print(" type="); serial_print_uint(fb_tag->framebuffer_type);
            serial_print("\n");

            if (gop_init_from_mb2_tag(fb_tag)) {
                serial_print("[BOOT] GOP init OK\n");
                use_gop = true;
                vga_init_gop();
            } else {
                serial_print("[BOOT] GOP init FAILED\n");
            }
        }
    } else if (mb_magic == MB1_MAGIC) {
        serial_print("[BOOT] MB1 boot detected\n");
    } else {
        serial_print("[BOOT] UNKNOWN magic\n");
    }

    if (!use_gop) {
        serial_print("[BOOT] falling back to VGA text mode\n");
        vga_init();
    }

    vga_clear();
    kprint("NephilimOS -- Hello, World!\n\n");

    if (mb_magic == MB2_MAGIC)
        kprint("[BOOT]    Multiboot 2");
    else
        kprint("[BOOT]    Multiboot 1 (legacy)");

    if (use_gop)
        kprint(" + GOP framebuffer\n");
    else
        kprint(" + VGA text mode\n");

    /* ── Core subsystems ── */
    gdt_init();
    kprint("[GDT]     Ring 0 / Ring 1 descriptors + TSS loaded\n");

    idt_init();
    kprint("[IDT]     256 gates installed\n");

    timer_init();
    kprint("[TIMER]   PIT at 100 Hz, IRQ0 armed\n");

    __asm__ volatile ("sti");

    syscall_init();
    kprint("[SYSCALL] int 0x80 registered (Ring 0/1)\n");

    keyboard_init();
    kprint("[KBD]     PS/2 keyboard initialized\n");

    process_init();
    kprint("[PROC]    Process manager ready\n\n");

    /* ── CPU info ── */
    cpu_info_t cpu;
    detect_cpu(&cpu);
    kprint("CPU Vendor : "); kprint(cpu.vendor); kprint("\n");
    kprint("CPU Model  : ");
    if (cpu.brand[0] != '\0') {
        const char *b = cpu.brand;
        while (*b == ' ') b++;
        kprint(b);
        size_t bi = 0;
        while (*b && bi < sizeof(boot_cpu_brand) - 1)
            boot_cpu_brand[bi++] = *b++;
        boot_cpu_brand[bi] = '\0';
    } else {
        kprint("(unavailable)");
        size_t vi = 0;
        while (cpu.vendor[vi] && vi < sizeof(boot_cpu_brand) - 1) {
            boot_cpu_brand[vi] = cpu.vendor[vi]; vi++;
        }
        boot_cpu_brand[vi] = '\0';
    }
    kprint("\n");
    kprint("Family     : "); kprint_uint64(cpu.family);
    kprint("  Model    : "); kprint_uint64(cpu.model);
    kprint("  Stepping : "); kprint_uint64(cpu.stepping);
    kprint("\n");

    /* ── RAM info + PMM init ── */
    if (mb_magic == MB2_MAGIC) {
        /* Try full mmap (tag 6); basic mem info (tag 4) used as fallback inside
         * pmm_init_mb2() itself, so we just call it unconditionally. */
        pmm_init_mb2(mb_info_phys);

        /* Derive nephilim_ram_kb from the basic-mem tag for display */
        const mb2_basic_mem_t *bm =
            (const mb2_basic_mem_t *)mb2_find_tag(mb_info_phys, MB2_TAG_BASIC_MEM);
        if (bm)
            nephilim_ram_kb = (uint64_t)bm->mem_lower + (uint64_t)bm->mem_upper;

    } else if (mb_magic == MB1_MAGIC) {
        /* MB1 legacy path */
        typedef struct {
            uint32_t flags;
            uint32_t mem_lower;
            uint32_t mem_upper;
        } __attribute__((packed)) mb1_basic_t;

        const mb1_basic_t *mbi = (const mb1_basic_t *)(uintptr_t)mb_info_phys;
        if (mbi->flags & 0x1)
            nephilim_ram_kb = (uint64_t)mbi->mem_lower + (uint64_t)mbi->mem_upper;

        pmm_init_mb1(mb_info_phys);
    }

    if (nephilim_ram_kb) {
        kprint("RAM        : "); kprint_uint64(nephilim_ram_kb / 1024);
        kprint(" MB  (");       kprint_uint64(nephilim_ram_kb);
        kprint(" KB)\n");
    }

    kprint("[PMM]     Free frames: "); kprint_uint64(pmm_free_frames());
    kprint(" (");                      kprint_uint64(pmm_free_frames() * 4 / 1024);
    kprint(" MB)\n");

    vmm_init();
    kprint("[VMM]     4-level paging active, CR3 recorded\n");

    /* ── Filesystem init ── */
    vfs_init();
    nephilim_disk.data = nephilim_disk_image;
    nephilim_disk.size = RAWFS_IMAGE_SIZE;
    int mnt = vfs_mount("/", &rawfs_driver, &nephilim_disk, RAWFS_IMAGE_SIZE);
    if (mnt == FS_OK) {
        kprint("[VFS]     root filesystem mounted at /\n");
        vfs_mkdir("/tmp",  0755);
        vfs_mkdir("/home", 0755);
        vfs_mkdir("/bin",  0755);
        vfs_mkdir("/etc",  0755);
        kprint("[VFS]     seeded /tmp /home /bin /etc\n");
        initramfs_seed();
    } else {
        kprint("[VFS]     WARNING: failed to mount root filesystem\n");
    }
    kprint("\n");

    /* ── minit ── */
    minit_init();

    /* ── Spawn shell as PID 1 ── */
    kprint("[BOOT]    Spawning shell (Ring 1, PID 1)...\n");
    process_t *shell = proc_create(shell_main, "shell",
                                   RING_SERVICE, SCHED_QUANTUM_BASE, 0);
    if (!shell) {
        kprint("[BOOT]    FATAL: could not allocate shell process\n");
        for (;;) __asm__ volatile ("hlt");
    }
    proc_wake(shell);
    minit_watch(shell_main, "shell", shell);

    kprint("[BOOT]    Entering scheduler. Shell is PID ");
    kprint_uint64(shell->pid);
    kprint("\n\n");

    process_t *first = sched_pick();
    if (first) proc_switch(first);

    for (;;) {
        minit_tick();
        __asm__ volatile ("hlt");
    }
}

