1	/*
2	 * userland/apps.c — JS app launcher
3	 *
4	 * At boot the kernel seeds all JS programs into /bin on the ext2 VFS.
5	 * app_run() reads the source from /bin/<name> via filesystem syscalls,
6	 * prepends a __args preamble, then executes it with SYS_JS_EXEC.
7	 *
8	 * If a /bin file cannot be read (e.g. disk not mounted yet) we fall back
9	 * to the embedded string literals so nothing breaks during early boot.
10	 */
11	#include <syscall.h>
12	#include <stdint.h>
13	#include <stddef.h>
14	#include <fs.h>
15	
