116	/* ── Helpers (no libc from Ring-1) ────────────────────────────────────────── */
117	static int app_strcmp(const char *a, const char *b) {
118	    while (*a && *a == *b) { a++; b++; }
119	    return (unsigned char)*a - (unsigned char)*b;
120	}
121	
122	static size_t app_strlen(const char *s) {
123	    size_t n = 0; while (s[n]) n++; return n;
124	}
125	
126	static void app_strcpy(char *dst, const char *src) {
127	    while ((*dst++ = *src++));
128	}
129	
130	static void app_strcat(char *dst, const char *src) {
131	    while (*dst) dst++;
132	    while ((*dst++ = *src++));
133	}
134	
135	/* ── Argument preamble builder ────────────────────────────────────────────── */
136	static int build_args_preamble(char *buf, size_t buflen,
137	                               const char *args_start, const char *cwd) {
138	    char *p = buf;
139	    char *end = buf + buflen - 1;
140	
141	#define EMIT(s) do { \
142	    const char *_s = (s); \
143	    while (*_s && p < end) *p++ = *_s++; \
144	} while(0)
145	
146	    /* Export cwd so JS apps can resolve relative paths */
147	    EMIT("var __cwd=\"");
148	    if (cwd) {
149	        const char *c = cwd;
150	        while (*c && p < end) {
151	            if (*c == '\\' || *c == '"') { if (p < end) *p++ = '\\'; }
152	            if (p < end) *p++ = *c;
153	            c++;
154	        }
155	    } else {
156	        if (p < end) *p++ = '/';
157	    }
158	    EMIT("\";");
159	
160	    EMIT("var __args=[");
161	
162	    const char *tok = args_start;
163	    int first = 1;
164	
165	    while (*tok) {
166	        while (*tok == ' ') tok++;
167	        if (!*tok) break;
168	
169	        const char *te = tok;
170	        while (*te && *te != ' ') te++;
171	
172	        if (!first) EMIT(",");
173	        first = 0;
174	
175	        if (p < end) *p++ = '"';
176	        while (tok < te && p < end) {
177	            if (*tok == '\\' || *tok == '"') { if (p < end) *p++ = '\\'; }
178	            if (p < end) *p++ = *tok;
179	            tok++;
180	        }
181	        if (p < end) *p++ = '"';
182	        tok = te;
183	    }
184	
185	    EMIT("];");
186	    *p = '\0';
187	    return (int)(p - buf);
188	
189	#undef EMIT
190	}
191	
192	/* ── Source buffer: preamble (≤1 KB) + source (≤16 KB) ─────────────────── */
193	#define APP_SRC_MAX   16384
194	#define APP_BUF_TOTAL (1024 + APP_SRC_MAX + 1)
195	static char combined[APP_BUF_TOTAL];
196	
197	/* ── Read JS source from /bin/<name> via fs syscalls ─────────────────────── */
198	/*
199	 * Returns pointer to combined[] with source loaded, or NULL on error.
200	 * bin_path must be "/bin/<name>" (already constructed by caller).
201	 * pre_len is the length of the preamble already written into combined[].
202	 */
203	static const char *load_from_disk(const char *bin_path, int pre_len) {
204	    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)bin_path, O_RDONLY, 0);
205	    if (fd < 0) return NULL;
206	
207	    char *dst = combined + pre_len;
208	    size_t remaining = APP_SRC_MAX;
209	    size_t total = 0;
210	
211	    for (;;) {
212	        int64_t n = syscall3(SYS_FS_READ, (uint64_t)fd,
213	                             (uint64_t)(dst + total), remaining);
214	        if (n <= 0) break;
215	        total += (size_t)n;
216	        remaining -= (size_t)n;
217	        if (remaining == 0) break;
218	    }
219	    syscall1(SYS_FS_CLOSE, (uint64_t)fd);
220	
221	    if (total == 0) return NULL;
222	    dst[total] = '\0';
223	    return combined;
224	}
225	
226	/* ── Public API ───────────────────────────────────────────────────────────── */
227	int app_run(const char *cmdline, const char *cwd) {
228	    const char *p = cmdline;
229	    while (*p == ' ') p++;
230	    if (!*p) return 0;
