/*
 * userland/apps.c — JS app launcher
 *
 * At boot the kernel seeds all JS programs into /bin on the ext2 VFS.
 * app_run() reads the source from /bin/<name> via filesystem syscalls,
 * prepends a __args preamble, then executes it with SYS_JS_EXEC.
 *
 * If a /bin file cannot be read (e.g. disk not mounted yet) we fall back
 * to the embedded string literals so nothing breaks during early boot.
 */
#include <syscall.h>
#include <stdint.h>
#include <stddef.h>
#include <fs.h>

/* ── Embedded JS sources (fallback) ──────────────────────────────────────── */

static const char src_calculator[] =
#include "calculator/main.js.h"
;

static const char src_ls[] =
#include "coreutils/ls.js.h"
;

static const char src_cat[] =
#include "coreutils/cat.js.h"
;

static const char src_touch[] =
#include "coreutils/touch.js.h"
;

static const char src_mkdir[] =
#include "coreutils/mkdir.js.h"
;

static const char src_rm[] =
#include "coreutils/rm.js.h"
;

static const char src_stat[] =
#include "coreutils/stat.js.h"
;

static const char src_write[] =
#include "coreutils/write.js.h"
;

static const char src_wc[] =
#include "coreutils/wc.js.h"
;

static const char src_uname[] =
#include "coreutils/uname.js.h"
;

static const char src_quill[] =
#include "quill/main.js.h"
;

static const char src_cd[] =
#include "coreutils/cd.js.h"
;

static const char src_ps[] =
#include "coreutils/ps.js.h"
;

static const char src_cp[] =
#include "coreutils/cp.js.h"
;

static const char src_mv[] =
#include "coreutils/mv.js.h"
;

static const char src_grep[] =
#include "coreutils/grep.js.h"
;

static const char src_sed[] =
#include "coreutils/sed.js.h"
;


/* ── App table ────────────────────────────────────────────────────────────── */
/* binname: filename under /bin (what the seed wrote).
 * name:    command the user types.
 * fallback: embedded source used if disk read fails. */
typedef struct { const char *name; const char *binname; const char *fallback; } app_t;

static const app_t apps[] = {
    { "calculator", "calculator", src_calculator },
    { "calc",       "calculator", src_calculator },
    { "ls",         "ls",         src_ls         },
    { "cat",        "cat",        src_cat        },
    { "touch",      "touch",      src_touch      },
    { "mkdir",      "mkdir",      src_mkdir      },
    { "rm",         "rm",         src_rm         },
    { "stat",       "stat",       src_stat       },
    { "write",      "write",      src_write      },
    { "wc",         "wc",         src_wc         },
    { "uname",      "uname",      src_uname      },
    { "quill",      "quill",      src_quill      },
    { "cd",         "cd",         src_cd         },
    { "chdir",      "cd",         src_cd         },
    { "ps",         "ps",         src_ps         },
    { "cp",         "cp",         src_cp         },
    { "mv",         "mv",         src_mv         },
    { "grep",       "grep",       src_grep       },
    { "sed",        "sed",        src_sed        },
    { NULL, NULL, NULL }
};

/* ── Helpers (no libc from Ring-1) ────────────────────────────────────────── */
static int app_strcmp(const char *a, const char *b) {
    while (*a && *a == *b) { a++; b++; }
    return (unsigned char)*a - (unsigned char)*b;
}

static size_t app_strlen(const char *s) {
    size_t n = 0; while (s[n]) n++; return n;
}

static void app_strcpy(char *dst, const char *src) {
    while ((*dst++ = *src++));
}

static void app_strcat(char *dst, const char *src) {
    while (*dst) dst++;
    while ((*dst++ = *src++));
}

/* ── Argument preamble builder ────────────────────────────────────────────── */
static int build_args_preamble(char *buf, size_t buflen,
                               const char *args_start, const char *cwd) {
    char *p = buf;
    char *end = buf + buflen - 1;

#define EMIT(s) do { \
    const char *_s = (s); \
    while (*_s && p < end) *p++ = *_s++; \
} while(0)

    /* Export cwd so JS apps can resolve relative paths */
    EMIT("var __cwd=\"");
    if (cwd) {
        const char *c = cwd;
        while (*c && p < end) {
            if (*c == '\\' || *c == '"') { if (p < end) *p++ = '\\'; }
            if (p < end) *p++ = *c;
            c++;
        }
    } else {
        if (p < end) *p++ = '/';
    }
    EMIT("\";");

    EMIT("var __args=[");

    const char *tok = args_start;
    int first = 1;

    while (*tok) {
        while (*tok == ' ') tok++;
        if (!*tok) break;

        const char *te = tok;
        while (*te && *te != ' ') te++;

        if (!first) EMIT(",");
        first = 0;

        if (p < end) *p++ = '"';
        while (tok < te && p < end) {
            if (*tok == '\\' || *tok == '"') { if (p < end) *p++ = '\\'; }
            if (p < end) *p++ = *tok;
            tok++;
        }
        if (p < end) *p++ = '"';
        tok = te;
    }

    EMIT("];");
    *p = '\0';
    return (int)(p - buf);

#undef EMIT
}

/* ── Source buffer: preamble (≤1 KB) + source (≤16 KB) ─────────────────── */
#define APP_SRC_MAX   16384
#define APP_BUF_TOTAL (1024 + APP_SRC_MAX + 1)
static char combined[APP_BUF_TOTAL];

/* ── Read JS source from /bin/<name> via fs syscalls ─────────────────────── */
/*
 * Returns pointer to combined[] with source loaded, or NULL on error.
 * bin_path must be "/bin/<name>" (already constructed by caller).
 * pre_len is the length of the preamble already written into combined[].
 */
static const char *load_from_disk(const char *bin_path, int pre_len) {
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)bin_path, O_RDONLY, 0);
    if (fd < 0) return NULL;

    char *dst = combined + pre_len;
    size_t remaining = APP_SRC_MAX;
    size_t total = 0;

    for (;;) {
        int64_t n = syscall3(SYS_FS_READ, (uint64_t)fd,
                             (uint64_t)(dst + total), remaining);
        if (n <= 0) break;
        total += (size_t)n;
        remaining -= (size_t)n;
        if (remaining == 0) break;
    }
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);

    if (total == 0) return NULL;
    dst[total] = '\0';
    return combined;
}

/* ── Public API ───────────────────────────────────────────────────────────── */
int app_run(const char *cmdline, const char *cwd) {
    const char *p = cmdline;
    while (*p == ' ') p++;
    if (!*p) return 0;

    const char *name_end = p;
    while (*name_end && *name_end != ' ') name_end++;

    char name[64];
    size_t nlen = (size_t)(name_end - p);
    if (nlen >= sizeof(name)) return 0;
    size_t i;
    for (i = 0; i < nlen; i++) name[i] = p[i];
    name[i] = '\0';

    /* Look up app to get the canonical name and fallback source */
    const app_t *app = NULL;
    for (const app_t *a = apps; a->name; a++) {
        if (app_strcmp(a->name, name) == 0) { app = a; break; }
    }
    if (!app) return 0;

    /* Build __args preamble (also injects __cwd) */
    const char *args_start = (*name_end == ' ') ? name_end + 1 : name_end;
    int pre_len = build_args_preamble(combined, sizeof(combined), args_start, cwd);
    if (pre_len < 0) pre_len = 0;

    /* Try to load from /bin/<name> on disk — use canonical name (first match) */
    char bin_path[72];
    bin_path[0] = '/'; bin_path[1] = 'b'; bin_path[2] = 'i'; bin_path[3] = 'n';
    bin_path[4] = '/'; bin_path[5] = '\0';
    app_strcat(bin_path, app->binname);

    const char *src = load_from_disk(bin_path, pre_len);

    if (!src) {
        /* Fallback: use embedded source */
        size_t src_len = app_strlen(app->fallback);
        if ((size_t)pre_len + src_len + 1 < sizeof(combined)) {
            app_strcpy(combined + pre_len, app->fallback);
            src = combined;
        } else {
            src = app->fallback;  /* run without args preamble */
            pre_len = 0;
        }
    }

    syscall1(SYS_JS_EXEC, (uint64_t)src);
    return 1;
}

