    sh_print(cwd);
    sh_print(" $ ");
}

/* ── Entry point ──────────────────────────────────────────────────────────── */
void shell_main(void) {
    sync_cwd();
    syscall0(SYS_CLEAR);
    sh_println("NephilimOS Shell  (Ring 1)");
    sh_println("Type 'help' for available commands.");
    sh_println("");

    for (;;) {
        sh_prompt();
        sh_readline();
        if (line[0]) hist_push(line);
        dispatch();
        syscall0(SYS_YIELD);
