/* repl.js — interactive JavaScript REPL
 *
 * Usage: repl
 *
 * Reads a line, evaluates it as JavaScript, prints the result.
 * 'exit' or 'quit' to leave.  Ctrl+C sends an empty line which is ignored.
 *
 * Each expression is evaluated in a persistent global state — variables
 * declared in one line are visible in subsequent lines.
 */

println("NephilimOS JS REPL  (MuJS)");
println("Type JS expressions. 'exit' or 'quit' to leave.\n");

for (;;) {
    print("js> ");
    var line = readline();

    if (line === null || line === "exit" || line === "quit") {
        println("Bye.");
        break;
    }

    if (line === "") continue;

    try {
        var result = eval(line);
        if (result !== undefined) {
            /* Stringify the result in a useful way */
            var out;
            if (result === null) {
                out = "null";
            } else if (typeof result === "object") {
                try { out = JSON.stringify(result); } catch(e) { out = String(result); }
            } else {
                out = String(result);
            }
            println("= " + out);
        }
    } catch (e) {
        println("Error: " + e.message);
    }
}

