/* exec.js — run a JS file directly
 *
 * Usage: exec <path>
 *
 * Reads the file at <path>, injects the standard __cwd / __args preamble,
 * and evaluates it in the current MuJS state.
 *
 * The executed script sees __cwd (inherited from the shell) and __args
 * containing every token after the filename argument, so scripts can
 * accept their own command-line arguments:
 *
 *   exec /home/USER foo bar
 *     → __args = ["foo", "bar"]  inside hello.js
 *
 * Path resolution: absolute paths are used as-is; relative paths are
 * resolved against __cwd.
 */

(function () {
    var cwd  = typeof __cwd  !== "undefined" ? __cwd  : "/";
    var args = typeof __args !== "undefined" ? __args : [];

    if (args.length === 0) {
        println("exec: usage: exec <file.js> [args...]");
        return;
    }

    /* Resolve path */
    var path = args[0];
    if (path.charAt(0) !== "/") {
        var base = cwd;
