/* exec.js — run a JS file directly
 *
 * Usage: exec <path>
 *
 * Reads the file at <path>, injects the standard __cwd / __args preamble,
 * and evaluates it in the current MuJS state.
 *
 * The executed script sees __cwd (inherited from the shell) and __args
 * containing every token after the filename argument, so scripts can
 * accept their own command-line arguments:
 *
 *   exec /home/USER foo bar
 *     → __args = ["foo", "bar"]  inside hello.js
 *
 * Path resolution: absolute paths are used as-is; relative paths are
 * resolved against __cwd.
 */

(function () {
    var cwd  = typeof __cwd  !== "undefined" ? __cwd  : "/";
    var args = typeof __args !== "undefined" ? __args : [];

    if (args.length === 0) {
        println("exec: usage: exec <file.js> [args...]");
        return;
    }

    /* Resolve path */
    var path = args[0];
    if (path.charAt(0) !== "/") {
        var base = cwd;
        if (base.charAt(base.length - 1) !== "/") base += "/";
        path = base + path;
    }

    /* Read file */
    var fd = fsOpen(path, "r");
    if (fd < 0) {
        println("exec: cannot open: " + path);
        return;
    }

    var src = "";
    var chunk;
    while ((chunk = fsRead(fd, 4096)) !== null) {
        src += chunk;
    }
    fsClose(fd);

    if (src === "") {
        println("exec: empty file: " + path);
        return;
    }

    /* Build preamble: pass remaining args (after the filename) to the script */
    var scriptArgs = args.slice(1);
    var preamble = "var __cwd=" + JSON.stringify(cwd) + ";"
                 + "var __args=" + JSON.stringify(scriptArgs) + ";";

    /* Evaluate the script in the current global context */
    eval(preamble + src);
})();

