        const char *c = cwd;
        while (*c && p < end) {
            if (*c == '\\' || *c == '"') { if (p < end) *p++ = '\\'; }
            if (p < end) *p++ = *c;
            c++;
        }
    } else {
        if (p < end) *p++ = '/';
