        while (tok < te && p < end) {
            if (*tok == '\\' || *tok == '"') { if (p < end) *p++ = '\\'; }
            if (p < end) *p++ = *tok;
            tok++;
        }
        if (p < end) *p++ = '"';
        tok = te;
    }

    EMIT("];");
    *p = '\0';
    return (int)(p - buf);

