static const char *load_from_disk(const char *bin_path, int pre_len) {
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)bin_path, O_RDONLY, 0);
    if (fd < 0) return NULL;

    char *dst = combined + pre_len;
    size_t remaining = APP_SRC_MAX;
    size_t total = 0;

    for (;;) {
        int64_t n = syscall3(SYS_FS_READ, (uint64_t)fd,
                             (uint64_t)(dst + total), remaining);
        if (n <= 0) break;
        total += (size_t)n;
        remaining -= (size_t)n;
        if (remaining == 0) break;
    }
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);

    if (total == 0) return NULL;
    dst[total] = '\0';
    return combined;
}

