int app_run(const char *cmdline, const char *cwd) {
    const char *p = cmdline;
    while (*p == ' ') p++;
    if (!*p) return 0;

    const char *name_end = p;
    while (*name_end && *name_end != ' ') name_end++;

    char name[64];
    size_t nlen = (size_t)(name_end - p);
    if (nlen >= sizeof(name)) return 0;
    size_t i;
    for (i = 0; i < nlen; i++) name[i] = p[i];
    name[i] = '\0';

    /* Look up app to get the canonical name and fallback source */
    const app_t *app = NULL;
    for (const app_t *a = apps; a->name; a++) {
        if (app_strcmp(a->name, name) == 0) { app = a; break; }
    }
    if (!app) return 0;

    /* Build __args preamble (also injects __cwd) */
    const char *args_start = (*name_end == ' ') ? name_end + 1 : name_end;
    int pre_len = build_args_preamble(combined, sizeof(combined), args_start, cwd);
    if (pre_len < 0) pre_len = 0;

    /* Try to load from /bin/<name> on disk — use canonical name (first match) */
    char bin_path[72];
    bin_path[0] = '/'; bin_path[1] = 'b'; bin_path[2] = 'i'; bin_path[3] = 'n';
    bin_path[4] = '/'; bin_path[5] = '\0';
    app_strcat(bin_path, app->binname);

    const char *src = load_from_disk(bin_path, pre_len);

    if (!src) {
        /* Fallback: use embedded source */
        size_t src_len = app_strlen(app->fallback);
        if ((size_t)pre_len + src_len + 1 < sizeof(combined)) {
            app_strcpy(combined + pre_len, app->fallback);
            src = combined;
        } else {
            src = app->fallback;  /* run without args preamble */
            pre_len = 0;
        }
    }

    syscall1(SYS_JS_EXEC, (uint64_t)src);
