/*
 * NephilimOS Shell — Ring-1 userland process
 *
 * Runs at Ring 1. All kernel interaction goes through int $0x80.
 */
#include <syscall.h>
#include <apps.h>
#include <keyboard.h>
#include <stdint.h>
#include <stddef.h>

#define INPUT_BUF_SIZE  256
#define HIST_MAX        32   /* circular history ring */

/* ── Global state ─────────────────────────────────────────────────────────── */
static char line[INPUT_BUF_SIZE];
static char cwd[256];   /* mirror of kernel_cwd, updated after each command */

/* ── History ring ─────────────────────────────────────────────────────────── */
static char hist[HIST_MAX][INPUT_BUF_SIZE];

