static void cmd_reboot(void)   { sh_println("Rebooting...");     syscall0(SYS_REBOOT); }
static void cmd_shutdown(void) { sh_println("Shutting down..."); syscall0(SYS_SHUTDOWN); }
static void cmd_snake(void)    { snake_main(); }

/* ── exec: run an arbitrary .js file ─────────────────────────────────────── */
#define EXEC_BUF_SIZE (16384 + 512)  /* source + preamble headroom */
static char exec_buf[EXEC_BUF_SIZE];

static void cmd_exec(void) {
    /* Parse: "exec <path> [args...]" — line already starts at "exec" */
    const char *p = line + 4;                   /* skip "exec" */
    while (*p == ' ') p++;
    if (!*p) { sh_println("exec: usage: exec <file.js> [args...]"); return; }

    /* Extract path token */
    const char *path_start = p;
    while (*p && *p != ' ') p++;
    size_t path_len = (size_t)(p - path_start);
    if (path_len >= 240) { sh_println("exec: path too long"); return; }

    /* Resolve to absolute path */
    char path[256];
    if (path_start[0] == '/') {
        size_t i = 0;
        while (i < path_len) { path[i] = path_start[i]; i++; }
        path[i] = '\0';
    } else {
        /* Relative — prepend cwd */
        size_t ci = 0;
        while (cwd[ci]) { path[ci] = cwd[ci]; ci++; }
        if (ci > 0 && path[ci-1] != '/') path[ci++] = '/';
        size_t i = 0;
        while (i < path_len && ci < 255) { path[ci++] = path_start[i++]; }
        path[ci] = '\0';
    }

    /* Build minimal __cwd/__args preamble */
    char *dst = exec_buf;
    char *end = exec_buf + EXEC_BUF_SIZE - 1;

#define EP(s) do { const char *_s=(s); while(*_s && dst<end) *dst++=*_s++; } while(0)
    EP("var __cwd=\""); EP(cwd); EP("\";");
    EP("var __args=[");
    /* remaining tokens after the path become __args */
    while (*p == ' ') p++;
    int first = 1;
    while (*p) {
        while (*p == ' ') p++;
        if (!*p) break;
        const char *te = p;
        while (*te && *te != ' ') te++;
        if (!first && dst < end) EP(",");
        first = 0;
        if (dst < end) *dst++ = '"';
        while (p < te && dst < end) {
            if (*p == '"' || *p == '\\') { if (dst < end) *dst++ = '\\'; }
            if (dst < end) *dst++ = *p;
            p++;
        }
        if (dst < end) *dst++ = '"';
        p = te;
    }
    EP("];");
#undef EP

    /* Read the file into the buffer after the preamble */
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)path, O_RDONLY, 0);
    if (fd < 0) { sh_print("exec: cannot open: "); sh_println(path); return; }

    size_t remaining = (size_t)(end - dst);
    size_t total = 0;
    for (;;) {
        int64_t n = syscall3(SYS_FS_READ, (uint64_t)fd,
                             (uint64_t)(dst + total), remaining - total);
        if (n <= 0) break;
        total += (size_t)n;
        if (total >= remaining) break;
    }
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);

    if (total == 0) { sh_println("exec: empty file"); return; }
    dst[total] = '\0';

    syscall1(SYS_JS_EXEC, (uint64_t)exec_buf);
}

