/*
 * NephilimOS Shell — Ring-1 userland process
 *
 * Runs at Ring 1. All kernel interaction goes through int $0x80.
 */
#include <syscall.h>
#include <apps.h>
#include <keyboard.h>
#include <stdint.h>
#include <stddef.h>

#define INPUT_BUF_SIZE  256
#define HIST_MAX        32   /* circular history ring */

/* ── Global state ─────────────────────────────────────────────────────────── */
static char line[INPUT_BUF_SIZE];
static char cwd[256];   /* mirror of kernel_cwd, updated after each command */

/* ── History ring ─────────────────────────────────────────────────────────── */
static char hist[HIST_MAX][INPUT_BUF_SIZE];
static int  hist_count = 0;
static int  hist_head  = 0;

static void hist_push(const char *s) {
    if (!s || !s[0]) return;
    if (hist_count > 0) {
        int prev = (hist_head - 1 + HIST_MAX) % HIST_MAX;
        const char *a = hist[prev], *b = s;
        while (*a && *a == *b) { a++; b++; }
        if (*a == '\0' && *b == '\0') return;   /* duplicate */
    }
    size_t i = 0;
    while (s[i] && i < INPUT_BUF_SIZE - 1) { hist[hist_head][i] = s[i]; i++; }
    hist[hist_head][i] = '\0';
    hist_head = (hist_head + 1) % HIST_MAX;
    if (hist_count < HIST_MAX) hist_count++;
}

static const char *hist_get(int offset) {
    if (offset <= 0 || offset > hist_count) return (const char *)0;
    int idx = (hist_head - offset + HIST_MAX * 2) % HIST_MAX;
    return hist[idx];
}

/* ── I/O helpers ──────────────────────────────────────────────────────────── */
static void sh_putchar(char c) {
    char tmp[2] = { c, '\0' };
    syscall2(SYS_PRINT, (uint64_t)tmp, 0);
}
static void sh_print(const char *s)   { syscall2(SYS_PRINT, (uint64_t)s, 0); }
static void sh_println(const char *s) { sh_print(s); syscall0(SYS_NEWLINE); }

static int sh_getkey(void) { return (int)syscall0(SYS_GETKEY); }

/* ── String helpers ───────────────────────────────────────────────────────── */
static size_t sh_strlen(const char *s) { size_t n=0; while(s[n]) n++; return n; }

static int sh_strcmp(const char *a, const char *b) {
    while (*a && *a == *b) { a++; b++; }
    return (unsigned char)*a - (unsigned char)*b;
}
static int sh_strncmp(const char *a, const char *b, size_t n) {
    while (n && *a && *a == *b) { a++; b++; n--; }
    return n ? (unsigned char)*a - (unsigned char)*b : 0;
}
static void sh_strcpy(char *dst, const char *src) { while ((*dst++ = *src++)); }

static void sh_rtrim(char *s) {
    char *p = s; while (*p) p++;
    while (p > s && p[-1] == ' ') *--p = '\0';
}

static void sh_erase_left(size_t n) {
    for (size_t i = 0; i < n; i++) sh_print("\b \b");
}

/* ── Sync cwd from kernel ─────────────────────────────────────────────────── */
static void sync_cwd(void) {
    syscall2(SYS_GETCWD, (uint64_t)cwd, sizeof(cwd));
}

/* ── Read a line with full editing and history ────────────────────────────── */
static void sh_readline(void) {
    size_t len    = 0;
    size_t cursor = 0;
    int    hist_pos = 0;
    static char saved[INPUT_BUF_SIZE];
    line[0] = '\0'; saved[0] = '\0';

    for (;;) {
        int k = sh_getkey();

        if (k == '\n' || k == '\r') {
            syscall0(SYS_NEWLINE);
            line[len] = '\0';
            break;
        }

        if (k == '\b' || k == 0x7F) {
            if (cursor > 0) {
                for (size_t i = cursor-1; i < len-1; i++) line[i] = line[i+1];
                len--; cursor--;
                line[len] = '\0';
                sh_putchar('\b');
                for (size_t i = cursor; i < len; i++) sh_putchar(line[i]);
                sh_putchar(' ');
                for (size_t i = cursor; i < len+1; i++) sh_print("\b");
            }
            continue;
        }

        if (k == KEY_UP) {
            if (hist_pos == 0) {
                size_t i = 0;
                while (line[i] && i < INPUT_BUF_SIZE-1) { saved[i]=line[i]; i++; }
                saved[i] = '\0';
            }
            const char *e = hist_get(hist_pos + 1);
            if (!e) continue;
            hist_pos++;
            sh_erase_left(len);
            sh_strcpy(line, e);
            len = sh_strlen(line); cursor = len;
            sh_print(line);
            continue;
        }

        if (k == KEY_DOWN) {
            if (hist_pos == 0) continue;
            hist_pos--;
            sh_erase_left(len);
            if (hist_pos == 0) sh_strcpy(line, saved);
            else { const char *e = hist_get(hist_pos); if (e) sh_strcpy(line, e); else line[0]='\0'; }
            len = sh_strlen(line); cursor = len;
            sh_print(line);
            continue;
        }

        if (k == KEY_LEFT)  { if (cursor > 0)   { cursor--; sh_print("\b"); }            continue; }
        if (k == KEY_RIGHT) { if (cursor < len)  { sh_putchar(line[cursor]); cursor++; }  continue; }
        if (k == KEY_HOME)  { while (cursor > 0) { sh_print("\b"); cursor--; }            continue; }
        if (k == KEY_END)   { while (cursor < len) { sh_putchar(line[cursor]); cursor++; } continue; }

        if (k == 3) {   /* Ctrl+C */
            sh_println("^C");
            line[0] = '\0'; len = 0; cursor = 0; hist_pos = 0;
            return;
        }

        if (k >= 32 && k <= 126 && len < INPUT_BUF_SIZE - 1) {
            for (size_t i = len; i > cursor; i--) line[i] = line[i-1];
            line[cursor] = (char)k;
            len++; cursor++;
            line[len] = '\0';
            for (size_t i = cursor-1; i < len; i++) sh_putchar(line[i]);
            for (size_t i = cursor; i < len; i++) sh_print("\b");
        }
    }

    sh_rtrim(line);
}

/* ── Built-in commands ────────────────────────────────────────────────────── */
static void cmd_help(void) {
    sh_println("NephilimOS Shell  built-in commands:");
    sh_println("  help               show this message");
    sh_println("  clear / cls        clear the screen");
    sh_println("  echo <text>        print text");
    sh_println("  pwd                print working directory");
    sh_println("  cpu                show CPU model");
    sh_println("  pid                show current PID");
    sh_println("  reboot             reboot the system");
    sh_println("  shutdown           power off the system");
    sh_println("");
    sh_println("JS coreutils:");
    sh_println("  cd [path]          change directory");
    sh_println("  ls [path]          list directory");
    sh_println("  cat <file>         print file contents");
    sh_println("  touch <file>       create empty file");
    sh_println("  mkdir <dir>        create directory");
    sh_println("  rm <file>          remove file");
    sh_println("  stat <file>        show file info");
    sh_println("  write <file> <txt> write text to file");
    sh_println("  wc <file>          count lines/words/bytes");
    sh_println("  uname              show system information");
    sh_println("  calculator         expression evaluator");
    sh_println("  quill [file]       full-screen text editor");
    sh_println("  ps                 list running processes");
    sh_println("  cp <src> <dst>     copy file");
    sh_println("  mv <src> <dst>     move/rename file");
    sh_println("  grep <pat> <file>  search lines matching pattern");
    sh_println("  sed s/p/r/[g] <f> substitute pattern in file");
    sh_println("  snake              C snake game (WASD/arrows, P=pause, Q=quit)");
    sh_println("");
    sh_println("Keys: Up/Down=history  Left/Right=move  Home/End  Ctrl+C=cancel");
}

static void cmd_clear(void)    { syscall0(SYS_CLEAR); }
static void cmd_pwd(void)      { sh_println(cwd); }

static void cmd_echo(void) {
    const char *arg = line + 5;
    while (*arg == ' ') arg++;
    sh_println(arg);
}

static void cmd_cpu(void) {
    char buf[64];
    syscall2(SYS_CPU_MODEL, (uint64_t)buf, sizeof(buf));
    sh_print("CPU: "); sh_println(buf);
}

static void cmd_pid(void) {
    int64_t pid = syscall0(SYS_GETPID);
    char tmp[12]; int i = 10; tmp[11] = '\0';
    if (pid == 0) { sh_println("PID: 0"); return; }
    uint64_t n = (uint64_t)pid;
    while (n) { tmp[i--] = '0' + (int)(n % 10); n /= 10; }
    sh_print("PID: "); sh_println(tmp + i + 1);
}

static void cmd_reboot(void)   { sh_println("Rebooting...");     syscall0(SYS_REBOOT); }
static void cmd_shutdown(void) { sh_println("Shutting down..."); syscall0(SYS_SHUTDOWN); }
static void cmd_snake(void)    { snake_main(); }

/* ── Dispatch ─────────────────────────────────────────────────────────────── */
typedef struct { const char *name; void (*fn)(void); } cmd_t;

static const cmd_t builtins[] = {
    { "help",     cmd_help     },
    { "clear",    cmd_clear    },
    { "cls",      cmd_clear    },
    { "pwd",      cmd_pwd      },
    { "cpu",      cmd_cpu      },
    { "pid",      cmd_pid      },
    { "reboot",   cmd_reboot   },
    { "shutdown", cmd_shutdown },
    { "snake",    cmd_snake    },
    { NULL, NULL }
};

static void dispatch(void) {
    char *cmd = line;
    while (*cmd == ' ') cmd++;
    if (!*cmd) return;

    if (sh_strncmp(cmd, "echo ", 5) == 0) { cmd_echo(); return; }

    for (const cmd_t *c = builtins; c->name; c++) {
        if (sh_strcmp(cmd, c->name) == 0) { c->fn(); return; }
    }

    /* JS apps — pass full cmdline; app_run also receives cwd for relative paths */
    if (app_run(cmd, cwd)) {
        sync_cwd();   /* cd.js may have changed kernel_cwd */
        return;
    }

    sh_print("Unknown command: "); sh_println(cmd);
}

/* ── Prompt ───────────────────────────────────────────────────────────────── */
static void sh_prompt(void) {
    sh_print(cwd);
    sh_print(" $ ");
}

/* ── Entry point ──────────────────────────────────────────────────────────── */
void shell_main(void) {
    sync_cwd();
    syscall0(SYS_CLEAR);
    sh_println("NephilimOS Shell  (Ring 1)");
    sh_println("Type 'help' for available commands.");
    sh_println("");

    for (;;) {
        sh_prompt();
        sh_readline();
        if (line[0]) hist_push(line);
        dispatch();
        syscall0(SYS_YIELD);
    }
}

