/* ls [path] — list directory contents */
(function() {
    var args = typeof __args !== 'undefined' ? __args : [];
    var cwd  = typeof __cwd  !== 'undefined' ? __cwd  : '/';
    var path = args.length > 0 ? args[0] : cwd;

    var st = fsStat(path);
    if (!st) { println("ls: cannot access '" + path + "': No such file or directory"); return; }

    /* If it's a regular file just print its name */
    var S_IFDIR = 0x4000;
    if ((st.mode & 0xF000) !== S_IFDIR) {
        println(path);
        return;
    }

    var fd = fsOpen(path, "r");
    if (fd < 0) { println("ls: cannot open '" + path + "'"); return; }

    var entries = [];
    var i = 0;
    for (;;) {
        var de = fsReaddir(fd, i);
        if (!de) break;
        entries.push(de.name);
        i++;
    }
    fsClose(fd);

    /* Print in columns — simple single-column for now */
    for (var j = 0; j < entries.length; j++) {
        println(entries[j]);
    }
})();

