/* grep <pattern> <file> [file...] — print matching lines */
(function() {
    var args = typeof __args !== 'undefined' ? __args : [];
    var cwd  = typeof __cwd  !== 'undefined' ? __cwd  : '/';

    if (args.length < 2) {
        println("usage: grep <pattern> <file> [file...]");
        return;
    }

    var pattern = args[0];
    var files   = args.slice(1);
    var multifile = files.length > 1;
    var found   = false;

    function resolvePath(p) {
        if (p[0] === '/') return p;
        return (cwd === '/' ? '' : cwd) + '/' + p;
    }

    /* Very lightweight pattern matching:
     * Supports: literal text, ^ (start), $ (end), . (any char), * (repeat prev),
     * and character classes [abc] / [^abc].
     * No full regex engine — this is enough for practical shell use. */
    function matchHere(pat, pi, str, si) {
        if (pi === pat.length) return true;
        /* $ at end of pattern matches end of string */
        if (pat[pi] === '$' && pi === pat.length - 1) return si === str.length;
        /* .* or char* */
        if (pi + 1 < pat.length && pat[pi + 1] === '*') {
            /* try matching zero or more of pat[pi] */
            var ch = pat[pi];
            /* try longest match first */
            var saved = si;
            var max   = si;
            while (max < str.length && (ch === '.' || str[max] === ch)) max++;
            for (var k = max; k >= saved; k--) {
                if (matchHere(pat, pi + 2, str, k)) return true;
            }
            return false;
        }
        /* character class [abc] or [^abc] */
        if (pat[pi] === '[') {
            var end = pi + 1;
            var negate = false;
            if (end < pat.length && pat[end] === '^') { negate = true; end++; }
            var cls = "";
            while (end < pat.length && pat[end] !== ']') { cls += pat[end]; end++; }
            if (si >= str.length) return false;
            var inClass = cls.indexOf(str[si]) >= 0;
            if (negate ? inClass : !inClass) return false;
            return matchHere(pat, end + 1, str, si + 1);
        }
        /* . matches any character */
        if (pat[pi] === '.') {
            if (si >= str.length) return false;
            return matchHere(pat, pi + 1, str, si + 1);
        }
        /* literal */
        if (si >= str.length || pat[pi] !== str[si]) return false;
        return matchHere(pat, pi + 1, str, si + 1);
    }

    function lineMatches(line, pat) {
        if (pat.length === 0) return true;
        /* ^ anchors to start */
        if (pat[0] === '^') return matchHere(pat, 1, line, 0);
        /* try matching at every position */
        for (var i = 0; i <= line.length; i++) {
            if (matchHere(pat, 0, line, i)) return true;
        }
        return false;
    }

    function grepFile(path, label) {
        var fd = fsOpen(path, "r");
        if (fd < 0) {
            println("grep: " + path + ": No such file or directory");
            return;
        }

        var buf = "";
        for (;;) {
            var chunk = fsRead(fd, 4096);
            if (!chunk) break;
            buf += chunk;
        }
        fsClose(fd);

        var lines = buf.split("\n");
        for (var i = 0; i < lines.length; i++) {
            if (lineMatches(lines[i], pattern)) {
                if (multifile) println(label + ":" + lines[i]);
                else           println(lines[i]);
                found = true;
            }
        }
    }

    for (var fi = 0; fi < files.length; fi++) {
        var path = resolvePath(files[fi]);
        grepFile(path, files[fi]);
    }

    /* exit status analogue — nothing to do in JS, but keep the convention
     * of printing nothing on no match (grep returns 1, we just stay silent) */
})();

