47	static void js_fn_readline(js_State *J) {
48	    static char buf[256];
49	    int i = 0;
50	    buf[0] = '\0';
51	    for (;;) {
52	        char c = keyboard_getchar();
53	        if (c == '\n') { kprint("\n"); break; }
54	        if ((c == '\b' || c == 0x7F) && i > 0) { i--; kprint("\b \b"); continue; }
55	        if (c >= 32 && c <= 126 && i < 255) {
56	            buf[i++] = c;
57	            char tmp[2] = { c, '\0' };
58	            kprint(tmp);
59	        }
60	    }
61	    buf[i] = '\0';
62	    js_pushstring(J, buf);
63	}
64	
