/*
 * js_runtime.c — MuJS engine integration for NephilimOS
 *
 * Compiles MuJS via the one.c amalgamation (with our port header),
 * then provides js_runtime_run() which:
 *   1. Creates a JS state
 *   2. Registers C→JS bindings (print, readline, etc.)
 *   3. Runs a JS source string
 *   4. Tears down the state
 */

/* Pull in the port shim before any MuJS header */
#include "../external/include/mujs/mujs_port.h"
/* Compile the entire MuJS engine as one translation unit */
#include "../external/include/mujs/one.c"

/* Signal library — injected into every JS state before the app source */
static const char js_signal_prelude[] =
#include "../userland/signal.js.h"
;

#include <js_runtime.h>
#include <vga.h>
#include <keyboard.h>
#include <timer.h>
#include <fs.h>
#include <process.h>
#include <string.h>

/* keyboard_getkey is declared in keyboard.h — use it for raw key input */

/* ── I/O bindings ─────────────────────────────────────────────────────────── */

static void js_fn_print(js_State *J) {
    const char *s = js_tostring(J, 1);
    kprint(s);
    js_pushundefined(J);
}

static void js_fn_println(js_State *J) {
    const char *s = js_tostring(J, 1);
    kprint(s);
    kprint("\n");
    js_pushundefined(J);
}

static void js_fn_readline(js_State *J) {
    static char buf[256];
    int i = 0;
    buf[0] = '\0';
    for (;;) {
        char c = keyboard_getchar();
        if (c == '\n') { kprint("\n"); break; }
        if ((c == '\b' || c == 0x7F) && i > 0) { i--; kprint("\b \b"); continue; }
        if (c >= 32 && c <= 126 && i < 255) {
            buf[i++] = c;
            char tmp[2] = { c, '\0' };
            kprint(tmp);
        }
    }
    buf[i] = '\0';
    js_pushstring(J, buf);
}

/* ── Filesystem bindings ──────────────────────────────────────────────────── */

/* open(path, flags) → fd  (flags: "r"=O_RDONLY, "w"=O_WRONLY|O_CREAT|O_TRUNC,
 *                                  "a"=O_WRONLY|O_CREAT|O_APPEND, "r+"=O_RDWR) */
static void js_fn_open(js_State *J) {
    const char *path  = js_tostring(J, 1);
    const char *mode  = js_tostring(J, 2);
    int flags;
    if (mode[0] == 'w') flags = O_WRONLY | O_CREAT | O_TRUNC;
    else if (mode[0] == 'a') flags = O_WRONLY | O_CREAT | O_APPEND;
    else if (mode[0] == 'r' && mode[1] == '+') flags = O_RDWR;
    else flags = O_RDONLY;
    int fd = vfs_open(path, flags, 0644);
    js_pushnumber(J, (double)fd);
}

