/* hideCursor() / showCursor() — disable/enable the blinking hardware cursor */
static void js_fn_hidecursor(js_State *J) {
    vga_cursor_disable();
    js_pushundefined(J);
}
static void js_fn_showcursor(js_State *J) {
    vga_cursor_enable(14, 15);
    js_pushundefined(J);
}

/* ── Process list binding ─────────────────────────────────────────────────── */

/* getProcessList() → array of {pid, name, state, ring, priority} objects */
static void js_fn_getprocesslist(js_State *J) {
    static proc_snap_t snaps[MAX_PROCS];
    int count = proc_snapshot(snaps, MAX_PROCS);
    js_newarray(J);
    for (int i = 0; i < count; i++) {
        js_newobject(J);
        js_pushnumber(J, (double)snaps[i].pid);      js_setproperty(J, -2, "pid");
        js_pushstring(J, snaps[i].name);             js_setproperty(J, -2, "name");
        js_pushnumber(J, (double)snaps[i].state);    js_setproperty(J, -2, "state");
        js_pushnumber(J, (double)snaps[i].ring);     js_setproperty(J, -2, "ring");
        js_pushnumber(J, (double)snaps[i].priority); js_setproperty(J, -2, "priority");
        js_setindex(J, -2, i);
    }
}

/* ── Error reporter ───────────────────────────────────────────────────────── */
static void js_report_fn(js_State *J, const char *msg) {
    (void)J;
    kprint("[JS] ");
    kprint(msg);
    kprint("\n");
}

