static void cmd_clear(void)    { syscall0(SYS_CLEAR); }
static void cmd_pwd(void)      { sh_println(cwd); }

static void cmd_echo(void) {
    const char *arg = line + 5;
    while (*arg == ' ') arg++;
    sh_println(arg);
}

static void cmd_cpu(void) {
    char buf[64];
    syscall2(SYS_CPU_MODEL, (uint64_t)buf, sizeof(buf));
    sh_print("CPU: "); sh_println(buf);
}

static void cmd_pid(void) {
    int64_t pid = syscall0(SYS_GETPID);
    char tmp[12]; int i = 10; tmp[11] = '\0';
    if (pid == 0) { sh_println("PID: 0"); return; }
    uint64_t n = (uint64_t)pid;
    while (n) { tmp[i--] = '0' + (int)(n % 10); n /= 10; }
    sh_print("PID: "); sh_println(tmp + i + 1);
}

static void cmd_reboot(void)   { sh_println("Rebooting...");     syscall0(SYS_REBOOT); }
static void cmd_shutdown(void) { sh_println("Shutting down..."); syscall0(SYS_SHUTDOWN); }
static void cmd_snake(void)    { snake_main(); }

/* ── exec: run an arbitrary .js file ─────────────────────────────────────── */
#define EXEC_BUF_SIZE (16384 + 512)  /* source + preamble headroom */
static char exec_buf[EXEC_BUF_SIZE];

static void cmd_exec(void) {
    /* Parse: "exec <path> [args...]" — line already starts at "exec" */
    const char *p = line + 4;                   /* skip "exec" */
    while (*p == ' ') p++;
    if (!*p) { sh_println("exec: usage: exec <file.js> [args...]"); return; }

    /* Extract path token */
    const char *path_start = p;
    while (*p && *p != ' ') p++;
    size_t path_len = (size_t)(p - path_start);
    if (path_len >= 240) { sh_println("exec: path too long"); return; }

    /* Resolve to absolute path */
    char path[256];
    if (path_start[0] == '/') {
        size_t i = 0;
        while (i < path_len) { path[i] = path_start[i]; i++; }
        path[i] = '\0';
    } else {
        /* Relative — prepend cwd */
        size_t ci = 0;
        while (cwd[ci]) { path[ci] = cwd[ci]; ci++; }
        if (ci > 0 && path[ci-1] != '/') path[ci++] = '/';
        size_t i = 0;
        while (i < path_len && ci < 255) { path[ci++] = path_start[i++]; }
        path[ci] = '\0';
    }

    /* Build minimal __cwd/__args preamble */
    char *dst = exec_buf;
    char *end = exec_buf + EXEC_BUF_SIZE - 1;

#define EP(s) do { const char *_s=(s); while(*_s && dst<end) *dst++=*_s++; } while(0)
    EP("var __cwd=\""); EP(cwd); EP("\";");
    EP("var __args=[");
    /* remaining tokens after the path become __args */
    while (*p == ' ') p++;
    int first = 1;
    while (*p) {
        while (*p == ' ') p++;
        if (!*p) break;
        const char *te = p;
        while (*te && *te != ' ') te++;
        if (!first && dst < end) EP(",");
        first = 0;
        if (dst < end) *dst++ = '"';
        while (p < te && dst < end) {
            if (*p == '"' || *p == '\\') { if (dst < end) *dst++ = '\\'; }
            if (dst < end) *dst++ = *p;
            p++;
        }
        if (dst < end) *dst++ = '"';
        p = te;
    }
    EP("];");
#undef EP

    /* Read the file into the buffer after the preamble */
    int64_t fd = syscall3(SYS_FS_OPEN, (uint64_t)path, O_RDONLY, 0);
    if (fd < 0) { sh_print("exec: cannot open: "); sh_println(path); return; }

    size_t remaining = (size_t)(end - dst);
    size_t total = 0;
    for (;;) {
        int64_t n = syscall3(SYS_FS_READ, (uint64_t)fd,
                             (uint64_t)(dst + total), remaining - total);
        if (n <= 0) break;
        total += (size_t)n;
        if (total >= remaining) break;
    }
    syscall1(SYS_FS_CLOSE, (uint64_t)fd);

    if (total == 0) { sh_println("exec: empty file"); return; }
    dst[total] = '\0';

    syscall1(SYS_JS_EXEC, (uint64_t)exec_buf);
}

/* ── Dispatch ─────────────────────────────────────────────────────────────── */
typedef struct { const char *name; void (*fn)(void); } cmd_t;

static const cmd_t builtins[] = {
    { "help",     cmd_help     },
    { "clear",    cmd_clear    },
    { "cls",      cmd_clear    },
    { "pwd",      cmd_pwd      },
    { "cpu",      cmd_cpu      },
    { "pid",      cmd_pid      },
    { "reboot",   cmd_reboot   },
    { "shutdown", cmd_shutdown },
    { "snake",    cmd_snake    },
    { NULL, NULL }
};

static void dispatch(void) {
    char *cmd = line;
    while (*cmd == ' ') cmd++;
    if (!*cmd) return;

    if (sh_strncmp(cmd, "echo ", 5) == 0) { cmd_echo(); return; }
    if (sh_strncmp(cmd, "exec ", 5) == 0) { cmd_exec(); return; }
    if (sh_strcmp(cmd, "exec") == 0)       { sh_println("exec: usage: exec <file.js> [args...]"); return; }

    for (const cmd_t *c = builtins; c->name; c++) {
        if (sh_strcmp(cmd, c->name) == 0) { c->fn(); return; }
    }

    /* JS apps — pass full cmdline; app_run also receives cwd for relative paths */
    if (app_run(cmd, cwd)) {
        sync_cwd();   /* cd.js may have changed kernel_cwd */
        return;
    }

    sh_print("Unknown command: "); sh_println(cmd);
}

/* ── Prompt ───────────────────────────────────────────────────────────────── */
static void sh_prompt(void) {
    sh_print(cwd);
    sh_print(" $ ");
}

/* ── Entry point ──────────────────────────────────────────────────────────── */
void shell_main(void) {
    sync_cwd();
    syscall0(SYS_CLEAR);
    sh_println("NephilimOS Shell  (Ring 1)");
    sh_println("Type 'help' for available commands.");
    sh_println("");

    for (;;) {
        sh_prompt();
        sh_readline();
        if (line[0]) hist_push(line);
        dispatch();
        syscall0(SYS_YIELD);
    }
}

/*
 * kernel/seed.c — initramfs-style VFS seeder
 *
 * At kernel startup, after the ext2 filesystem is mounted, call
 * initramfs_seed() to write the built-in JS programs into /bin on the
 * in-memory disk.  Userland then reads them from disk like any other file.
 *
 * The JS sources are included as C string literals via the same .js.h
 * headers used by userland/apps.c.  This makes the disk the single source
 * of truth: apps.c is updated separately to read from /bin rather than
 * from embedded constants.
 */

#include <fs.h>
#include <serial.h>
#include <string.h>

/* ── Embedded JS sources (C string literals) ────────────────────────────── */

static const char seed_ls[] =
#include "../userland/coreutils/ls.js.h"
;

static const char seed_cat[] =
#include "../userland/coreutils/cat.js.h"
;

static const char seed_touch[] =
#include "../userland/coreutils/touch.js.h"
;

static const char seed_mkdir[] =
#include "../userland/coreutils/mkdir.js.h"
;

static const char seed_rm[] =
#include "../userland/coreutils/rm.js.h"
;

static const char seed_stat[] =
#include "../userland/coreutils/stat.js.h"
;

static const char seed_write[] =
#include "../userland/coreutils/write.js.h"
;

static const char seed_wc[] =
#include "../userland/coreutils/wc.js.h"
;

static const char seed_uname[] =
#include "../userland/coreutils/uname.js.h"
;

static const char seed_cd[] =
#include "../userland/coreutils/cd.js.h"
;

static const char seed_calculator[] =
#include "../userland/calculator/main.js.h"
;

static const char seed_quill[] =
#include "../userland/quill/main.js.h"
;

static const char seed_ps[] =
#include "../userland/coreutils/ps.js.h"
;

static const char seed_cp[] =
#include "../userland/coreutils/cp.js.h"
;

static const char seed_mv[] =
#include "../userland/coreutils/mv.js.h"
;

static const char seed_grep[] =
#include "../userland/coreutils/grep.js.h"
;

static const char seed_sed[] =
#include "../userland/coreutils/sed.js.h"
;

static const char seed_repl[] =
#include "../userland/coreutils/repl.js.h"
;

/* ── Seed table ─────────────────────────────────────────────────────────── */

typedef struct {
    const char *path;
    const char *src;
} seed_entry_t;

static const seed_entry_t seed_table[] = {
    { "/bin/ls",         seed_ls         },
    { "/bin/cat",        seed_cat        },
    { "/bin/touch",      seed_touch      },
    { "/bin/mkdir",      seed_mkdir      },
    { "/bin/rm",         seed_rm         },
    { "/bin/stat",       seed_stat       },
    { "/bin/write",      seed_write      },
    { "/bin/wc",         seed_wc         },
    { "/bin/uname",      seed_uname      },
    { "/bin/cd",         seed_cd         },
    { "/bin/calculator", seed_calculator },
    { "/bin/quill",      seed_quill      },
    { "/bin/ps",         seed_ps         },
    { "/bin/cp",         seed_cp         },
    { "/bin/mv",         seed_mv         },
    { "/bin/grep",       seed_grep       },
    { "/bin/sed",        seed_sed        },
    { "/bin/repl",       seed_repl       },
    { NULL, NULL }
};

/* ── Public API ─────────────────────────────────────────────────────────── */

void kprint(const char *s);

void initramfs_seed(void) {
    for (const seed_entry_t *e = seed_table; e->path; e++) {
        size_t len = strlen(e->src);
        int r = vfs_write_file(e->path, e->src, len);
        if (r != FS_OK) {
            kprint("[SEED]    WARNING: failed to write ");
            kprint(e->path);
            kprint("\n");
        } else {
            serial_print("[SEED]    wrote ");
            serial_print(e->path);
            serial_print(" (");
            serial_print_uint((uint64_t)len);
            serial_print(" bytes)\n");
        }
    }
    kprint("[SEED]    /bin seeded with JS coreutils\n");

    /* Verify: read back /bin directory entries via serial */
    serial_print("[SEED]    verifying /bin entries:\n");
    int fd = vfs_open("/bin", O_RDONLY, 0);
    if (fd < 0) {
        serial_print("[SEED]    ERROR: cannot open /bin\n");
        return;
    }
    for (uint32_t i = 0; ; i++) {
        fs_dirent_t de;
        int r = vfs_readdir(fd, i, &de);
        if (r != FS_OK) break;
        serial_print("  [");
        serial_print_uint(i);
        serial_print("] ino=");
        serial_print_uint(de.inode);
        serial_print(" name='");
        serial_print(de.name);
        serial_print("'\n");
    }
    vfs_close(fd);
    serial_print("[SEED]    verification done\n");
}

/*
 * userland/apps.c — JS app launcher
 *
 * At boot the kernel seeds all JS programs into /bin on the ext2 VFS.
 * app_run() reads the source from /bin/<name> via filesystem syscalls,
 * prepends a __args preamble, then executes it with SYS_JS_EXEC.
 *
 * If a /bin file cannot be read (e.g. disk not mounted yet) we fall back
 * to the embedded string literals so nothing breaks during early boot.
 */
